//! MCP v0.8 Persistent Cache Pack for CodeLattice CLI
//!
//! Implements a MCP JSON-RPC server over stdin/stdout.
//! Provides 49 tools:
//!   v0:  codelattice_analyze, codelattice_quality, codelattice_summary, codelattice_smoke
//!   v0.1: codelattice_graph_overview, codelattice_unresolved_report,
//!         codelattice_symbol_search, codelattice_export_bridge
//!   v0.2: codelattice_symbol_context, codelattice_calls_from, codelattice_calls_to,
//!         codelattice_impact_preview, codelattice_query_graph, codelattice_project_overview,
//!         codelattice_repo_registry, codelattice_rename_preview
//!   v0.3: codelattice_cache_status, codelattice_cache_clear
//!   v0.5: codelattice_production_assist, codelattice_compare_runs
//!   v0.6: codelattice_cache_prewarm
//!   v0.7: codelattice_changed_symbols
//!   v0.8: codelattice_project_insights
//!   v0.9: codelattice_review_plan
//!   v0.10: codelattice_dead_code_candidates
//!   v0.11: codelattice_impact_analysis, codelattice_risk_hotspots, codelattice_architecture_drift
//!   v0.27: codelattice_automation_graph
//!   v0.28: codelattice_workspace_graph, codelattice_cross_project_impact
//!   v0.29: 8 facade tools (project, symbol, change_review, cleanup, workspace, release_check, cache, workflow)
//!   v0.30: codelattice_root_cause_assistant
//!
//! Transport: newline-delimited JSON-RPC.
//! Approach: subprocess — spawns the CLI binary for analyze/quality/summary,
//!           and the smoke script for smoke.
//! Cache: two-layer analysis cache (process-local memory + persistent disk)
//!        with fingerprint-based stale detection, structured stale reasons,
//!        and LRU eviction (max 16 in-memory entries).
//!        Persistent cache: ${TMPDIR}/codelattice-cache/ or CODELATTICE_CACHE_DIR.
//!        Disable with CODELATTICE_CACHE=off.
//! Safety: path deny list, output path restrictions (/tmp only for export).
//!         Tools advertise permission hints; source writes and project-code execution are not performed.

use gitnexus_analysis_engine::executor::SerializableResult;
use gitnexus_analysis_engine::job::JobStatus;

/// McpCache 的 FacadeCacheWarmer 实现：job worker 完成后直接从 job result
/// 把完整图谱分析结果灌入 McpCache.entries，实现闭环。
struct McpCacheWarmer {
    cache: Arc<Mutex<McpCache>>,
}

impl crate::mcp_job::FacadeCacheWarmer for McpCacheWarmer {
    /// Warm facade cache from job result. Returns (symbol_count, used_cli_fallback).
    fn warm_from_result(
        &self,
        root: &str,
        language: &str,
        result: &SerializableResult,
    ) -> Result<WarmCacheMeta, String> {
        let canonical = Path::new(root)
            .canonicalize()
            .map_err(|e| format!("canonicalize failed: {}", e))?;
        let key = CacheKey {
            root: canonical.to_string_lossy().to_string(),
            language: language.to_string(),
            strict: false,
        };

        {
            let cache = self
                .cache
                .lock()
                .map_err(|_| "facade cache lock poisoned".to_string())?;
            if let Some(existing) = cache.entries.get(&key) {
                // 已有缓存，返回其符号统计
                let (_, _, sc) = existing.graph_view.stats();
                let digest = build_facade_digest(
                    &canonical,
                    language,
                    &existing.graph_view,
                    false,
                    0,
                    json!({"cacheHit": true, "totalWarmMs": 0}),
                );
                return Ok(WarmCacheMeta {
                    symbol_count: sc,
                    call_edge_count: digest["callEdgeCount"].as_u64().unwrap_or(0) as usize,
                    used_cli_fallback: false,
                    warm_duration_ms: 0,
                    facade_digest: digest,
                    warm_trace: WarmTrace {
                        warm_total_wall_ms: 0,
                        ..Default::default()
                    },
                });
            }
        }

        // Build cache entry directly from job artifacts
        let (entry, meta) = build_warm_cache_entry_from_result(&canonical, language, result)?;
        let mut cache = self
            .cache
            .lock()
            .map_err(|_| "facade cache lock poisoned".to_string())?;
        if !cache.entries.contains_key(&key) {
            cache.entries.insert(key, entry);
        }
        Ok(meta)
    }
}
