// ============================================================
// Path Safety
// ============================================================

/// Paths that are explicitly denied for MCP access (live repos).
/// Subpaths in ALLOWED_DENIED_SUBPATHS are exempted from denial (read-only analysis).
const DENIED_PATHS: &[&str] = &["/Users/jiangxuanyang/Desktop/cangjie"];

/// Subpaths under denied directories that are explicitly allowed for read-only MCP analysis.
const ALLOWED_DENIED_SUBPATHS: &[&str] = &["/Users/jiangxuanyang/Desktop/cangjie/runtime/cjgui"];

/// Validate that an output path is within /tmp (or a system temp dir).
fn validate_output_path(output_path: &str) -> Result<PathBuf, Value> {
    let path = PathBuf::from(output_path);

    // Check by string prefix: must start with /tmp/ or /private/tmp/
    // We use string comparison rather than canonicalize because the file
    // may not exist yet, and /tmp may not canonicalize consistently.
    let path_str = path.to_string_lossy();
    if !path_str.starts_with("/tmp/") && !path_str.starts_with("/private/tmp/") {
        return Err(mcp_error_with_hint(
            "output_path_denied",
            &format!("Output path must be under /tmp, got: {output_path}"),
            "export_bridge only writes to /tmp for safety",
            "Use outputPath like /tmp/codelattice-bridge-<name>.json or omit to auto-generate",
        ));
    }

    Ok(path)
}

fn validate_root_path(root: &str) -> Result<PathBuf, Value> {
    let path = PathBuf::from(root);

    // Canonicalize for comparison (resolves symlinks, trailing slashes, etc.)
    let canonical = path
        .canonicalize()
        .map_err(|_| mcp_error("path_not_found", &format!("Path does not exist: {root}")))?;

    if !canonical.is_dir() {
        return Err(mcp_error(
            "path_not_directory",
            &format!("Path is not a directory: {root}"),
        ));
    }

    // Check deny list — but allow exempted subpaths
    for denied in DENIED_PATHS {
        // First check if path is in the allow list (exempt from denial)
        let mut is_allowed = false;
        for allowed in ALLOWED_DENIED_SUBPATHS {
            let allowed_canonical = PathBuf::from(allowed).canonicalize().ok();
            if let Some(ac) = allowed_canonical {
                if canonical == ac || canonical.starts_with(&ac) {
                    is_allowed = true;
                    break;
                }
            }
            // String-prefix fallback for allow list
            let allowed_with_sep = format!("{}/", allowed.trim_end_matches('/'));
            let canonical_str = canonical.to_string_lossy();
            if canonical_str.starts_with(&allowed_with_sep) || canonical_str == *allowed {
                is_allowed = true;
                break;
            }
        }
        if is_allowed {
            continue;
        }

        let denied_canonical = PathBuf::from(denied).canonicalize().ok();
        if let Some(dc) = denied_canonical {
            if canonical == dc {
                return Err(mcp_error(
                    "path_denied",
                    &format!("Path is on deny list (live repo): {denied}"),
                ));
            }
            // Check if canonical path is a descendant of denied directory
            if canonical.starts_with(&dc) {
                return Err(mcp_error(
                    "path_denied",
                    &format!("Path is under denied directory: {denied}"),
                ));
            }
        }
        // String-prefix fallback: ensure the match ends at a path component boundary
        let denied_with_sep = format!("{}/", denied.trim_end_matches('/'));
        let canonical_str = canonical.to_string_lossy();
        if canonical_str.starts_with(&denied_with_sep) || canonical_str == *denied {
            return Err(mcp_error(
                "path_denied",
                &format!("Path is under denied directory: {denied}"),
            ));
        }
    }

    Ok(canonical)
}

fn root_is_under_denied_path(canonical: &Path) -> bool {
    for denied in DENIED_PATHS {
        let denied_canonical = PathBuf::from(denied).canonicalize().ok();
        if let Some(dc) = denied_canonical {
            if canonical == dc || canonical.starts_with(&dc) {
                return true;
            }
        }
        let denied_with_sep = format!("{}/", denied.trim_end_matches('/'));
        let canonical_str = canonical.to_string_lossy();
        if canonical_str.starts_with(&denied_with_sep) || canonical_str == *denied {
            return true;
        }
    }
    false
}

/// Workspace-level tools may enter a protected live root in static workspace mode.
/// This does not relax source analysis deny rules for low-level project tools.
fn validate_workspace_root_path(root: &str) -> Result<(PathBuf, bool), Value> {
    let path = PathBuf::from(root);
    let canonical = path
        .canonicalize()
        .map_err(|_| mcp_error("path_not_found", &format!("Path does not exist: {root}")))?;

    if !canonical.is_dir() {
        return Err(mcp_error(
            "path_not_directory",
            &format!("Path is not a directory: {root}"),
        ));
    }

    let protected = root_is_under_denied_path(&canonical);
    Ok((canonical, protected))
}

fn source_only_entry_category(p: &ProjectInfo) -> (&'static str, &'static str, &'static str) {
    let rel = p.relative_path.to_lowercase();
    let name = p.name.to_lowercase();

    if p.language == "shell" || rel.contains("script") || name.contains("script") {
        (
            "script_directory",
            "source-only shell/script directory without a manifest",
            "Treat as support scripts. Analyze only when the task touches automation or operations.",
        )
    } else if is_test_like_path(&p.relative_path) || is_test_like_path(&p.name) {
        (
            "test_or_fixture_directory",
            "source-only test/example/fixture directory without a manifest",
            "Do not treat as architecture entry point; inspect when validating behavior or fixtures.",
        )
    } else if rel.ends_with("/src")
        || rel.contains("/src/")
        || name == "src"
        || rel.contains("/lib")
        || rel.contains("/core")
        || rel.contains("/api")
    {
        (
            "nested_source_directory",
            "source files detected under a nested source directory, but no project manifest was found there",
            "Prefer the nearest manifest-backed parent project. Use this path only for focused drill-down.",
        )
    } else {
        (
            "manifestless_source_directory",
            "source files detected, but no supported project manifest was found",
            "Select a manifest-backed sibling/parent when available, or specify language for focused analysis.",
        )
    }
}

fn source_only_entry_json(p: &ProjectInfo) -> Value {
    let (category, reason, next_action) = source_only_entry_category(p);
    let drill_down_candidate = matches!(
        category,
        "manifestless_source_directory" | "nested_source_directory"
    );
    let root_role = match category {
        "manifestless_source_directory" | "nested_source_directory" => "focused_drill_down",
        "script_directory" => "support_script_area",
        "test_or_fixture_directory" => "validation_area",
        _ => "source_only_area",
    };
    let selection_guidance = match category {
        "manifestless_source_directory" => {
            "Not a manifest-backed project root. Use only for focused drill-down after checking the nearest manifest-backed parent."
        }
        "nested_source_directory" => {
            "Nested source directory. Prefer the nearest manifest-backed parent for project analysis; use this path only to narrow a known area."
        }
        "script_directory" => {
            "Support scripts, not an application/project root. Analyze only when the task touches automation or operations."
        }
        "test_or_fixture_directory" => {
            "Validation or fixture area. Do not treat as an architecture entry point or primary project root."
        }
        _ => "Source-only area without a manifest. Prefer a manifest-backed project root when available.",
    };
    json!({
        "path": p.path,
        "relativePath": p.relative_path,
        "name": p.name,
        "language": p.language,
        "manifestFile": p.manifest_file,
        "category": category,
        "reason": reason,
        "nextAction": next_action,
        "supported": p.supported,
        "analyzable": true,
        "manifestBacked": false,
        "rootRole": root_role,
        "drillDownCandidate": drill_down_candidate,
        "recommendedAsProjectRoot": false,
        "recommendedAsFocusedRoot": drill_down_candidate,
        "selectionGuidance": selection_guidance
    })
}

fn source_only_entries_json<'a, I>(items: I, limit: usize) -> Vec<Value>
where
    I: IntoIterator<Item = &'a ProjectInfo>,
{
    items
        .into_iter()
        .filter(|p| p.supported && p.manifest_file.is_empty())
        .take(limit)
        .map(source_only_entry_json)
        .collect()
}

