fn project_component_key(file: &str, language: &str) -> String {
    let normalized = file.replace('\\', "/");
    let parts: Vec<&str> = normalized
        .split('/')
        .filter(|part| !part.is_empty())
        .collect();

    if parts.is_empty() {
        return "root".to_string();
    }

    if parts[0] == "src" {
        if parts.len() >= 3 {
            return format!("src/{}", parts[1]);
        }
        return "src".to_string();
    }

    if matches!(language, "typescript" | "javascript" | "arkts") {
        for prefix in ["pages", "routes", "app", "components", "store", "api"] {
            if parts[0] == prefix {
                return parts[0].to_string();
            }
        }
    }

    if matches!(language, "python") && parts[0] == "tests" {
        return "tests".to_string();
    }

    parts[0].to_string()
}

fn project_component_role(component: &str) -> &'static str {
    let lower = component.to_lowercase();
    if lower.contains("test") || lower.contains("fixture") || lower.contains("spec") {
        "validation"
    } else if lower.contains("api") || lower.contains("route") || lower.contains("controller") {
        "interface"
    } else if lower.contains("service")
        || lower.contains("core")
        || lower.contains("domain")
        || lower.contains("model")
    {
        "domain_logic"
    } else if lower.contains("component")
        || lower.contains("page")
        || lower.contains("view")
        || lower.contains("ui")
    {
        "presentation"
    } else if lower.contains("config") || lower.contains("script") || lower.contains("bin") {
        "operations"
    } else {
        "module"
    }
}

fn build_workspace_auto_entry(root: &str, protected: bool, compact: bool) -> Option<Value> {
    let path = PathBuf::from(root).canonicalize().ok()?;
    let inventory = scan_workspace_inventory(&path, true).ok()?;
    let supported: Vec<_> = inventory.iter().filter(|p| p.supported).collect();
    let supported_manifest_projects: Vec<_> = supported
        .iter()
        .filter(|p| !p.manifest_file.is_empty())
        .copied()
        .collect();
    let root_is_project = supported_manifest_projects
        .iter()
        .any(|p| p.relative_path == ".");
    let manifest_project_count = supported_manifest_projects.len();
    let child_project_count = supported_manifest_projects
        .iter()
        .filter(|p| p.relative_path != ".")
        .count();
    if manifest_project_count < 2 && (root_is_project || child_project_count < 2) && !protected {
        return None;
    }
    let unsupported: Vec<_> = inventory.iter().filter(|p| !p.supported).collect();
    let graph_summary = build_workspace_graph(&path, true)
        .ok()
        .and_then(|g| serde_json::to_value(g.summary).ok());
    let workspace_graph_available = graph_summary.is_some();
    let workspace_summary = graph_summary.unwrap_or_else(|| json!({}));
    let source_only_count = supported
        .len()
        .saturating_sub(supported_manifest_projects.len());
    let source_only_entries =
        source_only_entries_json(supported.iter().copied(), if compact { 3 } else { 50 });
    let source_only_summary = source_only_summary_json(&source_only_entries, source_only_count);
    let primary_project_roots =
        ranked_project_roots_json(supported_manifest_projects.iter().copied(), 8);
    let recommended_first_step = primary_project_roots
        .first()
        .and_then(|p| p["path"].as_str())
        .map(|p| format!("Start with codelattice_project mode=quick on {p}."))
        .unwrap_or_else(|| {
            "Use codelattice_workspace mode=graph, then choose a concrete project root.".to_string()
        });

    Some(json!({
        "schemaVersion": "codelattice.workspaceAutoEntry.v1",
        "status": if supported_manifest_projects.is_empty() { "needs_selection" } else { "workspace_analyzed" },
        "rootKind": if protected { "protected_live_workspace" } else { "workspace" },
        "root": path.to_string_lossy(),
        "rootDiagnosis": if compact {
            diagnose_root_compact(&path.to_string_lossy(), "auto")
        } else {
            diagnose_root(&path.to_string_lossy(), "auto")
        },
        "analysisSemantics": build_analysis_semantics(),
        "summary": {
            "supportedProjectCount": supported_manifest_projects.len(),
            "sourceOnlyEntryCount": source_only_count,
            "unsupportedModuleCount": unsupported.len(),
            "recommendedProjectCount": supported_manifest_projects.len(),
            "workspaceGraphAvailable": workspace_graph_available,
            "liveRootProtected": protected
        },
        "sourceOnlySummary": source_only_summary,
        "sourceOnlyEntries": source_only_entries,
        "primaryProjectRoots": primary_project_roots,
        "decisionGuidance": {
            "toolRole": "workspace entry router",
            "rootKind": if protected { "protected_live_workspace" } else { "workspace" },
            "rootUseGuidance": if compact {
                "Workspace root: pick primaryProjectRoots before project/symbol review."
            } else {
                "This is a workspace root. Use codelattice_workspace for cross-project questions, then choose a manifest-backed primaryProjectRoots entry for codelattice_project/codelattice_symbol/codelattice_change_review."
            },
            "recommendedNextTool": "codelattice_project",
            "recommendedNextAction": recommended_first_step.clone(),
            "toolBoundary": if compact {
                json!(["workspace=boundaries", "project=selected root", "symbol=selected root"])
            } else {
                json!({
                    "workspace": "Use codelattice_workspace for graph/impact across project boundaries.",
                    "project": "Use codelattice_project only after selecting one manifest-backed project root.",
                    "symbol": "Use codelattice_symbol only on a concrete project root, not the workspace root."
                })
            },
            "compactSemantics": compact_semantics(compact)
        },
        "progressiveExploration": {
            "recommendedFirstStep": recommended_first_step,
            "depthModel": [
                {"depth": 1, "mode": "quick", "purpose": "orientation"},
                {"depth": 2, "mode": "standard", "purpose": "module risk"},
                {"depth": 3, "mode": "deep", "purpose": "full static detail"}
            ],
            "compactSourceOnlyEntries": compact
        },
        "supportedProjects": supported_manifest_projects.iter().map(|p| json!({
            "path": p.path,
            "relativePath": p.relative_path,
            "name": p.name,
            "language": p.language,
            "manifestFile": p.manifest_file,
            "recommended": true
        })).collect::<Vec<_>>(),
        "unsupportedModules": unsupported.iter().map(|p| json!({
            "path": p.path,
            "relativePath": p.relative_path,
            "name": p.name,
            "language": p.language,
            "manifestFile": p.manifest_file,
            "supported": false
        })).collect::<Vec<_>>(),
        "analyzedProjects": [],
        "failedProjects": [],
        "workspaceSummary": workspace_summary,
        "nextActions": [
            "Inspect boundaries with workspace graph.",
            "Pick primaryProjectRoots before project/symbol calls.",
            "Use impact mode for cross-project targets."
        ],
        "cautions": [
            "static-only",
            "no scripts executed",
            "unsupported modules are reported only"
        ],
        "generatedFrom": {
            "staticAnalysis": true,
            "workspaceInventory": true,
            "workspaceGraph": workspace_graph_available,
            "projectContentRead": false,
            "scriptsExecuted": false,
            "runtimeVerified": false,
            "coverageVerified": false,
            "liveRootProtected": protected
        }
    }))
}

