// ============================================================
// v0.20: Entry Point & Reachability Map
// ============================================================

fn detect_entry_points_rich(
    gv: &GraphView,
    language: &str,
    entry_hints: &[String],
) -> Vec<(
    String,
    String,
    String,
    String,
    u64,
    String,
    f64,
    Vec<String>,
)> {
    let entry_file_suffixes: &[&str] = match language {
        "rust" => &["main.rs", "lib.rs"],
        "cangjie" => &["package.cj", "main.cj"],
        "arkts" => &["Index.ets", "MainAbility"],
        "typescript" => &["index.ts", "index.tsx", "main.ts", "app.ts", "server.ts"],
        "python" => &[
            "main.py",
            "__main__.py",
            "app.py",
            "cli.py",
            "api.py",
            "__init__.py",
        ],
        "c" | "cpp" => &["main.c", "main.cpp", "main.cc"],
        _ => &["main"],
    };
    let mut results: Vec<(
        String,
        String,
        String,
        String,
        u64,
        String,
        f64,
        Vec<String>,
    )> = Vec::new();
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    for node in gv.nodes_by_id.values() {
        let kind = node["kind"].as_str().unwrap_or("");
        let label = node["label"].as_str().unwrap_or("");
        if kind != "symbol" && label != "symbol" {
            continue;
        }
        let name = node["properties"]["name"]
            .as_str()
            .or_else(|| {
                node["id"]
                    .as_str()
                    .and_then(|id_str| id_str.split("::").last())
            })
            .unwrap_or("");
        let file = node["properties"]["sourcePath"].as_str().unwrap_or("");
        let line = node["properties"]["startLine"].as_u64().unwrap_or(0);
        let id = node["id"].as_str().unwrap_or("").to_string();
        if id.is_empty() || seen.contains(&id) {
            continue;
        }
        let fan_out = gv.outgoing.get(&id).map(|v| v.len()).unwrap_or(0);
        let mut score: f64 = 0.0;
        let mut reasons: Vec<String> = Vec::new();
        if name == "main" {
            score += 0.50;
            reasons.push("entry-like symbol name".to_string());
        }
        match language {
            "python" if name == "create_app" || name == "createApp" => {
                score += 0.40;
                reasons.push("framework entry name".to_string());
            }
            "c" | "cpp" if name == "WinMain" || name == "wWinMain" || name == "DllMain" => {
                score += 0.35;
                reasons.push("platform entry name".to_string());
            }
            "arkts" if name == "build" || name == "aboutToAppear" => {
                score += 0.40;
                reasons.push("lifecycle entry name".to_string());
            }
            _ => {}
        }
        for s in entry_file_suffixes {
            if file.ends_with(s) {
                score += 0.30;
                reasons.push("entry-like filename".to_string());
                break;
            }
        }
        if fan_out > 8 {
            score += 0.15;
            reasons.push("high fan-out orchestrator".to_string());
        } else if fan_out > 4 {
            score += 0.08;
            reasons.push("moderate fan-out".to_string());
        }
        if (file.ends_with("lib.rs")
            || file.ends_with("package.cj")
            || file.ends_with("__init__.py"))
            && !name.starts_with('_')
        {
            score += 0.10;
            reasons.push("public symbol in package root".to_string());
        }
        for hint in entry_hints {
            if name == hint.as_str() || file.contains(hint.as_str()) || id.contains(hint.as_str()) {
                score += 0.35;
                reasons.push(format!("user hint: {}", hint));
                break;
            }
        }
        if score < 0.15 {
            continue;
        }
        let confidence = if score >= 0.70 {
            "high"
        } else if score >= 0.40 {
            "medium"
        } else {
            "low"
        };
        seen.insert(id.clone());
        results.push((
            id,
            name.to_string(),
            kind.to_string(),
            file.to_string(),
            line,
            confidence.to_string(),
            score.min(1.0),
            reasons,
        ));
    }
    if results.is_empty() {
        let mut cands: Vec<&Value> = gv
            .nodes_by_id
            .values()
            .filter(|n| {
                let k = n["kind"].as_str().unwrap_or("");
                k == "function" || k == "method" || k == "symbol"
            })
            .collect();
        cands.sort_by_key(|n| {
            std::cmp::Reverse(
                gv.outgoing
                    .get(n["id"].as_str().unwrap_or(""))
                    .map(|v| v.len())
                    .unwrap_or(0),
            )
        });
        for node in cands.iter().take(5) {
            let id = node["id"].as_str().unwrap_or("").to_string();
            if id.is_empty() || seen.contains(&id) {
                continue;
            }
            let name = node["properties"]["name"]
                .as_str()
                .unwrap_or("")
                .to_string();
            let file = node["properties"]["sourcePath"]
                .as_str()
                .unwrap_or("")
                .to_string();
            let line = node["properties"]["startLine"].as_u64().unwrap_or(0);
            let kind = node["kind"].as_str().unwrap_or("symbol").to_string();
            seen.insert(id.clone());
            results.push((
                id,
                name,
                kind,
                file,
                line,
                "low".to_string(),
                0.25,
                vec!["fallback: high fan-out".to_string()],
            ));
        }
    }
    results
}

fn reachable_from_entry_points_rich(
    gv: &GraphView,
    entry_points: &[(
        String,
        String,
        String,
        String,
        u64,
        String,
        f64,
        Vec<String>,
    )],
    max_depth: usize,
) -> std::collections::HashSet<String> {
    let mut reachable = std::collections::HashSet::new();
    let mut queue: std::collections::VecDeque<(String, usize)> = std::collections::VecDeque::new();
    for (id, _, _, _, _, _, _, _) in entry_points {
        reachable.insert(id.clone());
        queue.push_back((id.clone(), 0));
    }
    let follow: &[&str] = &["CALLS", "REFERENCES", "IMPORTS", "INCLUDES", "DEFINES"];
    while let Some((node_id, depth)) = queue.pop_front() {
        if depth >= max_depth {
            continue;
        }
        if let Some(edges) = gv.outgoing.get(&node_id) {
            for edge in edges {
                let et = edge["type"].as_str().unwrap_or("");
                if follow.contains(&et) {
                    if let Some(target) = edge["target"].as_str() {
                        if reachable.insert(target.to_string()) {
                            queue.push_back((target.to_string(), depth + 1));
                        }
                    }
                }
            }
        }
    }
    reachable
}

fn handle_reachability_map(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    let validated = validate_root_path(root)?;
    let language = params["language"].as_str().unwrap_or("auto");
    check_language_feature(language)?;
    let compact = params["compact"].as_bool().unwrap_or(true);
    let limit = params["limit"].as_u64().unwrap_or(100).min(500) as usize;
    let max_depth = params["maxDepth"].as_u64().unwrap_or(8).min(20).max(1) as usize;
    let include_tests = params["includeTests"].as_bool().unwrap_or(false);
    let include_reachable_items = params["includeReachableItems"].as_bool().unwrap_or(false);
    let entry_hints: Vec<String> = params["entryHints"]
        .as_array()
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default();
    let exclude_patterns: Vec<String> = params["excludePatterns"]
        .as_array()
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default();
    let (gv, _result, cache_meta) = cache.get_or_analyze(&validated, language, false)?;
    let entry_points = detect_entry_points_rich(&gv, language, &entry_hints);
    let ep_ids: std::collections::HashSet<String> = entry_points
        .iter()
        .map(|(id, _, _, _, _, _, _, _)| id.clone())
        .collect();
    let reachable = reachable_from_entry_points_rich(&gv, &entry_points, max_depth);
    let mut reachable_files: std::collections::HashSet<String> = std::collections::HashSet::new();
    for id in &reachable {
        if let Some(n) = gv.nodes_by_id.get(id) {
            if let Some(f) = n["properties"]["sourcePath"].as_str() {
                if !f.is_empty() {
                    reachable_files.insert(f.to_string());
                }
            }
        }
    }
    let mut file_sym_count: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();
    let mut file_unreach: std::collections::HashMap<String, usize> =
        std::collections::HashMap::new();
    let mut unreachable_symbols: Vec<Value> = Vec::new();
    for node in gv.nodes_by_id.values() {
        let kind = node["kind"].as_str().unwrap_or("");
        let label = node["label"].as_str().unwrap_or("");
        if kind != "symbol"
            && label != "symbol"
            && kind != "function"
            && kind != "method"
            && kind != "class"
            && kind != "struct"
            && kind != "enum"
            && kind != "const"
            && kind != "static"
            && kind != "associated-function"
        {
            continue;
        }
        let id = node["id"].as_str().unwrap_or("");
        if id.is_empty() {
            continue;
        }
        let name = node["properties"]["name"]
            .as_str()
            .or_else(|| node["id"].as_str().and_then(|i| i.split("::").last()))
            .unwrap_or("");
        let file = node["properties"]["sourcePath"].as_str().unwrap_or("");
        let line = node["properties"]["startLine"].as_u64().unwrap_or(0);
        let node_kind = node["kind"].as_str().unwrap_or("symbol");
        if ep_ids.contains(id) || is_generated_path(file) {
            continue;
        }
        if !include_tests && is_test_like_path(file) {
            continue;
        }
        if exclude_patterns
            .iter()
            .any(|p| file.contains(p.as_str()) || name.contains(p.as_str()))
        {
            continue;
        }
        if !file.is_empty() {
            *file_sym_count.entry(file.to_string()).or_insert(0) += 1;
        }
        if reachable.contains(id) {
            continue;
        }
        *file_unreach.entry(file.to_string()).or_insert(0) += 1;
        let mut score: f64 = 0.0;
        let mut reasons: Vec<String> = Vec::new();
        let mut cautions: Vec<String> = Vec::new();
        reasons.push("not-reachable-from-entry-points".to_string());
        score += 0.40;
        let incoming = gv.incoming.get(id).map(|v| v.len()).unwrap_or(0);
        if incoming == 0 {
            reasons.push("no-incoming-calls".to_string());
            score += 0.25;
        }
        if !reachable_files.contains(file) && !file.is_empty() {
            reasons.push("file-not-reachable".to_string());
            score += 0.15;
        }
        cautions.push("static-analysis-only".to_string());
        if !name.starts_with('_') && incoming == 0 {
            cautions.push("public-api-may-have-external-callers".to_string());
        }
        if has_dynamic_pattern(name, file) {
            cautions.push("dynamic-dispatch-may-hide-callers".to_string());
        }
        if score < 0.30 {
            continue;
        }
        let confidence = if score >= 0.70 {
            "high"
        } else if score >= 0.45 {
            "medium"
        } else {
            "low"
        };
        let mut sym = json!({"name": name, "kind": node_kind, "file": file, "line": line, "score": (score * 100.0).round() / 100.0, "confidence": confidence, "reasons": reasons, "cautions": cautions});
        if !compact {
            if let Some(o) = sym.as_object_mut() {
                o.insert("id".to_string(), json!(id));
            }
        }
        unreachable_symbols.push(sym);
    }
    unreachable_symbols.sort_by(|a, b| {
        b["score"]
            .as_f64()
            .unwrap_or(0.0)
            .partial_cmp(&a["score"].as_f64().unwrap_or(0.0))
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    unreachable_symbols.truncate(limit);
    let mut unreachable_files: Vec<Value> = Vec::new();
    for (file, total) in &file_sym_count {
        if is_generated_path(file) || (!include_tests && is_test_like_path(file)) {
            continue;
        }
        if exclude_patterns.iter().any(|p| file.contains(p.as_str())) {
            continue;
        }
        let uc = file_unreach.get(file).copied().unwrap_or(0);
        if uc == *total && uc > 0 {
            let mut fr: Vec<String> = vec!["file-not-reachable-from-entry-points".to_string()];
            if !reachable_files.contains(file) {
                fr.push("no-incoming-import-or-include".to_string());
            }
            unreachable_files.push(json!({"path": file, "symbolCount": total, "score": 0.70, "reasons": fr, "cautions": ["static-analysis-only"]}));
        }
    }
    let ep_json: Vec<Value> = entry_points.iter().map(|(id, name, kind, file, line, conf, score, reasons)| {
        let mut ep = json!({"name": name, "kind": kind, "file": file, "line": line, "confidence": conf, "score": (*score * 100.0).round() / 100.0, "reasons": reasons});
        if !compact { if let Some(o) = ep.as_object_mut() { o.insert("id".to_string(), json!(id)); } } ep
    }).collect();
    let dyn_caution = unreachable_symbols
        .iter()
        .filter(|s| {
            s["cautions"]
                .as_array()
                .map(|a| {
                    a.iter().any(|v| {
                        v.as_str()
                            .map(|t| t.contains("dynamic-dispatch"))
                            .unwrap_or(false)
                    })
                })
                .unwrap_or(false)
        })
        .count();
    let mut warnings = vec![
        "static graph reachability only".to_string(),
        "dynamic dispatch may hide runtime reachability".to_string(),
    ];
    if entry_points.is_empty() {
        warnings.push("entry-point-detection-low-confidence".to_string());
    }
    let reachable_section = if include_reachable_items {
        let syms: Vec<Value> = reachable.iter().filter_map(|id_val| gv.nodes_by_id.get(id_val)).take(limit)
            .map(|n| json!({"id": n["id"], "name": n["properties"]["name"], "kind": n["kind"], "file": n["properties"]["sourcePath"]})).collect();
        json!({"symbolCount": reachable.len(), "fileCount": reachable_files.len(), "symbols": syms, "files": reachable_files.iter().take(limit).map(|f| json!(f)).collect::<Vec<Value>>()})
    } else {
        json!({"symbolCount": reachable.len(), "fileCount": reachable_files.len()})
    };
    let result_data = json!({
        "language": language, "root": root,
        "summary": {"entryPointCount": entry_points.len(), "reachableSymbolCount": reachable.len(), "reachableFileCount": reachable_files.len(),
            "unreachableSymbolCandidateCount": unreachable_symbols.len(), "unreachableFileCandidateCount": unreachable_files.len(), "dynamicCautionCount": dyn_caution},
        "entryPoints": ep_json, "reachable": reachable_section, "unreachableCandidates": {"symbols": unreachable_symbols, "files": unreachable_files},
        "warnings": warnings, "generatedFrom": {"graphBased": true, "compilerVerified": false, "runtimeVerified": false, "heuristic": true}
    });
    Ok(merge_cache_and_result(&result_data, &cache_meta))
}

// JSON-RPC Dispatch
// ============================================================

fn make_response(id: &Value, result: Value) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": result
    })
}

fn make_error_response(id: &Value, code: i64, message: &str) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "error": {
            "code": code,
            "message": message
        }
    })
}

/// 控制面调用判定：这些调用只读 job registry 或 cache stats，不触发分析，
/// 必须绕过 busy guard，永远快速返回。
fn is_control_plane_call(tool_name: &str, params: &Value) -> bool {
    match tool_name {
        "codelattice_cache" => {
            matches!(params["mode"].as_str(), Some("status" | "explain"))
        }
        "codelattice_project"
        | "codelattice_symbol"
        | "codelattice_change_review"
        | "codelattice_workspace" => {
            matches!(
                params["mode"].as_str(),
                Some("job" | "job_status" | "job_detail" | "job_cancel")
            )
        }
        _ => false,
    }
}

/// 控制面直接处理：不需要 McpCache 锁，只读全局 MCP_JOBS registry。
/// 返回 None 表示不是控制面调用，需要走分析面路径。
fn handle_control_plane_call(tool_name: &str, params: &Value) -> Option<Result<Value, Value>> {
    match tool_name {
        "codelattice_cache" => {
            let mode = params["mode"].as_str().unwrap_or("status");
            match mode {
                "status" => {
                    let stats = crate::mcp_job::cache_stats();
                    let cache_disabled = std::env::var("CODELATTICE_CACHE").as_deref() == Ok("off");
                    let is_custom = std::env::var("CODELATTICE_CACHE_DIR").is_ok();
                    let persistent_available = !cache_disabled;
                    let cache_dir = if persistent_available {
                        get_persistent_cache_dir().map(|p| p.display().to_string())
                    } else {
                        None
                    };
                    let body = json!({
                        "schemaVersion": "codelattice.cacheStatus.v1",
                        "cache": stats,
                        "persistentCache": {
                            "available": persistent_available,
                            "cacheDir": cache_dir,
                            "source": if cache_disabled { "disabled" }
                                else if is_custom { "env" } else { "default" },
                            "explanation": if cache_disabled {
                                "CODELATTICE_CACHE=off. Persistent cache is disabled."
                            } else if is_custom {
                                "CODELATTICE_CACHE_DIR is set explicitly."
                            } else {
                                "Using default cache directory ~/.cache/codelattice. Set CODELATTICE_CACHE=off to disable, or CODELATTICE_CACHE_DIR to override."
                            },
                        },
                        "activeAnalysisCount": crate::mcp_job::active_analysis_count(),
                        "generatedFrom": {"staticAnalysis": false, "targetCodeExecuted": false}
                    });
                    Some(Ok(tool_result(&body)))
                }
                "explain" => {
                    let body = json!({
                        "layers": ["memory", "persistent"],
                        "disable": "CODELATTICE_CACHE=off",
                        "clear": "Use mode=clear",
                        "prewarm": "Use codelattice_cache_prewarm"
                    });
                    Some(Ok(tool_result(&body)))
                }
                _ => None,
            }
        }
        "codelattice_project"
        | "codelattice_symbol"
        | "codelattice_change_review"
        | "codelattice_workspace" => {
            let mode = params["mode"].as_str().unwrap_or("");
            match mode {
                "job" => {
                    let root = params["root"].as_str().unwrap_or("");
                    let compact = params["compact"].as_bool().unwrap_or(false);
                    if root.is_empty() {
                        return Some(Err(mcp_error(
                            "missing_parameter",
                            "root required for job mode",
                        )));
                    }
                    let requested_language = params["language"].as_str().unwrap_or("auto");
                    if tool_name != "codelattice_workspace" {
                        if let Some(error) = workspace_root_selection_error(
                            root,
                            requested_language,
                            tool_name,
                            "job",
                        ) {
                            let response = attach_facade_job_contract(
                                error,
                                tool_name,
                                mode,
                                root,
                                requested_language,
                                compact,
                            );
                            return Some(Ok(tool_result(&response)));
                        }
                    }
                    let language = if tool_name == "codelattice_workspace" {
                        "auto".to_string()
                    } else {
                        let validated_root = match validate_root_path(root) {
                            Ok(root) => root,
                            Err(err) => return Some(Err(err)),
                        };
                        match resolve_auto_language_for_root(&validated_root, requested_language) {
                            Ok(language) => language,
                            Err(err) => return Some(Err(err)),
                        }
                    };
                    let parallel = params["parallel"].as_bool().unwrap_or(false);
                    let engine_mode = if parallel { "parallel" } else { "serial" };
                    let result = if tool_name == "codelattice_workspace" {
                        crate::mcp_job::submit_workspace_job(root, engine_mode)
                    } else {
                        crate::mcp_job::submit_project_job(root, &language, engine_mode)
                    };
                    let mut result = match result {
                        Ok(v) => v,
                        Err(e) => {
                            return Some(Err(mcp_error(
                                "job_submit_failed",
                                &format!("Failed to submit job: {e}"),
                            )))
                        }
                    };

                    if params["wait"].as_bool().unwrap_or(false) {
                        let job_id = result["jobId"].as_str().unwrap_or("").to_string();
                        if !job_id.is_empty() {
                            let timeout_ms = params["timeoutMs"].as_u64().unwrap_or(10000);
                            let (final_status, timed_out) =
                                crate::mcp_job::MCP_JOBS.wait_for_job(&job_id, timeout_ms);
                            if let Some(status) = final_status {
                                result = status;
                                if timed_out {
                                    if let Some(obj) = result.as_object_mut() {
                                        obj.insert("waitTimedOut".to_string(), json!(true));
                                        obj.insert("retryAfterMs".to_string(), json!(2000));
                                        obj.insert(
                                            "message".to_string(),
                                            json!(format!(
                                                "Job {} still running after {}ms. Poll job_status to check completion.",
                                                job_id,
                                                timeout_ms.min(30000)
                                            )),
                                        );
                                    }
                                }
                            }
                        }
                    }
                    let response = attach_facade_job_contract(
                        result,
                        tool_name,
                        mode,
                        root,
                        requested_language,
                        compact,
                    );
                    Some(Ok(tool_result(&response)))
                }
                "job_status" => {
                    let job_id = params["jobId"].as_str().unwrap_or("");
                    let requested_language = params["language"].as_str().unwrap_or("auto");
                    let requested_root = params["root"].as_str().unwrap_or("");
                    let compact = params["compact"].as_bool().unwrap_or(false);
                    if job_id.is_empty() {
                        return Some(Err(mcp_error(
                            "missing_parameter",
                            "jobId required for job_status mode",
                        )));
                    }
                    match crate::mcp_job::get_job_status(job_id) {
                        Some(job) => {
                            let response = attach_facade_job_contract(
                                job,
                                tool_name,
                                mode,
                                requested_root,
                                requested_language,
                                compact,
                            );
                            Some(Ok(tool_result(&response)))
                        }
                        None => {
                            let response = attach_facade_job_contract(
                                json!({
                                    "error": "job_not_found",
                                    "jobId": job_id,
                                    "facade": tool_name
                                }),
                                tool_name,
                                mode,
                                requested_root,
                                requested_language,
                                compact,
                            );
                            Some(Ok(tool_result(&response)))
                        }
                    }
                }
                "job_cancel" => {
                    let job_id = params["jobId"].as_str().unwrap_or("");
                    let requested_language = params["language"].as_str().unwrap_or("auto");
                    let requested_root = params["root"].as_str().unwrap_or("");
                    let compact = params["compact"].as_bool().unwrap_or(false);
                    if job_id.is_empty() {
                        return Some(Err(mcp_error(
                            "missing_parameter",
                            "jobId required for job_cancel mode",
                        )));
                    }
                    let response = attach_facade_job_contract(
                        crate::mcp_job::MCP_JOBS.cancel_job(job_id),
                        tool_name,
                        mode,
                        requested_root,
                        requested_language,
                        compact,
                    );
                    Some(Ok(tool_result(&response)))
                }
                "job_detail" => {
                    let job_id = params["jobId"].as_str().unwrap_or("");
                    let requested_language = params["language"].as_str().unwrap_or("auto");
                    let requested_root = params["root"].as_str().unwrap_or("");
                    let compact = params["compact"].as_bool().unwrap_or(false);
                    if job_id.is_empty() {
                        return Some(Err(mcp_error(
                            "missing_parameter",
                            "jobId required for job_detail mode",
                        )));
                    }
                    let page = params["page"].as_u64().unwrap_or(0) as usize;
                    let page_size =
                        params["pageSize"].as_u64().unwrap_or(50).clamp(1, 200) as usize;
                    if crate::mcp_job::MCP_JOBS.get(job_id).is_none() {
                        let response = attach_facade_job_contract(
                            json!({
                                "error": "job_not_found",
                                "jobId": job_id,
                                "facade": tool_name
                            }),
                            tool_name,
                            mode,
                            requested_root,
                            requested_language,
                            compact,
                        );
                        return Some(Ok(tool_result(&response)));
                    }
                    match crate::mcp_job::MCP_JOBS.get_detail_page(job_id, page, page_size) {
                        Some(page_result) => {
                            let response = attach_facade_job_contract(
                                page_result,
                                tool_name,
                                mode,
                                requested_root,
                                requested_language,
                                compact,
                            );
                            Some(Ok(tool_result(&response)))
                        }
                        None => {
                            let handle = crate::mcp_job::MCP_JOBS.get(job_id);
                            let status_str = handle
                                .as_ref()
                                .map(|h| match h.status {
                                    JobStatus::Queued => "queued",
                                    JobStatus::Running => "running",
                                    JobStatus::Succeeded => "succeeded",
                                    JobStatus::Failed => "failed",
                                    JobStatus::Cancelled => "cancelled",
                                })
                                .unwrap_or("unknown");
                            if matches!(
                                handle.as_ref().map(|h| h.status),
                                Some(JobStatus::Running) | Some(JobStatus::Queued)
                            ) {
                                let response = attach_facade_job_contract(
                                    json!({
                                    "schemaVersion": "codelattice.jobNotReady.v1",
                                    "status": "job_not_ready",
                                    "jobId": job_id,
                                    "jobStatus": status_str,
                                    "message": "Job is still running. Detail pages will be available after job succeeds.",
                                    "retryAfterSeconds": 3,
                                    "recommendedNextCalls": [
                                        {"tool": tool_name, "mode": "job_status", "arguments": {"jobId": job_id}},
                                        {"tool": tool_name, "mode": "job_detail", "arguments": {"jobId": job_id, "page": page, "pageSize": page_size}}
                                    ]
                                    }),
                                    tool_name,
                                    mode,
                                    requested_root,
                                    requested_language,
                                    compact,
                                );
                                Some(Ok(tool_result(&response)))
                            } else {
                                let response = attach_facade_job_contract(
                                    json!({
                                        "error": "job_detail_unavailable",
                                        "jobId": job_id,
                                        "facade": tool_name
                                    }),
                                    tool_name,
                                    mode,
                                    requested_root,
                                    requested_language,
                                    compact,
                                );
                                Some(Ok(tool_result(&response)))
                            }
                        }
                    }
                }
                _ => None,
            }
        }
        _ => None,
    }
}

fn make_busy_response(id: &Value, tool_name: &str) -> Value {
    let running_jobs = crate::mcp_job::get_running_jobs_info();
    let running_job_id = running_jobs.first().map(|j| j.job_id.clone());
    let retry_after = 5u64;
    let body = json!({
        "schemaVersion": "codelattice.mcpBusy.v2",
        "error": "mcp_server_busy",
        "backpressureKind": "analysis_in_progress",
        "tool": tool_name,
        "runningJobId": running_job_id,
        "retryAfterSeconds": retry_after,
        "message": "An analysis job is running in the background. Control-plane calls (cache status, job_status, job_detail) are still available.",
        "allowedControlCalls": [
            "codelattice_cache(mode=status)",
            "codelattice_project(mode=job_status, jobId=...)",
            "codelattice_project(mode=job_detail, jobId=...)",
            "codelattice_symbol(mode=job_status, jobId=...)",
            "codelattice_workspace(mode=job_status, jobId=...)"
        ],
        "canCallCacheStatus": true,
        "canCallJobStatus": true,
        "canCallJobCancel": true,
        "recommendedNextCalls": if running_job_id.is_some() {
            vec![
                json!({"tool": "codelattice_project", "mode": "job_status", "arguments": {"jobId": running_job_id}}),
                json!({"tool": "codelattice_cache", "mode": "status", "arguments": {"compact": true}})
            ]
        } else {
            vec![]
        },
        "retry": format!("Wait {} seconds and retry, or use control-plane calls to check progress.", retry_after),
        "aiGuidance": [
            "Analysis now runs in background threads. The MCP event loop is not blocked.",
            "Use job_status/job_detail to poll progress — these always work even during analysis.",
            "Use codelattice_cache(mode=status) to check cache state — always available.",
            "Do not keep retrying analysis calls in a tight loop; poll job_status instead."
        ],
        "generatedFrom": {
            "staticAnalysis": false,
            "targetCodeExecuted": false,
            "scriptsExecuted": false
        }
    });
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": {
            "content": [{ "type": "text", "text": serde_json::to_string(&body).unwrap_or_default() }],
            "isError": true
        }
    })
}

fn handle_request(request: &Value, cache: &mut McpCache) -> Option<Value> {
    let method = request["method"].as_str().unwrap_or("");
    let id = request.get("id").cloned().unwrap_or(Value::Null);
    let params = request.get("params").cloned().unwrap_or(json!({}));

    // Notifications (no id or id is null) don't get responses
    if id.is_null() && !method.starts_with("tools/") {
        match method {
            "notifications/initialized" => {
                eprintln!("[mcp] client initialized");
                return None;
            }
            _ => {
                eprintln!("[mcp] ignoring notification: {}", method);
                return None;
            }
        }
    }

    match method {
        "initialize" => {
            let cangjie_support = {
                #[cfg(feature = "tree-sitter-cangjie")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-cangjie"))]
                {
                    false
                }
            };
            let arkts_support = {
                #[cfg(feature = "tree-sitter-arkts")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-arkts"))]
                {
                    false
                }
            };
            let typescript_support = {
                #[cfg(feature = "tree-sitter-typescript")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-typescript"))]
                {
                    false
                }
            };
            let c_support = {
                #[cfg(feature = "tree-sitter-c")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-c"))]
                {
                    false
                }
            };
            let cpp_support = {
                #[cfg(feature = "tree-sitter-cpp")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-cpp"))]
                {
                    false
                }
            };
            let python_support = {
                #[cfg(feature = "tree-sitter-python")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-python"))]
                {
                    false
                }
            };
            let javascript_support = {
                #[cfg(feature = "tree-sitter-javascript")]
                {
                    true
                }
                #[cfg(not(feature = "tree-sitter-javascript"))]
                {
                    false
                }
            };
            let toolset = current_toolset();
            let full_tool_count = tools_list()["tools"]
                .as_array()
                .map(|tools| tools.len())
                .unwrap_or(0);
            let tool_count = tool_count_for_toolset(toolset);
            Some(make_response(
                &id,
                json!({
                    "protocolVersion": "2024-11-05",
                    "capabilities": { "tools": {} },
                    "serverInfo": {
                        "name": "codelattice",
                        "version": "0.16.0-beta.1",
                        "cangjieSupport": cangjie_support,
                        "arktsSupport": arkts_support,
                        "typescriptSupport": typescript_support,
                        "cSupport": c_support,
                        "cppSupport": cpp_support,
                        "pythonSupport": python_support,
                        "javascriptSupport": javascript_support,
                        "shellSupport": true,
                        "toolset": toolset.as_str(),
                        "toolCount": tool_count,
                        "fullToolCount": full_tool_count,
                        "recommendedEntryTools": [
                            "codelattice_workflow",
                            "codelattice_project",
                            "codelattice_symbol",
                            "codelattice_change_review",
                            "codelattice_workspace",
                            "codelattice_cache"
                        ]
                    }
                }),
            ))
        }

        "tools/list" => {
            let mut tools_val = tools_list();
            filter_tools_by_toolset(&mut tools_val, current_toolset());
            Some(make_response(&id, tools_val))
        }

        "tools/call" => {
            let tool_name = params["name"].as_str().unwrap_or("");

            let arguments = params.get("arguments").cloned().unwrap_or(json!({}));
            let toolset = current_toolset();
            if tool_exists(tool_name) && !is_tool_allowed_in_toolset(tool_name, toolset) {
                return Some(make_response(
                    &id,
                    json!({
                        "content": [{ "type": "text", "text": serde_json::to_string(&hidden_toolset_error(tool_name, toolset)).unwrap_or_default() }],
                        "isError": true
                    }),
                ));
            }

            let result = match tool_name {
                "codelattice_analyze" => handle_analyze(cache, &arguments),
                "codelattice_quality" => handle_quality(cache, &arguments),
                "codelattice_summary" => handle_summary(cache, &arguments),
                "codelattice_smoke" => handle_smoke(cache, &arguments),
                "codelattice_graph_overview" => handle_graph_overview(cache, &arguments),
                "codelattice_unresolved_report" => handle_unresolved_report(cache, &arguments),
                "codelattice_symbol_search" => handle_symbol_search(cache, &arguments),
                "codelattice_export_bridge" => handle_export_bridge(cache, &arguments),
                "codelattice_symbol_context" => handle_symbol_context(cache, &arguments),
                "codelattice_calls_from" => handle_calls_from(cache, &arguments),
                "codelattice_calls_to" => handle_calls_to(cache, &arguments),
                "codelattice_impact_preview" => handle_impact_preview(cache, &arguments),
                "codelattice_query_graph" => handle_query_graph(cache, &arguments),
                "codelattice_project_overview" => handle_project_overview(cache, &arguments),
                "codelattice_repo_registry" => handle_repo_registry(cache, &arguments),
                "codelattice_rename_preview" => handle_rename_preview(cache, &arguments),
                "codelattice_cache_status" => handle_cache_status(cache, &arguments),
                "codelattice_cache_clear" => handle_cache_clear(cache, &arguments),
                "codelattice_production_assist" => handle_production_assist(cache, &arguments),
                "codelattice_compare_runs" => handle_compare_runs(cache, &arguments),
                "codelattice_cache_prewarm" => handle_cache_prewarm(cache, &arguments),
                "codelattice_changed_symbols" => handle_changed_symbols(cache, &arguments),
                "codelattice_project_insights" => handle_project_insights(cache, &arguments),
                "codelattice_review_plan" => handle_review_plan(cache, &arguments),
                "codelattice_dead_code_candidates" => {
                    handle_dead_code_candidates(cache, &arguments)
                }
                "codelattice_impact_analysis" => handle_impact_analysis(cache, &arguments),
                "codelattice_risk_hotspots" => handle_risk_hotspots(cache, &arguments),
                "codelattice_architecture_drift" => handle_architecture_drift(cache, &arguments),
                "codelattice_ai_context_pack" => handle_ai_context_pack(cache, &arguments),
                "codelattice_review_gate" => handle_review_gate(cache, &arguments),
                "codelattice_root_cause_assistant" => {
                    handle_root_cause_assistant(cache, &arguments)
                }
                "codelattice_reachability_map" => handle_reachability_map(cache, &arguments),
                "codelattice_external_api_surface" => {
                    handle_external_api_surface(cache, &arguments)
                }
                "codelattice_framework_entry_hints" => {
                    handle_framework_entry_hints(cache, &arguments)
                }
                "codelattice_breaking_change_review" => {
                    handle_breaking_change_review(cache, &arguments)
                }
                "codelattice_consistency_review" => handle_consistency_review(cache, &arguments),
                "codelattice_config_examples_review" => {
                    handle_config_examples_review(cache, &arguments)
                }
                "codelattice_automation_graph" => handle_automation_graph(cache, &arguments),
                "codelattice_workflow_presets" => handle_workflow_presets(cache, &arguments),
                "codelattice_workspace_graph" => handle_workspace_graph(cache, &arguments),
                "codelattice_cross_project_impact" => {
                    handle_cross_project_impact(cache, &arguments)
                }
                "codelattice_project" => handle_project(cache, &arguments),
                "codelattice_symbol" => handle_symbol(cache, &arguments),
                "codelattice_change_review" => handle_change_review(cache, &arguments),
                "codelattice_cleanup" => handle_cleanup(cache, &arguments),
                "codelattice_workspace" => handle_workspace(cache, &arguments),
                "codelattice_release_check" => handle_release_check(cache, &arguments),
                "codelattice_cache" => handle_cache(cache, &arguments),
                "codelattice_workflow" => handle_workflow(cache, &arguments),
                _ => Err(mcp_error(
                    "unknown_tool",
                    &format!("Unknown tool: {tool_name}"),
                )),
            };

            match result {
                Ok(r) => Some(make_response(&id, r)),
                Err(e) => Some(make_response(
                    &id,
                    json!({
                        "content": [{ "type": "text", "text": serde_json::to_string(&e).unwrap_or_default() }],
                        "isError": true
                    }),
                )),
            }
        }

        "shutdown" | "exit" => {
            eprintln!("[mcp] shutdown requested");
            None
        }

        _ => Some(make_error_response(
            &id,
            -32601,
            &format!("Method not found: {method}"),
        )),
    }
}

