fn automation_rel_path(root: &Path, path: &Path) -> String {
    path.strip_prefix(root)
        .unwrap_or(path)
        .to_string_lossy()
        .replace('\\', "/")
}

fn automation_skip_dir(name: &str) -> bool {
    matches!(
        name,
        ".git"
            | ".gitnexus"
            | ".claude"
            | ".arts"
            | "target"
            | "node_modules"
            | "dist"
            | "vendor"
            | ".venv"
            | "venv"
            | "__pycache__"
    )
}

fn automation_is_shell_file(path: &Path) -> bool {
    let name = path
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("")
        .to_ascii_lowercase();
    let ext = path
        .extension()
        .and_then(|s| s.to_str())
        .unwrap_or("")
        .to_ascii_lowercase();
    matches!(ext.as_str(), "sh" | "bash" | "zsh" | "ksh" | "bats")
        || matches!(
            name.as_str(),
            "build" | "test" | "release" | "install" | "configure"
        )
}

#[cfg(test)]
mod tests {
    use super::*;

    // ═══ Fix #1: ask evidence/confidence 必须出现在 ask_result ═══

    #[test]
    fn mcp_workflow_ask_approval_returns_evidence_and_confidence() {
        let mut cache = McpCache::new();
        let result = handle_workflow(
            &mut cache,
            &json!({
                "mode": "ask",
                "question": "What is the approval flow?",
                "root": "/nonexistent",
                "language": "auto"
            }),
        );
        let resp = result.expect("ask should succeed");
        let text = resp["content"][0]["text"].as_str().unwrap_or("");
        let parsed: Value = serde_json::from_str(text).unwrap_or(Value::Null);

        // 必须有 evidence 字段（array）
        assert!(
            parsed["evidence"].is_array(),
            "ask_result must have evidence array, got: {:?}",
            parsed.get("evidence")
        );
        // 必须有 confidence 字段（object with level + reason）
        assert!(
            parsed["confidence"]["level"].is_string(),
            "ask_result must have confidence.level, got: {:?}",
            parsed.get("confidence")
        );
        assert!(
            parsed["confidence"]["reason"].is_string(),
            "ask_result must have confidence.reason, got: {:?}",
            parsed.get("confidence")
        );
        // 必须有 aiGuidance
        assert!(
            parsed["aiGuidance"].is_string(),
            "ask_result must have aiGuidance, got: {:?}",
            parsed.get("aiGuidance")
        );
    }

    // ═══ Fix #2: extract_symbol 优先返回业务关键词 ═══

    #[test]
    fn mcp_workflow_ask_approval_prefers_approval_query_not_flow() {
        // "What is the approval flow?" 应提取 "approval" 而非 "flow"
        let sym = extract_symbol_from_question("What is the approval flow?");
        assert_eq!(
            sym, "approval",
            "expected 'approval' but got '{}': should prioritize business keywords",
            sym
        );
    }

    #[test]
    fn extract_symbol_prefers_route_over_last_word() {
        let sym = extract_symbol_from_question("Where is the API route handler?");
        // 应优先 route 或 handler，而非最后一个词
        assert!(
            sym == "route" || sym == "handler" || sym == "api",
            "expected business keyword (route/handler/api) but got '{}'",
            sym
        );
    }

    #[test]
    fn extract_symbol_prefers_handler_in_question() {
        let sym = extract_symbol_from_question("Show me the handler for approval");
        assert!(
            sym == "handler" || sym == "approval",
            "expected 'handler' or 'approval' but got '{}'",
            sym
        );
    }

    // ═══ Fix #4: compact schedule 去重 ═══

    #[test]
    fn mcp_compact_schedule_strips_phases() {
        let mut value = json!({
            "schedule": {
                "action": "analyze",
                "cacheIntent": "memory",
                "reason": "cold start",
                "phases": [
                    {"name": "phase1", "files": 100},
                    {"name": "phase2", "files": 200},
                    {"name": "phase3", "files": 300},
                    {"name": "phase4", "files": 400}
                ],
                "fileSnapshot": [{"path": "a.rs"}, {"path": "b.rs"}],
                "fingerprint": "abcdef1234567890"
            },
            "other": "data"
        });
        compact_strip_schedule(&mut value);
        // schedule 应被替换为 scheduleSummary
        assert!(
            value["scheduleSummary"].is_object(),
            "schedule should be replaced with scheduleSummary"
        );
        assert!(
            value["schedule"].is_null(),
            "original schedule should be removed"
        );
        // scheduleSummary 不应含 phases/fileSnapshot
        let summary = &value["scheduleSummary"];
        assert_eq!(summary["action"], "analyze");
        assert_eq!(summary["phaseCount"], 4);
        assert_eq!(summary["dirtyFileCount"], 2);
        assert_eq!(summary["fingerprintShort"], "abcdef123456");
        assert!(
            summary["phases"].is_null(),
            "scheduleSummary must not have phases"
        );
    }

    #[test]
    fn mcp_compact_schedule_recursive_in_result() {
        let mut value = json!({
            "result": {
                "data": "something",
                "schedule": {
                    "action": "reanalyze",
                    "phases": [{"name": "p1"}, {"name": "p2"}, {"name": "p3"}],
                    "fingerprint": "deadbeef"
                },
                "nested": {
                    "schedule": {
                        "action": "cache",
                        "phases": [{"name": "n1"}]
                    }
                }
            }
        });
        compact_strip_schedule(&mut value);
        // 递归应处理 result 内部的 schedule
        let result = &value["result"];
        assert!(
            result["scheduleSummary"].is_object(),
            "result.schedule should be replaced"
        );
        assert_eq!(result["scheduleSummary"]["phaseCount"], 3);
        assert!(
            result["nested"]["scheduleSummary"].is_object(),
            "nested schedule should also be replaced"
        );
        assert_eq!(result["nested"]["scheduleSummary"]["phaseCount"], 1);
    }

    #[test]
    fn mcp_build_schedule_summary_truncates_fingerprint() {
        let schedule = json!({
            "action": "analyze",
            "cacheIntent": "memory",
            "reason": "cold",
            "phases": [1, 2, 3, 4, 5, 6, 7, 8],
            "fingerprint": "0123456789abcdef0123456789abcdef"
        });
        let summary = build_schedule_summary(&schedule);
        assert_eq!(summary["fingerprintShort"], "0123456789ab");
        assert_eq!(summary["phaseCount"], 8);
    }

    // ═══ Fix #5: change_review job_cancel 允许 ═══

    #[test]
    fn mcp_change_review_job_cancel_control_plane_allowed() {
        let mut cache = McpCache::new();
        // 先提交一个 job
        let job_result = handle_change_review(
            &mut cache,
            &json!({
                "mode": "job",
                "root": "/tmp/codelattice-test-cancel",
                "language": "rust",
            }),
        );
        // 如果 job 提交成功（不一定，取决于环境），尝试 cancel
        // 关键是验证 job_cancel 不被 invalid_mode 拦截
        let result = handle_change_review(
            &mut cache,
            &json!({
                "mode": "job_cancel",
                "jobId": "fake_job_id_for_test",
            }),
        );
        // 不应返回 invalid_mode 错误
        match result {
            Ok(resp) => {
                // cancel 应该返回（即使是 job not found）
                assert!(
                    resp["content"][0]["text"]
                        .as_str()
                        .unwrap_or("")
                        .contains("cancelled")
                        || resp["content"][0]["text"]
                            .as_str()
                            .unwrap_or("")
                            .contains("not_found")
                        || resp["content"][0]["text"]
                            .as_str()
                            .unwrap_or("")
                            .contains("cancel"),
                    "job_cancel should not be blocked by invalid_mode"
                );
            }
            Err(_) => {
                // 其他错误也可接受（如 job not found），关键是没被 invalid_mode 拦截
            }
        }
    }

    // ═══ Fix #6: job wait=true 支持 ═══

    #[test]
    fn mcp_job_wait_timeout_returns_job_id() {
        // 测试 wait_for_job 在超时时返回正确的结构
        let registry = crate::mcp_job::McpJobRegistry::new();
        let job = registry.submit("/tmp/wait-test", "rust", "serial");
        let job_id = job.job_id;

        let (status, timed_out) = registry.wait_for_job(&job_id, 100);
        assert!(timed_out, "should time out");
        assert!(status.is_some(), "should return status even on timeout");
    }

    // ═══ 综合测试：ask 对 no cache 也返回 evidence + confidence ═══

    #[test]
    fn mcp_workflow_ask_no_cache_returns_empty_evidence_and_low_confidence() {
        let mut cache = McpCache::new();
        let result = handle_workflow(
            &mut cache,
            &json!({
                "mode": "ask",
                "question": "审批流程是什么？",
                "root": "/nonexistent/path",
                "language": "auto"
            }),
        );
        let resp = result.expect("ask should succeed");
        let text = resp["content"][0]["text"].as_str().unwrap_or("");
        let parsed: Value = serde_json::from_str(text).unwrap_or(Value::Null);

        assert!(
            parsed["evidence"].is_array(),
            "evidence must be array even when no cache"
        );
        assert_eq!(
            parsed["evidence"].as_array().unwrap().len(),
            0,
            "evidence should be empty when no cache"
        );
        assert_eq!(
            parsed["confidence"]["level"].as_str().unwrap_or(""),
            "low",
            "confidence should be low when no cache"
        );
    }
}

fn automation_kind_for_path(
    rel: &str,
    include_shell: bool,
    include_ci: bool,
    include_pkg: bool,
    include_docker: bool,
) -> Option<&'static str> {
    let lower = rel.to_ascii_lowercase();
    let file = Path::new(rel)
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("")
        .to_ascii_lowercase();
    if include_ci
        && (lower.starts_with(".github/workflows/")
            || lower.starts_with(".gitee/workflows/")
            || file == ".gitlab-ci.yml"
            || file == ".gitlab-ci.yaml"
            || file == ".gitcode-ci.yml"
            || file == ".gitcode-ci.yaml"
            || file == "jenkinsfile")
    {
        return Some("ci");
    }
    if include_pkg && file == "package.json" {
        return Some("package-script");
    }
    if file == "makefile" || file.ends_with(".mk") {
        return Some("makefile");
    }
    if include_docker && (file == "dockerfile" || file.starts_with("dockerfile.")) {
        return Some("docker");
    }
    if include_shell && automation_is_shell_file(Path::new(rel)) {
        return Some("shell");
    }
    None
}

fn collect_automation_files(
    root: &Path,
    include_shell: bool,
    include_ci: bool,
    include_pkg: bool,
    include_docker: bool,
) -> Vec<(PathBuf, String, String)> {
    fn walk(
        root: &Path,
        dir: &Path,
        out: &mut Vec<(PathBuf, String, String)>,
        include_shell: bool,
        include_ci: bool,
        include_pkg: bool,
        include_docker: bool,
    ) {
        if out.len() >= 500 {
            return;
        }
        let Ok(entries) = std::fs::read_dir(dir) else {
            return;
        };
        for entry in entries.flatten() {
            let path = entry.path();
            let name = entry.file_name().to_string_lossy().to_string();
            if path.is_dir() {
                if !automation_skip_dir(&name) {
                    walk(
                        root,
                        &path,
                        out,
                        include_shell,
                        include_ci,
                        include_pkg,
                        include_docker,
                    );
                }
                continue;
            }
            let rel = automation_rel_path(root, &path);
            if let Some(kind) = automation_kind_for_path(
                &rel,
                include_shell,
                include_ci,
                include_pkg,
                include_docker,
            ) {
                out.push((path, rel, kind.to_string()));
            }
        }
    }

    let mut out = Vec::new();
    walk(
        root,
        root,
        &mut out,
        include_shell,
        include_ci,
        include_pkg,
        include_docker,
    );
    out.sort_by(|a, b| a.1.cmp(&b.1));
    out
}

fn automation_highest_risk(current: &str, next: &str) -> String {
    let rank = |s: &str| match s {
        "critical" => 4,
        "high" => 3,
        "medium" => 2,
        "low" => 1,
        _ => 0,
    };
    if rank(next) > rank(current) {
        next.to_string()
    } else {
        current.to_string()
    }
}

fn automation_risk_findings(rel: &str, line_no: usize, text: &str) -> Vec<Value> {
    let lower = text.to_ascii_lowercase();
    let mut out = Vec::new();
    let mut push = |severity: &str, kind: &str, message: &str, action: &str| {
        out.push(json!({
            "severity": severity,
            "kind": kind,
            "file": rel,
            "line": line_no,
            "message": message,
            "reviewAction": action
        }));
    };

    if (lower.contains("curl ") || lower.contains("wget "))
        && (lower.contains("| sh") || lower.contains("| bash"))
    {
        push(
            "high",
            "curl_pipe_shell",
            "downloaded script is piped directly to a shell",
            "pin source, verify checksum, and avoid pipe-to-shell installers",
        );
    }
    if lower.contains("rm -rf") {
        push(
            "medium",
            "rm_rf",
            "destructive recursive delete command appears in automation",
            "verify path guards and dry-run behavior before running",
        );
    }
    if lower.contains("sudo ") {
        push(
            "medium",
            "sudo",
            "automation command requests elevated privileges",
            "verify why privilege escalation is required",
        );
    }
    if lower.contains("chmod 777") {
        push(
            "medium",
            "chmod_777",
            "world-writable permission change appears in automation",
            "use narrower permissions and document ownership expectations",
        );
    }
    if lower.contains("docker run") && lower.contains("--privileged") {
        push(
            "high",
            "docker_privileged",
            "privileged Docker run appears in automation",
            "review container isolation and host access assumptions",
        );
    }
    if lower.contains("pull_request_target") {
        push(
            "high",
            "pull_request_target",
            "pull_request_target workflow can run with privileged token context",
            "review checkout/ref handling and token permissions",
        );
    }
    if lower.starts_with("uses:")
        && (lower.ends_with("@main") || lower.ends_with("@master") || lower.ends_with("@latest"))
    {
        push(
            "medium",
            "workflow_unpinned_action",
            "workflow action is pinned to a mutable ref",
            "pin actions to a version tag or commit SHA",
        );
    }
    if lower.contains("echo $")
        && (lower.contains("secret") || lower.contains("token") || lower.contains("password"))
    {
        push(
            "high",
            "secret_echo",
            "automation may print secret-like environment variables",
            "remove secret echoing and rely on masked CI logs",
        );
    }
    out
}

fn automation_extract_script_refs(command: &str) -> Vec<String> {
    command
        .split(|c: char| c.is_whitespace() || matches!(c, '"' | '\'' | ';' | '&' | '|'))
        .filter(|token| {
            token.ends_with(".sh")
                || token.ends_with(".bash")
                || token.ends_with(".zsh")
                || token.starts_with("scripts/")
        })
        .map(|s| s.trim_start_matches("./").to_string())
        .collect()
}

fn automation_push_step(
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
    workflow_id: &str,
    workflow_risk: &mut String,
    rel: &str,
    step_kind: &str,
    name: &str,
    command: &str,
    line_no: usize,
) {
    let step_id = format!("{workflow_id}:step:{line_no}:{}", steps.len() + 1);
    let findings = automation_risk_findings(rel, line_no, command);
    for finding in &findings {
        if let Some(sev) = finding["severity"].as_str() {
            *workflow_risk = automation_highest_risk(workflow_risk, sev);
        }
    }
    risks.extend(findings.clone());
    steps.push(json!({
        "id": step_id,
        "workflowId": workflow_id,
        "name": name,
        "kind": step_kind,
        "command": command,
        "file": rel,
        "line": line_no,
        "riskLevel": workflow_risk,
        "riskFindingCount": findings.len()
    }));
    edges.push(json!({
        "source": workflow_id,
        "target": step_id,
        "type": "contains",
        "reason": "workflow-contains-step"
    }));
}

fn parse_ci_workflow(
    rel: &str,
    content: &str,
    workflows: &mut Vec<Value>,
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
) {
    let mut name = Path::new(rel)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("ci")
        .to_string();
    for line in content.lines() {
        let trimmed = line.trim();
        if let Some(rest) = trimmed.strip_prefix("name:") {
            let candidate = rest.trim().trim_matches('"').trim_matches('\'');
            if !candidate.is_empty() {
                name = candidate.to_string();
            }
            break;
        }
    }
    let workflow_id = format!("ci:{rel}");
    let mut risk_level = "low".to_string();
    let start_steps = steps.len();
    for (idx, line) in content.lines().enumerate() {
        let trimmed = line.trim();
        if trimmed.starts_with("run:") {
            let command = trimmed.trim_start_matches("run:").trim();
            automation_push_step(
                steps,
                edges,
                risks,
                &workflow_id,
                &mut risk_level,
                rel,
                "run",
                "run",
                command,
                idx + 1,
            );
        } else if trimmed.starts_with("uses:") || trimmed.starts_with("- uses:") {
            let command = trimmed.trim_start_matches("- ").trim();
            automation_push_step(
                steps,
                edges,
                risks,
                &workflow_id,
                &mut risk_level,
                rel,
                "uses",
                "uses",
                command,
                idx + 1,
            );
        } else {
            let findings = automation_risk_findings(rel, idx + 1, trimmed);
            for finding in &findings {
                if let Some(sev) = finding["severity"].as_str() {
                    risk_level = automation_highest_risk(&risk_level, sev);
                }
            }
            risks.extend(findings);
        }
    }
    workflows.push(json!({
        "id": workflow_id,
        "name": name,
        "kind": "ci",
        "file": rel,
        "line": 1,
        "stepCount": steps.len().saturating_sub(start_steps),
        "riskLevel": risk_level
    }));
}

fn parse_package_scripts(
    rel: &str,
    content: &str,
    workflows: &mut Vec<Value>,
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
) {
    let Ok(value) = serde_json::from_str::<Value>(content) else {
        return;
    };
    let Some(scripts) = value["scripts"].as_object() else {
        return;
    };
    for (name, command_value) in scripts {
        let Some(command) = command_value.as_str() else {
            continue;
        };
        let workflow_id = format!("package:{name}");
        let mut risk_level = "low".to_string();
        let start_steps = steps.len();
        automation_push_step(
            steps,
            edges,
            risks,
            &workflow_id,
            &mut risk_level,
            rel,
            "package-script",
            name,
            command,
            1,
        );
        workflows.push(json!({
            "id": workflow_id,
            "name": name,
            "kind": "package-script",
            "file": rel,
            "line": 1,
            "stepCount": steps.len().saturating_sub(start_steps),
            "riskLevel": risk_level
        }));
    }
}

fn parse_makefile(
    rel: &str,
    content: &str,
    workflows: &mut Vec<Value>,
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
) {
    let mut current: Option<(String, String, usize, String, usize)> = None;
    for (idx, line) in content.lines().enumerate() {
        if !line.starts_with('\t') && line.contains(':') && !line.contains('=') {
            if let Some((id, name, line_no, risk, start)) = current.take() {
                workflows.push(json!({"id": id, "name": name, "kind": "makefile", "file": rel, "line": line_no, "stepCount": steps.len().saturating_sub(start), "riskLevel": risk}));
            }
            let target = line.split(':').next().unwrap_or("").trim();
            if !target.is_empty() {
                current = Some((
                    format!("make:{rel}:{target}"),
                    target.to_string(),
                    idx + 1,
                    "low".to_string(),
                    steps.len(),
                ));
            }
        } else if line.starts_with('\t') {
            if let Some((id, _, _, risk, _)) = current.as_mut() {
                let command = line.trim();
                automation_push_step(
                    steps,
                    edges,
                    risks,
                    id,
                    risk,
                    rel,
                    "make-command",
                    "make-command",
                    command,
                    idx + 1,
                );
            }
        }
    }
    if let Some((id, name, line_no, risk, start)) = current.take() {
        workflows.push(json!({"id": id, "name": name, "kind": "makefile", "file": rel, "line": line_no, "stepCount": steps.len().saturating_sub(start), "riskLevel": risk}));
    }
}

fn parse_dockerfile(
    rel: &str,
    content: &str,
    workflows: &mut Vec<Value>,
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
) {
    let workflow_id = format!("docker:{rel}");
    let mut risk_level = "low".to_string();
    let start_steps = steps.len();
    for (idx, line) in content.lines().enumerate() {
        let trimmed = line.trim();
        let upper = trimmed.to_ascii_uppercase();
        if ["RUN ", "COPY ", "CMD ", "ENTRYPOINT "]
            .iter()
            .any(|prefix| upper.starts_with(prefix))
        {
            let kind = upper.split_whitespace().next().unwrap_or("DOCKER");
            automation_push_step(
                steps,
                edges,
                risks,
                &workflow_id,
                &mut risk_level,
                rel,
                &kind.to_ascii_lowercase(),
                kind,
                trimmed,
                idx + 1,
            );
        }
    }
    workflows.push(json!({
        "id": workflow_id,
        "name": rel,
        "kind": "docker",
        "file": rel,
        "line": 1,
        "stepCount": steps.len().saturating_sub(start_steps),
        "riskLevel": risk_level
    }));
}

fn parse_shell_script(
    rel: &str,
    content: &str,
    workflows: &mut Vec<Value>,
    steps: &mut Vec<Value>,
    edges: &mut Vec<Value>,
    risks: &mut Vec<Value>,
) {
    let workflow_id = format!("shell:{rel}");
    let mut risk_level = "low".to_string();
    let start_steps = steps.len();
    for (idx, line) in content.lines().enumerate() {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('#') || trimmed == "set -euo pipefail" {
            continue;
        }
        automation_push_step(
            steps,
            edges,
            risks,
            &workflow_id,
            &mut risk_level,
            rel,
            "shell-command",
            "shell-command",
            trimmed,
            idx + 1,
        );
    }
    workflows.push(json!({
        "id": workflow_id,
        "name": rel,
        "kind": "shell",
        "file": rel,
        "line": 1,
        "stepCount": steps.len().saturating_sub(start_steps),
        "riskLevel": risk_level
    }));
}

fn compute_automation_graph(root: &Path, params: &Value) -> Value {
    let include_shell = params["includeShellScripts"].as_bool().unwrap_or(true);
    let include_ci = params["includeCi"].as_bool().unwrap_or(true);
    let include_pkg = params["includePackageScripts"].as_bool().unwrap_or(true);
    let include_docker = params["includeDocker"].as_bool().unwrap_or(true);
    let compact = params["compact"].as_bool().unwrap_or(true);
    let limit = params["limit"].as_u64().unwrap_or(80).clamp(1, 300) as usize;

    let files =
        collect_automation_files(root, include_shell, include_ci, include_pkg, include_docker);
    let mut workflows: Vec<Value> = Vec::new();
    let mut steps: Vec<Value> = Vec::new();
    let mut edges: Vec<Value> = Vec::new();
    let mut risks: Vec<Value> = Vec::new();

    for (path, rel, kind) in files.iter().take(500) {
        let Ok(content) = std::fs::read_to_string(path) else {
            continue;
        };
        match kind.as_str() {
            "ci" => parse_ci_workflow(
                &rel,
                &content,
                &mut workflows,
                &mut steps,
                &mut edges,
                &mut risks,
            ),
            "package-script" => parse_package_scripts(
                &rel,
                &content,
                &mut workflows,
                &mut steps,
                &mut edges,
                &mut risks,
            ),
            "makefile" => parse_makefile(
                &rel,
                &content,
                &mut workflows,
                &mut steps,
                &mut edges,
                &mut risks,
            ),
            "docker" => parse_dockerfile(
                &rel,
                &content,
                &mut workflows,
                &mut steps,
                &mut edges,
                &mut risks,
            ),
            "shell" => parse_shell_script(
                &rel,
                &content,
                &mut workflows,
                &mut steps,
                &mut edges,
                &mut risks,
            ),
            _ => {}
        }
    }

    let mut workflow_by_file: HashMap<String, String> = HashMap::new();
    for workflow in &workflows {
        if workflow["kind"] == "shell" {
            if let (Some(file), Some(id)) = (workflow["file"].as_str(), workflow["id"].as_str()) {
                workflow_by_file.insert(file.to_string(), id.to_string());
            }
        }
    }
    for step in &steps {
        let Some(source) = step["id"].as_str() else {
            continue;
        };
        let command = step["command"].as_str().unwrap_or("");
        for script in automation_extract_script_refs(command) {
            if let Some(target) = workflow_by_file.get(&script) {
                edges.push(json!({
                    "source": source,
                    "target": target,
                    "type": "invokes",
                    "reason": "automation-command-references-script"
                }));
            }
        }
    }

    let high_count = risks
        .iter()
        .filter(|r| r["severity"] == "high" || r["severity"] == "critical")
        .count();
    let medium_count = risks.iter().filter(|r| r["severity"] == "medium").count();
    let entry_files: Vec<Value> = workflows
        .iter()
        .filter_map(|w| w["file"].as_str())
        .collect::<std::collections::BTreeSet<_>>()
        .into_iter()
        .take(limit)
        .map(|f| json!(f))
        .collect();

    workflows.sort_by(|a, b| {
        let ak = a["kind"].as_str().unwrap_or("");
        let bk = b["kind"].as_str().unwrap_or("");
        ak.cmp(bk).then_with(|| {
            a["file"]
                .as_str()
                .unwrap_or("")
                .cmp(b["file"].as_str().unwrap_or(""))
        })
    });

    let summary = json!({
        "workflowCount": workflows.len(),
        "stepCount": steps.len(),
        "edgeCount": edges.len(),
        "riskCount": risks.len(),
        "highRiskCount": high_count,
        "mediumRiskCount": medium_count,
        "entryCount": entry_files.len(),
        "staticOnly": true
    });

    let workflow_out: Vec<Value> = workflows.into_iter().take(limit).collect();
    let risk_out: Vec<Value> = risks.into_iter().take(limit).collect();
    let mut out = json!({
        "summary": summary,
        "workflows": workflow_out,
        "riskFindings": risk_out,
        "entryFiles": entry_files,
        "generatedFrom": {
            "staticAnalysis": true,
            "runtimeVerified": false,
            "scriptsExecuted": false,
            "buildExecuted": false,
            "heuristic": true
        },
        "cautions": [
            "static automation graph only",
            "scripts and CI jobs were not executed",
            "risk findings are review leads, not proof of exploitability"
        ]
    });
    if !compact {
        if let Some(obj) = out.as_object_mut() {
            obj.insert(
                "steps".to_string(),
                json!(steps.into_iter().take(limit * 3).collect::<Vec<_>>()),
            );
            obj.insert(
                "edges".to_string(),
                json!(edges.into_iter().take(limit * 4).collect::<Vec<_>>()),
            );
        }
    }
    out
}

fn handle_automation_graph(_cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    let validated = validate_root_path(root)?;
    let language = params["language"].as_str().unwrap_or("auto");
    check_language_feature(language)?;
    let result = compute_automation_graph(&validated, params);
    let mut out = result.as_object().cloned().unwrap_or_default();
    out.insert("language".to_string(), json!(language));
    out.insert("root".to_string(), json!(validated));
    Ok(tool_result(&json!(out)))
}

