// v0.29: Facade Tools — Consolidated MCP Tool Surface
// ============================================================

/// 从 tool_result 格式中提取内层 JSON
fn unwrap_tool_result(result: &Value) -> Value {
    result["content"]
        .get(0)
        .and_then(|c| c["text"].as_str())
        .and_then(|s| serde_json::from_str::<Value>(s).ok())
        .unwrap_or(json!({}))
}

// ── AI Usability Hardening: root diagnosis ──────────────────────────

fn diagnose_root(root: &str, language: &str) -> Value {
    diagnose_root_with_source_only_limit(root, language, 50)
}

fn diagnose_root_compact(root: &str, language: &str) -> Value {
    diagnose_root_with_source_only_limit(root, language, 0)
}

/// 判断 root 更像 single_project / workspace / unsupported / unknown
/// 使用 scan_workspace_inventory 扫描目录结构
fn diagnose_root_with_source_only_limit(
    root: &str,
    _language: &str,
    source_only_limit: usize,
) -> Value {
    let path = match PathBuf::from(root).canonicalize() {
        Ok(p) => p,
        Err(_) => {
            return json!({
                "kind": "unknown",
                "inputRoot": root,
                "explanation": "Cannot canonicalize root path. Verify the path exists and is accessible."
            })
        }
    };

    let inventory = match scan_workspace_inventory(&path, true) {
        Ok(inv) => inv,
        Err(e) => {
            return json!({
                "kind": "unknown",
                "inputRoot": root,
                "explanation": format!("Workspace inventory scan failed: {}", e)
            })
        }
    };

    let supported: Vec<_> = inventory.iter().filter(|p| p.supported).collect();
    let unsupported: Vec<_> = inventory.iter().filter(|p| !p.supported).collect();
    let supported_manifest_projects: Vec<_> = supported
        .iter()
        .filter(|p| !p.manifest_file.is_empty())
        .copied()
        .collect();
    let manifest_count = supported_manifest_projects.len();
    let source_only_count = supported.len().saturating_sub(manifest_count);
    let source_only_entries = if source_only_limit == 0 {
        Vec::new()
    } else {
        source_only_entries_json(supported.iter().copied(), source_only_limit)
    };
    let source_only_preview = if source_only_limit == 0 {
        source_only_entry_previews_json(supported.iter().copied(), 5)
    } else {
        Vec::new()
    };
    let source_only_reported = if source_only_limit == 0 {
        source_only_preview.len()
    } else {
        source_only_entries.len()
    };
    let source_only_summary = source_only_summary_from_projects(
        supported.iter().copied(),
        source_only_count,
        source_only_reported,
    );
    let root_project = supported_manifest_projects
        .iter()
        .find(|p| p.relative_path == ".");
    let root_source_project = supported
        .iter()
        .find(|p| p.relative_path == "." && p.manifest_file.is_empty());
    let child_manifest_count = supported_manifest_projects
        .iter()
        .filter(|p| p.relative_path != ".")
        .count();

    // 判断 root 类型
    let (kind, explanation) = if root_project.is_some() && child_manifest_count == 0 {
        (
            "single_project",
            "Root contains a single detected project with a manifest.".to_string(),
        )
    } else if root_project.is_some() && child_manifest_count >= 1 {
        ("workspace", format!(
            "Root contains a manifest-backed project at the root plus {} child manifest-backed project(s). Treat it as a workspace root.",
            child_manifest_count
        ))
    } else if child_manifest_count >= 2 || (root_project.is_none() && manifest_count >= 2) {
        (
            "workspace",
            format!(
                "Root contains {} manifest-backed supported projects across subdirectories.",
                manifest_count
            ),
        )
    } else if supported.is_empty() && !unsupported.is_empty() {
        (
            "unsupported_or_mixed_workspace",
            format!(
                "Root contains {} unsupported modules and no supported projects.",
                unsupported.len()
            ),
        )
    } else if manifest_count == 1 && root_project.is_none() {
        (
            "single_project",
            "Root contains one project in a subdirectory.".to_string(),
        )
    } else if manifest_count == 0 && supported.len() == 1 && root_source_project.is_some() {
        (
            "single_project",
            "Root contains one source-only project without a manifest.".to_string(),
        )
    } else if manifest_count == 0 && supported.len() >= 2 {
        ("unsupported_or_mixed_workspace",
         format!("Root has {} source-only entries and no detected manifests. Some may be internal source directories rather than analyzable project roots.", supported.len()))
    } else {
        (
            "unknown",
            format!(
                "Found {} supported entries, {} with manifests. Cannot confidently classify root.",
                supported.len(),
                manifest_count
            ),
        )
    };

    // 收集推荐的项目 roots
    let mut recommended_candidates: Vec<&ProjectInfo> = supported_manifest_projects
        .iter()
        .copied()
        .filter(|p| p.relative_path != "." || kind == "single_project")
        .collect();
    if recommended_candidates.is_empty() && kind == "single_project" {
        if let Some(p) = root_source_project {
            recommended_candidates.push(*p);
        }
    }
    let recommended_project_roots = ranked_project_roots_json(recommended_candidates, 12);

    let detected_projects: Vec<_> = inventory
        .iter()
        .filter(|p| !p.manifest_file.is_empty() || !p.supported || p.relative_path == ".")
        .map(|p| {
            json!({
                "path": p.path,
                "relativePath": p.relative_path,
                "name": p.name,
                "language": p.language,
                "manifestFile": p.manifest_file,
                "supported": p.supported
            })
        })
        .collect();

    // 根据 root 类型推荐合适的工具
    let recommended_tool = match kind {
        "single_project" => json!("codelattice_project"),
        "workspace" => json!("codelattice_workspace"),
        _ => Value::Null,
    };

    let mut cautions: Vec<Value> = Vec::new();
    if kind == "workspace" || kind == "unsupported_or_mixed_workspace" {
        cautions.push(json!("Do not pass workspace root to codelattice_symbol or codelattice_project — use a specific project root from recommendedProjectRoots."));
        cautions.push(json!(
            "Use codelattice_workspace for cross-project analysis and graph overview."
        ));
    }
    if !unsupported.is_empty() {
        cautions.push(json!(format!(
            "{} unsupported entries detected. These will not be analyzed.",
            unsupported.len()
        )));
    }

    let mut diagnosis = json!({
        "kind": kind,
        "inputRoot": root,
        "canonicalRoot": path.to_string_lossy(),
        "recommendedTool": recommended_tool,
        "recommendedProjectRoots": recommended_project_roots,
        "detectedProjects": detected_projects,
        "counts": {
            "manifestBackedSupportedProjects": manifest_count,
            "sourceOnlySupportedEntries": source_only_count,
            "unsupportedEntries": unsupported.len()
        },
        "sourceOnlySummary": source_only_summary,
        "cautions": cautions,
        "explanation": explanation
    });

    if let Some(obj) = diagnosis.as_object_mut() {
        if source_only_limit == 0 {
            obj.insert(
                "sourceOnlyEntryPreview".to_string(),
                json!(source_only_preview),
            );
            obj.insert(
                "sourceOnlyDetailHint".to_string(),
                json!("Re-run with compact=false to include full sourceOnlyEntries."),
            );
        } else {
            obj.insert("sourceOnlyEntries".to_string(), json!(source_only_entries));
        }
    }

    diagnosis
}

/// 构建 analysisSemantics 对象，明确说明分析已执行但目标代码未运行
fn build_analysis_semantics() -> Value {
    json!({
        "staticAnalysisExecuted": true,
        "targetCodeExecuted": false,
        "targetScriptsExecuted": false,
        "runtimeProof": false,
        "coverageProof": false,
        "explanation": "CodeLattice executed static parsing and graph analysis only. It did NOT run or execute the target project's code, build scripts, or package manager. runtimeExecuted=false means the target project was NOT run — it does NOT mean CodeLattice failed to analyze."
    })
}

/// 构建 cacheSemantics 对象，防止 AI 误判 persistent cache disabled 为 CodeLattice 不可用
fn build_cache_semantics(has_persistent: bool) -> Value {
    json!({
        "memoryCacheAvailable": true,
        "persistentCacheAvailable": has_persistent,
        "analysisAvailableWithoutPersistentCache": true,
        "explanation": "Persistent cache is an optional performance layer. Disabled persistent cache does NOT prevent fresh static analysis — CodeLattice will still run analysis and cache results in memory for the current session.",
        "note": "Persistent cache defaults to ~/.cache/codelattice. Override with CODELATTICE_CACHE_DIR. Disable with CODELATTICE_CACHE=off."
    })
}

/// Compact 模式下将 schedule 对象替换为 scheduleSummary。
/// 递归处理 value 中所有名为 "schedule" 的字段（包括嵌套在 result / cacheMeta 下）。
fn compact_strip_schedule(value: &mut Value) {
    // 如果 value 是对象，查找 "schedule" key 并替换
    if let Some(obj) = value.as_object_mut() {
        if let Some(schedule) = obj.remove("schedule") {
            // 构建 scheduleSummary
            let summary = build_schedule_summary(&schedule);
            obj.insert("scheduleSummary".to_string(), summary);
        }
        // 递归处理所有子值
        for (_k, v) in obj.iter_mut() {
            compact_strip_schedule(v);
        }
    } else if let Some(arr) = value.as_array_mut() {
        for item in arr.iter_mut() {
            compact_strip_schedule(item);
        }
    }
}

/// 从完整 schedule 对象提取摘要信息，省略 phases/fileSnapshot/snapshots
fn build_schedule_summary(schedule: &Value) -> Value {
    json!({
        "action": schedule["action"].as_str().unwrap_or("unknown"),
        "cacheIntent": schedule["cacheIntent"].as_str().unwrap_or("unknown"),
        "reason": schedule["reason"].as_str().unwrap_or(""),
        "phaseCount": schedule["phases"].as_array().map(|a| a.len()).unwrap_or(0),
        "dirtyFileCount": schedule["dirtyFileCount"].as_u64()
            .or_else(|| schedule["fileSnapshot"].as_array().map(|a| a.len() as u64))
            .unwrap_or(0),
        "fingerprintShort": schedule["fingerprint"].as_str()
            .map(|fp| if fp.len() > 12 { &fp[..12] } else { fp })
            .unwrap_or("n/a"),
    })
}

/// 将子工具结果包装为统一 facade 输出
/// rootDiagnosis: 如果提供，直接使用；否则如果 root 非空且非 "n/a"，自动计算
fn wrap_facade_output(
    inner: Value,
    tool: &str,
    mode: &str,
    language: &str,
    root: &str,
    summary: Value,
    next_actions: Vec<&str>,
    underlying: Vec<&str>,
    compact: bool,
) -> Value {
    // 自动计算 root diagnosis（如果 root 有效）
    let root_diagnosis = if root.is_empty() || root == "n/a" {
        json!({"kind": "not_applicable", "explanation": "No root path provided."})
    } else if compact {
        diagnose_root_compact(root, language)
    } else {
        diagnose_root(root, language)
    };

    let mut out = json!({
        "schemaVersion": "facade.v1",
        "tool": tool,
        "mode": mode,
        "language": language,
        "root": root,
        "rootDiagnosis": root_diagnosis,
        "analysisSemantics": build_analysis_semantics(),
        "decisionGuidance": decision_guidance(tool, mode, &root_diagnosis, compact),
        "summary": summary,
        "result": inner,
        "nextActions": next_actions,
        "cautions": [
            "static analysis only — no runtime proof",
            "scripts executed: false",
            "coverage verified: false",
            "do not treat as production readiness signal"
        ],
        "generatedFrom": {
            "staticAnalysis": true,
            "runtimeVerified": false,
            "scriptsExecuted": false,
            "coverageVerified": false
        },
        "compact": compact,
        "underlyingTools": underlying
    });
    if compact {
        if let Some(obj) = out.as_object_mut() {
            // Keep result in compact mode (handlers produce bounded output)
            obj.insert(
                "detailHint".to_string(),
                json!("Re-run with compact=false or a deeper mode when you need full result payloads."),
            );
            obj.insert("compactSemantics".to_string(), compact_semantics(true));

            // ── Compact 去重：减少跨调用重复字段 ──

            // 1. 递归处理所有 schedule 字段（包括 result 内部）
            //    将完整 schedule 替换为 scheduleSummary
            if let Some(result) = obj.get_mut("result") {
                compact_strip_schedule(result);
            }

            // 2. rootDiagnosis 摘要化：保留关键字段，省略 sourceOnlyEntries 全量列表
            if let Some(rd) = obj.get_mut("rootDiagnosis") {
                if let Some(rd_obj) = rd.as_object_mut() {
                    // sourceOnlyEntries 只保留前 3 条 preview
                    if let Some(entries) = rd_obj.get_mut("sourceOnlyEntries") {
                        if let Some(arr) = entries.as_array_mut() {
                            if arr.len() > 3 {
                                let preview: Vec<Value> = arr.drain(..3).collect();
                                *arr = preview;
                                rd_obj
                                    .insert("sourceOnlyEntriesTruncated".to_string(), json!(true));
                            }
                        }
                    }
                    // schedule 替换为 scheduleSummary
                    if let Some(schedule) = rd_obj.remove("schedule") {
                        rd_obj.insert(
                            "scheduleSummary".to_string(),
                            build_schedule_summary(&schedule),
                        );
                    }
                }
            }

            // 2. analysisSemantics 用 ref 替代完整展开
            obj.insert(
                "analysisSemantics".to_string(),
                json!({"$ref": "facade.v1.analysisSemantics.default"}),
            );

            // 3. generatedFrom 与 cautions 用 ref
            obj.insert(
                "generatedFrom".to_string(),
                json!({"$ref": "facade.v1.generatedFrom.default"}),
            );
            if let Some(cautions) = obj.get_mut("cautions") {
                if let Some(arr) = cautions.as_array_mut() {
                    if arr.len() > 2 {
                        arr.truncate(2);
                    }
                }
            }

            // 4. contextRefs：首次调用返回完整，后续调用 AI 可用 ref 跳过
            obj.insert(
                "contextRefs".to_string(),
                json!({
                    "schemaVersion": "facade.v1",
                    "refs": [
                        "analysisSemantics",
                        "generatedFrom",
                        "cautions"
                    ],
                    "explanation": "These fields use $ref in compact mode. Non-compact mode returns full values. AI can skip $ref fields on subsequent calls."
                }),
            );
        }
    }
    if let Some(obj) = out.as_object_mut() {
        obj.insert(
            "runtimeCapabilities".to_string(),
            facade_language_runtime_capabilities(language),
        );
        if compact {
            obj.insert(
                "omitted".to_string(),
                json!([
                    {
                        "field": "rootDiagnosis.sourceOnlyEntries",
                        "reason": "compact mode keeps only sourceOnlyEntryPreview/sourceOnlySummary"
                    },
                    {
                        "field": "schedule.phases",
                        "reason": "compact mode replaces full schedules with scheduleSummary"
                    },
                    {
                        "field": "analysisSemantics/generatedFrom",
                        "reason": "compact mode uses contextRefs for repeated static-analysis semantics"
                    }
                ]),
            );
        }
    }
    let request_context =
        FacadeRequestContext::unrouted(tool, mode, root, language, language, compact);
    attach_facade_contract(&mut out, &request_context);
    if compact {
        let estimated_bytes = serde_json::to_string(&out).map(|s| s.len()).unwrap_or(0);
        if let Some(obj) = out.as_object_mut() {
            obj.insert(
                "tokenBudget".to_string(),
                json!({
                    "used": estimated_bytes,
                    "max": 16 * 1024,
                    "estimated": true,
                    "policy": "compact facade responses should stay below the 16KB AI decision budget"
                }),
            );
        }
    }
    out
}

fn take_json_items(value: &Value, limit: usize) -> Vec<Value> {
    value
        .as_array()
        .map(|items| items.iter().take(limit).cloned().collect())
        .unwrap_or_default()
}

fn project_depth_limit(depth: &str) -> usize {
    match depth {
        "quick" => 5,
        "standard" => 10,
        "deep" => 25,
        _ => 5,
    }
}

fn project_depth_next_actions(depth: &str) -> Vec<&'static str> {
    match depth {
        "quick" => vec![
            "Read summary.aiDigest.readFirst before opening random files.",
            "Use codelattice_project mode=standard if you need component risk detail.",
            "Use codelattice_workflow mode=diagnose_issue when you have a concrete symptom.",
        ],
        "standard" => vec![
            "Use summary.aiDigest.reviewFirst before editing risky components.",
            "Use codelattice_symbol mode=search/context to drill into a named area.",
            "Use codelattice_project mode=deep only when you need full static detail.",
        ],
        "deep" => vec![
            "Use result sections as detailed static evidence, not runtime proof.",
            "Use codelattice_change_review before changing high-risk symbols.",
            "Confirm with targeted tests outside CodeLattice.",
        ],
        _ => vec!["Use codelattice_project mode=quick for orientation."],
    }
}

fn compact_digest_component_item(item: &Value) -> Value {
    json!({
        "component": item["component"],
        "role": item["role"],
        "fileCount": item["fileCount"],
        "symbolCount": item["symbolCount"],
        "edgeCount": item["edgeCount"],
        "riskLevel": item["riskLevel"],
        "riskScore": item["riskScore"],
        "priorityRank": item["priorityRank"],
        "relativePriority": item["relativePriority"],
        "riskDrivers": item["riskDrivers"],
        "readFirstFiles": item["readFirstFiles"],
        "recommendedAction": item["recommendedAction"],
    })
}

fn compact_digest_risk_item(item: &Value) -> Value {
    let priority_band = item["riskCalibration"]["calibratedPriorityBand"]
        .as_str()
        .or_else(|| item["relativePriority"].as_str())
        .unwrap_or("unknown");
    let risk_note = item["whyTopRisk"]
        .as_str()
        .or_else(|| item["whySuspicious"].as_str())
        .unwrap_or("Static risk hint; not runtime proof.");
    json!({
        "id": item["id"],
        "name": item["name"],
        "kind": item["kind"],
        "file": item["file"],
        "line": item["line"],
        "riskLevel": item["riskLevel"],
        "riskScore": item["riskScore"],
        "rawRiskScore": item["rawRiskScore"],
        "priorityRank": item["priorityRank"],
        "priorityBand": priority_band,
        "relativePriority": item["relativePriority"],
        "riskDrivers": item["riskDrivers"],
        "riskNote": risk_note,
        "recommendedAction": item["recommendedAction"],
        "staticOnly": true,
    })
}

fn build_project_ai_digest(insights: &Value, depth: &str, limit: usize) -> Value {
    let components: Vec<Value> =
        take_json_items(&insights["architectureMap"]["components"], limit.min(6))
            .iter()
            .map(compact_digest_component_item)
            .collect();
    let read_first = take_json_items(&insights["readFirst"], limit.min(6));
    let review_first = take_json_items(&insights["reviewFirst"], limit.min(6));
    let entry_points = take_json_items(&insights["entryPointCandidates"], limit.min(6));
    let suspicious: Vec<Value> = take_json_items(&insights["suspiciousAreas"], limit.min(6))
        .iter()
        .map(compact_digest_risk_item)
        .collect();
    let missing = take_json_items(&insights["missingEvidence"], 3);

    json!({
        "purpose": match depth {
            "quick" => "Fast orientation for an AI agent entering an unfamiliar project.",
            "standard" => "Balanced project map with risk and component guidance.",
            "deep" => "Detailed static exploration; use after quick/standard or before risky edits.",
            _ => "Progressive project exploration."
        },
        "readFirst": read_first,
        "reviewFirst": review_first,
        "entryPoints": entry_points,
        "topComponents": components,
        "topRisks": suspicious,
        "missingEvidence": missing,
        "drillDownOptions": [
            {"mode": "quick", "when": "first contact or after switching projects"},
            {"mode": "standard", "when": "you need module boundaries and risk review"},
            {"mode": "deep", "when": "you need full static detail before a high-risk edit"},
            {"workflow": "diagnose_issue", "when": "you have a symptom, error text, or suspicious file"},
            {"workflow": "before_edit", "when": "you have chosen a concrete symbol to modify"}
        ]
    })
}

fn build_project_progressive_summary(insights: &Value, depth: &str, root: &str) -> Value {
    let summary = &insights["summary"];
    let limit = project_depth_limit(depth);
    let ai_digest = if insights["aiDigest"].is_object() {
        insights["aiDigest"].clone()
    } else {
        build_project_ai_digest(insights, depth, limit)
    };
    json!({
        "riskLevel": summary["architectureRiskLevel"].as_str().unwrap_or("unknown"),
        "mode": depth,
        "analysisDepth": depth,
        "modeSemantics": mode_semantics("codelattice_project", depth),
        "root": root,
        "language": summary["language"].clone(),
        "sourceFileCount": summary["sourceFileCount"].clone(),
        "symbolCount": summary["symbolCount"].clone(),
        "edgeCount": summary["edgeCount"].clone(),
        "architectureRiskScore": summary["architectureRiskScore"].clone(),
        "architectureComponentCount": summary["architectureComponentCount"].clone(),
        "entryPointCandidateCount": summary["entryPointCandidateCount"].clone(),
        "aiDigest": ai_digest,
    })
}

/// 验证 facade mode 参数
fn validate_facade_mode(mode: &str, valid: &[&str], tool: &str) -> Result<(), Value> {
    if valid.contains(&mode) {
        Ok(())
    } else {
        Err(mcp_error(
            "invalid_mode",
            &format!(
                "Unknown mode '{mode}' for {tool}. Valid: {}",
                valid.join(", ")
            ),
        ))
    }
}

/// multi-tool mode 安全调用：失败收错，不中止。
/// 结果按 key 写入，避免部分子工具失败时 Vec 顺序错位导致字段误标。
fn safe_insert_tool<F>(merged: &mut Value, errors: &mut Vec<String>, key: &str, name: &str, f: F)
where
    F: FnOnce() -> Result<Value, Value>,
{
    match f() {
        Ok(v) => {
            if let Some(obj) = merged.as_object_mut() {
                obj.insert(key.to_string(), v);
            }
        }
        Err(e) => errors.push(format!("{name}: {e}")),
    }
}

#[derive(Clone, Debug)]
struct DiagnoseCandidate {
    id: String,
    name: String,
    kind: String,
    file: String,
    line: u64,
    score: f64,
    confidence: f64,
    reasons: Vec<String>,
    next_action: String,
    fan_in: usize,
    fan_out: usize,
    entry_kind: String,
    is_test_entry: bool,
}

fn diagnose_candidate_json(candidate: &DiagnoseCandidate, idx: usize) -> Value {
    json!({
        "rank": idx + 1,
        "id": candidate.id,
        "name": candidate.name,
        "kind": candidate.kind,
        "file": candidate.file,
        "line": candidate.line,
        "score": (candidate.score * 10.0).round() / 10.0,
        "confidence": (candidate.confidence * 100.0).round() / 100.0,
        "reason": candidate.reasons.join("; "),
        "reasons": candidate.reasons,
        "nextAction": candidate.next_action,
        "fanIn": candidate.fan_in,
        "fanOut": candidate.fan_out,
        "entryKind": candidate.entry_kind,
        "isTestEntry": candidate.is_test_entry,
        "staticOnly": true
    })
}

fn diagnose_file_read_item(file: &str, reason: &str, priority: usize) -> Value {
    json!({
        "kind": "file",
        "file": file,
        "priority": priority,
        "reason": reason,
        "nextAction": "Read this file before editing; confirm with targeted tests or runtime evidence outside CodeLattice."
    })
}

fn build_project_diagnose(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    let validated = validate_root_path(root)?;
    let language = params["language"].as_str().unwrap_or("auto");
    let limit = params["limit"].as_u64().unwrap_or(10).clamp(1, 50) as usize;
    check_language_feature(language)?;

    let input_text = diagnose_input_text(params);
    let mut terms = diagnose_terms_from_text(&input_text);
    let changed_path = params["changedPath"]
        .as_str()
        .unwrap_or("")
        .replace('\\', "/");
    if !changed_path.is_empty() {
        for term in diagnose_terms_from_text(&changed_path.replace(['/', '.', '-'], " ")) {
            if !terms.contains(&term) {
                terms.push(term);
            }
        }
    }

    let (gv, _result, cache_meta) = cache.get_or_analyze(&validated, language, false)?;
    let mut candidates: Vec<DiagnoseCandidate> = Vec::new();
    let mut file_scores: HashMap<String, (f64, Vec<String>)> = HashMap::new();

    for (id, node) in &gv.nodes_by_id {
        let node_kind = node_symbol_kind(node);
        let is_symbol = node["label"].as_str() == Some("symbol")
            || node["kind"].as_str() == Some("symbol")
            || node["properties"]["symbolKind"].as_str().is_some();
        if !is_symbol {
            continue;
        }

        let name = node_display_name(node);
        let file = node_source_path(node);
        let file_lower = file.to_lowercase().replace('\\', "/");
        let name_lower = name.to_lowercase();
        let id_lower = id.to_lowercase();
        let fan_out = gv.edges_from(id, Some("CALLS")).len();
        let fan_in = gv.edges_to(id, Some("CALLS")).len();
        let entry_signal =
            classify_entry_signal(&name, &node_kind, &file, &gv.language, fan_out, fan_in);

        let mut score: f64 = 0.0;
        let mut reasons: Vec<String> = Vec::new();

        for term in &terms {
            if name_lower.contains(term) {
                score += 6.0;
                reasons.push(format!("symbol name matches '{term}'"));
            }
            if file_lower.contains(term) {
                score += 3.0;
                reasons.push(format!("file path matches '{term}'"));
            }
            if id_lower.contains(term) {
                score += 1.5;
            }
        }

        if !changed_path.is_empty() {
            let changed_lower = changed_path.to_lowercase();
            if file_lower.contains(&changed_lower) || changed_lower.contains(&file_lower) {
                score += 8.0;
                reasons.push("changedPath points at this file".to_string());
            }
        }

        if entry_signal.primary_candidate {
            score += 1.5 + entry_signal.confidence;
            reasons.push(format!(
                "architecture entry signal: {}",
                entry_signal.category
            ));
        }
        if fan_in > 0 {
            score += (fan_in as f64).min(8.0) * 0.35;
        }
        if fan_out > 0 {
            score += (fan_out as f64).min(8.0) * 0.25;
        }
        let diag_count = gv.diagnostics_for(id).len();
        if diag_count > 0 {
            score += diag_count as f64;
            reasons.push(format!("{diag_count} diagnostic(s) nearby"));
        }

        if score <= 0.0 {
            continue;
        }
        if is_test_symbol(&name, &file) {
            score *= 0.35;
            reasons.push("test-like symbol downweighted".to_string());
        }

        if !file.is_empty() {
            let entry = file_scores.entry(file.clone()).or_insert((0.0, Vec::new()));
            entry.0 += score;
            entry.1.extend(reasons.iter().take(3).cloned());
        }

        let confidence = (score / 12.0).min(0.95).max(0.20);
        let next_action = if fan_in > 0 || fan_out > 0 {
            "Inspect callers/callees and confirm with targeted tests; this is a static hypothesis."
        } else {
            "Read this symbol and nearby file context; static graph has limited impact evidence here."
        }
        .to_string();

        candidates.push(DiagnoseCandidate {
            id: id.clone(),
            name,
            kind: node_kind,
            file,
            line: node_line_start(node),
            score,
            confidence,
            reasons,
            next_action,
            fan_in,
            fan_out,
            entry_kind: entry_signal.category,
            is_test_entry: entry_signal.is_test_entry,
        });
    }

    candidates.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.file.cmp(&b.file))
            .then_with(|| a.name.cmp(&b.name))
    });
    candidates.truncate(limit);

    let likely_areas: Vec<Value> = candidates
        .iter()
        .enumerate()
        .map(|(i, c)| diagnose_candidate_json(c, i))
        .collect();

    let mut read_first: Vec<Value> = Vec::new();
    let mut seen_files: Vec<String> = Vec::new();
    for candidate in &candidates {
        if candidate.file.is_empty() || seen_files.contains(&candidate.file) {
            continue;
        }
        seen_files.push(candidate.file.clone());
        read_first.push(diagnose_file_read_item(
            &candidate.file,
            &format!(
                "contains likely symbol '{}': {}",
                candidate.name,
                candidate.reasons.join("; ")
            ),
            read_first.len() + 1,
        ));
        if read_first.len() >= limit.min(8) {
            break;
        }
    }

    let mut file_rank: Vec<(String, f64, Vec<String>)> = file_scores
        .into_iter()
        .map(|(file, (score, reasons))| {
            let mut deduped = Vec::new();
            for r in reasons {
                if !deduped.contains(&r) {
                    deduped.push(r);
                }
            }
            (file, score, deduped)
        })
        .collect();
    file_rank.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
    for (file, _score, reasons) in file_rank.iter().take(limit) {
        if seen_files.contains(file) {
            continue;
        }
        read_first.push(diagnose_file_read_item(
            file,
            &format!("file-level symptom match: {}", reasons.join("; ")),
            read_first.len() + 1,
        ));
        seen_files.push(file.clone());
    }

    let mut entry_points: Vec<Value> = gv
        .nodes_by_id
        .iter()
        .filter_map(|(id, node)| {
            let name = node_display_name(node);
            let kind = node_symbol_kind(node);
            let file = node_source_path(node);
            let fan_out = gv.edges_from(id, Some("CALLS")).len();
            let fan_in = gv.edges_to(id, Some("CALLS")).len();
            let signal = classify_entry_signal(&name, &kind, &file, &gv.language, fan_out, fan_in);
            if !signal.primary_candidate {
                return None;
            }
            Some(json!({
                "id": id,
                "name": name,
                "kind": kind,
                "file": file,
                "line": node_line_start(node),
                "entryKind": signal.category,
                "confidence": signal.confidence,
                "evidence": signal.evidence,
                "nextAction": signal.next_action,
                "fanIn": fan_in,
                "fanOut": fan_out
            }))
        })
        .collect();
    entry_points.sort_by(|a, b| {
        b["confidence"]
            .as_f64()
            .unwrap_or(0.0)
            .partial_cmp(&a["confidence"].as_f64().unwrap_or(0.0))
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    entry_points.truncate(limit.min(8));

    let mut impact_hints: Vec<Value> = Vec::new();
    for candidate in candidates.iter().take(5) {
        for edge in gv
            .edges_to(&candidate.id, Some("CALLS"))
            .iter()
            .take(3)
            .chain(gv.edges_from(&candidate.id, Some("CALLS")).iter().take(3))
        {
            let source = edge_source_id(edge).unwrap_or("");
            let target = edge_target_id(edge).unwrap_or("");
            let other_id = if source == candidate.id {
                target
            } else {
                source
            };
            let other = gv.nodes_by_id.get(other_id);
            impact_hints.push(json!({
                "target": candidate.name,
                "direction": if source == candidate.id { "outgoing" } else { "incoming" },
                "edgeKind": edge_type_name(edge),
                "relatedSymbol": other.map(node_display_name).unwrap_or_else(|| other_id.to_string()),
                "relatedFile": other.map(node_source_path).unwrap_or_default(),
                "confidence": edge["properties"]["confidence"].as_f64().unwrap_or(1.0),
                "reason": edge["properties"]["reason"].as_str().unwrap_or("static graph edge")
            }));
        }
    }
    impact_hints.truncate(limit);

    let top_confidence = candidates.first().map(|c| c.confidence).unwrap_or(0.0);
    let risk_level = if candidates.is_empty() {
        "unknown"
    } else if top_confidence >= 0.75 {
        "medium"
    } else {
        "low"
    };
    let answer_summary = if candidates.is_empty() {
        "No strong static match found. Use broader query terms, project_insights, or targeted source search."
            .to_string()
    } else {
        format!(
            "Static diagnosis found {} likely area(s); start with {}.",
            candidates.len(),
            candidates
                .first()
                .map(|c| c.name.as_str())
                .unwrap_or("the first likely area")
        )
    };

    let mut result = json!({
        "schemaVersion": "codelattice.projectDiagnose.v1",
        "summary": {
            "riskLevel": risk_level,
            "likelyAreaCount": likely_areas.len(),
            "readFirstCount": read_first.len(),
            "impactHintCount": impact_hints.len(),
            "topConfidence": (top_confidence * 100.0).round() / 100.0
        },
        "inputSignals": {
            "symptom": params["symptom"].as_str().unwrap_or(""),
            "errorText": params["errorText"].as_str().unwrap_or(""),
            "query": params["query"].as_str().unwrap_or(""),
            "changedPath": params["changedPath"].as_str().unwrap_or(""),
            "terms": terms
        },
        "likelyAreas": likely_areas,
        "readFirst": read_first,
        "entryPoints": entry_points,
        "impactHints": impact_hints,
        "answerSummary": answer_summary,
        "recommendedNextActions": [
            "Read readFirst in order before editing.",
            "Use codelattice_symbol mode=context/callers/callees for the top likelyArea.",
            "Use codelattice_change_review mode=impact before modifying a likelyArea.",
            "Confirm hypotheses with targeted tests or runtime reproduction outside CodeLattice."
        ],
        "cautions": [
            "static diagnosis only — not root-cause proof",
            "target project code was not executed",
            "missing graph edges can hide runtime/framework behavior"
        ],
        "generatedFrom": {
            "graphBased": true,
            "staticAnalysis": true,
            "runtimeVerified": false,
            "scriptsExecuted": false
        }
    });
    result = merge_cache_and_result(&result, &cache_meta);
    Ok(result)
}

// ── codelattice_project ──────────────────────────────────────────────

// ═══ Analysis Engine 1.3 Job Runtime helpers ═══

// ═══ Generic job runtime dispatch for all facades ═══

fn attach_facade_job_contract(
    mut response: Value,
    facade: &str,
    mode: &str,
    requested_root: &str,
    requested_language: &str,
    compact: bool,
) -> Value {
    let job_id = response["jobId"].as_str().unwrap_or("");
    let job_handle = if job_id.is_empty() {
        None
    } else {
        crate::mcp_job::MCP_JOBS.get(job_id)
    };
    let effective_root = response["root"]
        .as_str()
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .or_else(|| job_handle.as_ref().map(|job| job.root.clone()))
        .unwrap_or_else(|| requested_root.to_string());
    let effective_language = response["language"]
        .as_str()
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .or_else(|| job_handle.as_ref().map(|job| job.language.clone()))
        .unwrap_or_else(|| requested_language.to_string());
    let original_root = if requested_root.is_empty() {
        effective_root.as_str()
    } else {
        requested_root
    };
    let root_router = json!({
        "schemaVersion": "codelattice.rootRouter.v1",
        "routed": false,
        "tool": facade,
        "mode": mode,
        "originalRoot": original_root,
        "selectedRoot": effective_root.clone(),
        "selectedLanguage": effective_language.clone(),
        "confidence": "n/a",
        "reason": "job control-plane response uses the submitted job root/language"
    });
    let context = FacadeRequestContext::new(
        facade,
        mode,
        original_root,
        &effective_root,
        requested_language,
        &effective_language,
        compact,
        root_router,
    );
    attach_facade_contract(&mut response, &context);
    response
}

fn handle_facade_job(
    root: &str,
    language: &str,
    mode: &str,
    facade: &str,
    params: &Value,
    compact: bool,
) -> Result<Value, Value> {
    match mode {
        "job_cancel" => {
            let job_id = params["jobId"]
                .as_str()
                .ok_or_else(|| mcp_error("missing_parameter", "jobId required"))?;
            let response = attach_facade_job_contract(
                crate::mcp_job::MCP_JOBS.cancel_job(job_id),
                facade,
                mode,
                root,
                language,
                compact,
            );
            Ok(tool_result(&response))
        }
        "job" => {
            let parallel = params["parallel"].as_bool().unwrap_or(false);
            let wait = params["wait"].as_bool().unwrap_or(false);
            let timeout_ms = params["timeoutMs"].as_u64().unwrap_or(0);
            let engine_mode = if parallel { "parallel" } else { "serial" };
            let result = if facade == "codelattice_workspace" {
                crate::mcp_job::submit_workspace_job(root, engine_mode)
            } else {
                if let Some(error) = workspace_root_selection_error(root, language, facade, "job") {
                    return Ok(tool_result(&error));
                }
                let validated_root = validate_root_path(root)?;
                let language_owned = resolve_auto_language_for_root(&validated_root, language)?;
                crate::mcp_job::submit_project_job(root, &language_owned, engine_mode)
            };
            match result {
                Ok(job_resp) => {
                    // 如果 wait=true，短轮询直到完成或超时
                    if wait {
                        let job_id = job_resp["jobId"].as_str().unwrap_or("");
                        if !job_id.is_empty() {
                            let effective_timeout = if timeout_ms > 0 { timeout_ms } else { 10000 };
                            let (final_status, timed_out) =
                                crate::mcp_job::MCP_JOBS.wait_for_job(job_id, effective_timeout);
                            return match final_status {
                                Some(status) => {
                                    let mut response = status;
                                    if timed_out {
                                        if let Some(obj) = response.as_object_mut() {
                                            obj.insert("waitTimedOut".to_string(), json!(true));
                                            obj.insert("retryAfterMs".to_string(), json!(2000));
                                            obj.insert(
                                                "message".to_string(),
                                                json!(format!(
                                                    "Job {} still running after {}ms. Poll job_status to check completion.",
                                                    job_id, effective_timeout
                                                )),
                                            );
                                        }
                                    }
                                    let response = attach_facade_job_contract(
                                        response, facade, mode, root, language, compact,
                                    );
                                    Ok(tool_result(&response))
                                }
                                None => {
                                    let response = attach_facade_job_contract(
                                        job_resp, facade, mode, root, language, compact,
                                    );
                                    Ok(tool_result(&response))
                                }
                            };
                        }
                    }
                    let response =
                        attach_facade_job_contract(job_resp, facade, mode, root, language, compact);
                    Ok(tool_result(&response))
                }
                Err(e) => Err(mcp_error("job_failed", &e)),
            }
        }
        "job_status" => {
            let job_id = params["jobId"]
                .as_str()
                .ok_or_else(|| mcp_error("missing_parameter", "jobId required"))?;
            match crate::mcp_job::MCP_JOBS.get(job_id) {
                Some(handle) => {
                    let response = attach_facade_job_contract(
                        crate::mcp_job::MCP_JOBS.to_response(&handle),
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
                None => {
                    let response = attach_facade_job_contract(
                        json!({"error": "job_not_found", "jobId": job_id, "facade": facade}),
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
            }
        }
        "job_detail" => {
            let job_id = params["jobId"]
                .as_str()
                .ok_or_else(|| mcp_error("missing_parameter", "jobId required"))?;
            let page = params["page"].as_u64().unwrap_or(0) as usize;
            let page_size = params["pageSize"].as_u64().unwrap_or(50).clamp(1, 200) as usize;
            if crate::mcp_job::MCP_JOBS.get(job_id).is_none() {
                let response = attach_facade_job_contract(
                    json!({"error": "job_not_found", "jobId": job_id, "facade": facade}),
                    facade,
                    mode,
                    root,
                    language,
                    compact,
                );
                return Ok(tool_result(&response));
            }
            match crate::mcp_job::MCP_JOBS.get_detail_page(job_id, page, page_size) {
                Some(page_result) => {
                    let response = attach_facade_job_contract(
                        page_result,
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
                None => {
                    let response = attach_facade_job_contract(
                        json!({"error": "job_detail_unavailable", "jobId": job_id, "facade": facade}),
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
            }
        }
        _ => Err(mcp_error(
            "invalid_mode",
            &format!("Unknown job mode: {}", mode),
        )),
    }
}

/// Facade 自动 job 化决策：
/// cache hit → 调用者同步返回；cache miss/stale + asyncOnMiss → 自动提交异步 job。
/// 返回 None 表示 cache hit，调用者应继续同步执行。
/// 返回 Some(Value) 表示已提交异步 job 或应返回 backpressure。
fn facade_auto_job_check(
    cache: &McpCache,
    root: &str,
    requested_language: &str,
    language: &str,
    tool_name: &str,
    mode: &str,
    params: &Value,
) -> Option<Value> {
    let async_on_miss = params["asyncOnMiss"].as_bool().unwrap_or(true);
    let force_sync = params["forceSync"].as_bool().unwrap_or(false);
    let compact = params["compact"].as_bool().unwrap_or(false);
    let with_contract = |mut response: Value| {
        let context = FacadeRequestContext::unrouted(
            tool_name,
            mode,
            root,
            requested_language,
            language,
            compact,
        );
        attach_facade_contract(&mut response, &context);
        response
    };

    if force_sync || !async_on_miss {
        return None;
    }
    // compact 模式不再强制同步阻塞：
    // - 小项目 (≤10 文件) cache miss 仍可同步（由下面 small_project_threshold 控制）
    // - 大项目 cache miss 走 async job，返回 analyzing/jobId
    // - 大项目 cache hit 时 get_or_analyze 直接返回 top-N（无需走本函数）

    let probe = cache.probe_analysis_cache(Path::new(root), language, false);
    let probe_status = probe["status"].as_str().unwrap_or("miss");

    if probe_status == "hit" {
        return None;
    }

    // 检查是否有 running/succeeded 的同 root/language job（SingleFlight + 闭环）
    let running_jobs = crate::mcp_job::get_running_jobs_info();
    let matching_running = running_jobs
        .iter()
        .find(|j| j.root == root && (j.language == language || j.language == "auto"));
    if let Some(running) = matching_running {
        let estimate = crate::mcp_job::estimate_analysis_duration(0, language, probe_status);
        return Some(with_contract(json!({
            "status": "analyzing",
            "jobId": running.job_id,
            "cacheProbe": probe,
            "retryAfterSeconds": estimate["retryAfterSeconds"],
            "message": "A matching analysis job is already running. Poll job_status until succeeded, then retry.",
            "recommendedNextCalls": [
                {"tool": tool_name, "mode": "job_status", "arguments": {"jobId": running.job_id, "root": root, "language": language, "compact": true}},
                {"tool": tool_name, "mode": "job_detail", "arguments": {"jobId": running.job_id, "root": root, "language": language, "page": 0, "pageSize": 50, "compact": true}}
            ],
            "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false}
        })));
    }

    // 检查是否有 succeeded 的同 root/language job 且缓存已被预热
    // 如果 succeeded job 已把结果灌入 McpCache，上面 probe 应该 hit
    // 但 probe 仍 miss 可能是因为 canonicalize 差异，这里做二次确认
    if probe_status == "miss" {
        let succeeded_jobs = crate::mcp_job::MCP_JOBS.list_succeeded_jobs(root, language);
        if let Some(job) = succeeded_jobs.first() {
            // succeeded job 存在但缓存仍 miss，说明预热失败或缓存 key 不匹配。
            // 不自动走同步大分析；否则 AI 在 job 完成后重试 quick/search 会再次卡住。
            let warm_status = job
                .summary
                .as_ref()
                .and_then(|s| s["facadeCacheWarmStatus"].as_str())
                .unwrap_or("unknown");
            let warm_error = job
                .summary
                .as_ref()
                .and_then(|s| s["facadeCacheWarmError"].as_str())
                .unwrap_or("");
            return Some(with_contract(json!({
                "status": "analysis_ready_cache_unavailable",
                "jobId": job.job_id,
                "cacheProbe": probe,
                "facadeCacheReady": false,
                "facadeCacheWarmStatus": warm_status,
                "facadeCacheWarmError": warm_error,
                "message": "A matching background job succeeded, but the facade graph cache is not ready. CodeLattice will not run a synchronous large analysis automatically.",
                "recommendedNextCalls": [
                    {"tool": tool_name, "mode": "job_status", "arguments": {"jobId": job.job_id, "root": root, "language": language, "compact": true}},
                    {"tool": tool_name, "mode": "job_detail", "arguments": {"jobId": job.job_id, "page": 0, "pageSize": 50, "root": root, "language": language, "compact": true}},
                    {"tool": tool_name, "mode": mode, "arguments": {"root": root, "language": language, "compact": true, "asyncOnMiss": true}},
                    {"tool": tool_name, "mode": mode, "arguments": {"root": root, "language": language, "compact": true, "forceSync": true}, "why": "Only use forceSync when the user explicitly accepts a blocking full analysis."}
                ],
                "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false}
            })));
        }
    }

    let file_count = if let Some(adapter) = crate::engine_bridge::get_adapter_for_language(language)
    {
        adapter.discover_files(root).map(|f| f.len()).unwrap_or(0)
    } else {
        0
    };

    // 小项目允许同步跑，避免过度 job 化
    let small_project_threshold = 10usize;
    if file_count <= small_project_threshold && probe_status == "miss" {
        return None;
    }

    let estimate = crate::mcp_job::estimate_analysis_duration(file_count, language, probe_status);

    match crate::mcp_job::submit_project_job(root, language, "serial") {
        Ok(job_resp) => {
            let job_id = job_resp["jobId"].as_str().unwrap_or("").to_string();
            Some(with_contract(json!({
                "status": "analyzing",
                "jobId": job_id,
                "cacheProbe": probe,
                "estimatedSeconds": estimate["estimatedSeconds"],
                "retryAfterSeconds": estimate["retryAfterSeconds"],
                "estimatedClass": estimate["estimatedClass"],
                "message": "Analysis is running in background. Use job_status/job_detail; retry this facade after job succeeds.",
                "recommendedNextCalls": [
                    {"tool": tool_name, "mode": "job_status", "arguments": {"jobId": job_id, "root": root, "language": language, "compact": true}},
                    {"tool": tool_name, "mode": "job_detail", "arguments": {"jobId": job_id, "page": 0, "pageSize": 50, "root": root, "language": language, "compact": true}}
                ],
                "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false}
            })))
        }
        Err(e) => Some(with_contract(json!({
            "error": "auto_job_submit_failed",
            "message": e,
            "cacheProbe": probe,
        }))),
    }
}

fn handle_project_job(
    root: &str,
    language: &str,
    mode: &str,
    params: &Value,
    compact: bool,
) -> Result<Value, Value> {
    let facade = "codelattice_project";
    match mode {
        "job_cancel" => {
            let job_id = params["jobId"]
                .as_str()
                .ok_or_else(|| mcp_error("missing_parameter", "jobId required"))?;
            let response = attach_facade_job_contract(
                crate::mcp_job::MCP_JOBS.cancel_job(job_id),
                facade,
                mode,
                root,
                language,
                compact,
            );
            Ok(tool_result(&response))
        }
        "job" => {
            let parallel = params["parallel"].as_bool().unwrap_or(false);
            let wait = params["wait"].as_bool().unwrap_or(false);
            let timeout_ms = params["timeoutMs"].as_u64().unwrap_or(0);
            let engine_mode = if parallel { "parallel" } else { "serial" };
            let validated_root = validate_root_path(root)?;
            let language_owned = resolve_auto_language_for_root(&validated_root, language)?;
            let result = crate::mcp_job::submit_project_job(root, &language_owned, engine_mode)?;

            // 如果 wait=true，短轮询直到完成或超时
            if wait {
                let job_id = result["jobId"].as_str().unwrap_or("");
                if !job_id.is_empty() {
                    let effective_timeout = if timeout_ms > 0 { timeout_ms } else { 10000 };
                    let (final_status, timed_out) =
                        crate::mcp_job::MCP_JOBS.wait_for_job(job_id, effective_timeout);
                    return match final_status {
                        Some(status) => {
                            let mut response = status;
                            if timed_out {
                                if let Some(obj) = response.as_object_mut() {
                                    obj.insert("waitTimedOut".to_string(), json!(true));
                                    obj.insert("retryAfterMs".to_string(), json!(2000));
                                    obj.insert(
                                        "message".to_string(),
                                        json!(format!(
                                            "Job {} still running after {}ms. Poll job_status to check completion.",
                                            job_id, effective_timeout
                                        )),
                                    );
                                }
                            }
                            let response = attach_facade_job_contract(
                                response, facade, mode, root, language, compact,
                            );
                            Ok(tool_result(&response))
                        }
                        None => {
                            let response = attach_facade_job_contract(
                                result, facade, mode, root, language, compact,
                            );
                            Ok(tool_result(&response))
                        }
                    };
                }
            }
            let response =
                attach_facade_job_contract(result, facade, mode, root, language, compact);
            Ok(tool_result(&response))
        }
        "job_status" => {
            let job_id = params["jobId"].as_str().ok_or_else(|| {
                mcp_error("missing_parameter", "jobId required for job_status mode")
            })?;
            match crate::mcp_job::get_job_status(job_id) {
                Some(job) => {
                    let response =
                        attach_facade_job_contract(job, facade, mode, root, language, compact);
                    Ok(tool_result(&response))
                }
                None => {
                    let response = attach_facade_job_contract(
                        json!({"error": "job_not_found", "jobId": job_id, "facade": "codelattice_project"}),
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
            }
        }
        "job_detail" => {
            let job_id = params["jobId"].as_str().ok_or_else(|| {
                mcp_error("missing_parameter", "jobId required for job_detail mode")
            })?;
            let page = params["page"].as_u64().unwrap_or(0) as usize;
            let page_size = params["pageSize"].as_u64().unwrap_or(50).clamp(1, 200) as usize;
            if crate::mcp_job::MCP_JOBS.get(job_id).is_none() {
                let response = attach_facade_job_contract(
                    json!({"error": "job_not_found", "jobId": job_id, "facade": "codelattice_project"}),
                    facade,
                    mode,
                    root,
                    language,
                    compact,
                );
                return Ok(tool_result(&response));
            }
            match crate::mcp_job::MCP_JOBS.get_detail_page(job_id, page, page_size) {
                Some(page_result) => {
                    let response = attach_facade_job_contract(
                        page_result,
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
                None => {
                    let response = attach_facade_job_contract(
                        json!({"error": "job_detail_unavailable", "jobId": job_id, "facade": "codelattice_project"}),
                        facade,
                        mode,
                        root,
                        language,
                        compact,
                    );
                    Ok(tool_result(&response))
                }
            }
        }
        _ => Err(mcp_error(
            "invalid_mode",
            &format!("Unknown job mode: {}", mode),
        )),
    }
}

fn handle_project(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["mode"].as_str().unwrap_or("overview");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let requested_language = params["language"].as_str().unwrap_or("auto");
    validate_facade_mode(
        mode,
        &[
            "overview",
            "quick",
            "standard",
            "deep",
            "quality",
            "insights",
            "diagnose",
            "ai_context",
            "full",
            "job",
            "job_status",
            "job_detail",
            "job_cancel",
        ],
        "codelattice_project",
    )?;

    // ═══ Analysis Engine 1.3 job runtime modes ═══
    if matches!(mode, "job_status" | "job_detail" | "job_cancel") {
        return handle_project_job("", requested_language, mode, params, compact);
    }
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    if matches!(mode, "job" | "job_status" | "job_detail" | "job_cancel") {
        return handle_project_job(root, requested_language, mode, params, compact);
    }

    if requested_language == "auto" {
        if let Ok((validated, protected)) = validate_workspace_root_path(root) {
            if let Some(workspace) =
                build_workspace_auto_entry(&validated.to_string_lossy(), protected, compact)
            {
                return Ok(tool_result(&workspace));
            }
        }
    }

    let validated_root = validate_root_path(root)?;
    let language_owned = resolve_auto_language_for_root(&validated_root, requested_language)?;
    let language = language_owned.as_str();
    let mut effective_params = params.clone();
    effective_params["language"] = json!(language);
    let analysis_params = &effective_params;

    // 分析面 mode 的自动 job 化：cache miss/stale + 大项目 → 异步 job
    if matches!(
        mode,
        "quick" | "standard" | "deep" | "insights" | "diagnose" | "full" | "ai_context"
    ) {
        if let Some(auto_job_resp) = facade_auto_job_check(
            cache,
            root,
            requested_language,
            language,
            "codelattice_project",
            mode,
            analysis_params,
        ) {
            return Ok(tool_result(&auto_job_resp));
        }
    }

    let mut quick_freshness: Option<String> = None;

    let (inner, underlying): (Value, Vec<&str>) = match mode {
        "overview" => {
            let r = handle_project_overview(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_project_overview"])
        }
        "quick" | "standard" | "deep" => {
            let mut insight_params = analysis_params.clone();
            insight_params["mode"] = json!("onboarding");
            insight_params["compact"] = json!(true);
            insight_params["limit"] = json!(project_depth_limit(mode));
            if mode == "deep" {
                insight_params["compact"] = json!(false);
            }
            let r = handle_project_insights(cache, &insight_params)?;
            let insights = unwrap_tool_result(&r);
            if mode == "quick" {
                quick_freshness = insights["freshness"].as_str().map(String::from);
            }
            let progressive = json!({
                "schemaVersion": "codelattice.projectProgressiveMap.v1",
                "analysisDepth": mode,
                "summary": insights["summary"].clone(),
                "aiDigest": build_project_ai_digest(&insights, mode, project_depth_limit(mode)),
                "details": if mode == "deep" { insights.clone() } else { Value::Null },
                "generatedFrom": {
                    "staticAnalysis": true,
                    "runtimeVerified": false,
                    "scriptsExecuted": false,
                    "coverageVerified": false
                }
            });
            (
                progressive,
                vec![
                    "codelattice_project_insights",
                    "codelattice_project_overview",
                ],
            )
        }
        "quality" => {
            let r = handle_quality(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_quality"])
        }
        "insights" => {
            let r = handle_project_insights(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_project_insights"])
        }
        "diagnose" => {
            let r = build_project_diagnose(cache, analysis_params)?;
            (
                unwrap_tool_result(&r),
                vec![
                    "codelattice_project_insights",
                    "codelattice_symbol",
                    "codelattice_change_review",
                ],
            )
        }
        "ai_context" => {
            let r = handle_ai_context_pack(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_ai_context_pack"])
        }
        "full" => {
            let mut merged = json!({});
            let mut errors = Vec::new();
            safe_insert_tool(&mut merged, &mut errors, "overview", "overview", || {
                Ok(unwrap_tool_result(&handle_project_overview(
                    cache,
                    analysis_params,
                )?))
            });
            safe_insert_tool(&mut merged, &mut errors, "quality", "quality", || {
                Ok(unwrap_tool_result(&handle_quality(cache, analysis_params)?))
            });
            safe_insert_tool(&mut merged, &mut errors, "insights", "insights", || {
                Ok(unwrap_tool_result(&handle_project_insights(
                    cache,
                    analysis_params,
                )?))
            });
            safe_insert_tool(&mut merged, &mut errors, "aiContext", "ai_context", || {
                Ok(unwrap_tool_result(&handle_ai_context_pack(
                    cache,
                    analysis_params,
                )?))
            });
            if let Some(obj) = merged.as_object_mut() {
                if !errors.is_empty() {
                    obj.insert("errors".into(), json!(errors));
                }
            }
            return Ok(tool_result(&wrap_facade_output(
                merged,
                "codelattice_project",
                mode,
                language,
                root,
                json!({"riskLevel":"check sections"}),
                vec![],
                vec![
                    "codelattice_project_overview",
                    "codelattice_quality",
                    "codelattice_project_insights",
                    "codelattice_ai_context_pack",
                ],
                compact,
            )));
        }
        _ => unreachable!(),
    };
    let summary = if matches!(mode, "quick" | "standard" | "deep") {
        build_project_progressive_summary(
            inner
                .get("details")
                .filter(|v| !v.is_null())
                .unwrap_or(&inner),
            mode,
            root,
        )
    } else if mode == "diagnose" {
        let diagnose_summary = inner
            .get("summary")
            .cloned()
            .unwrap_or_else(|| json!({"riskLevel":"unknown"}));
        let likely_areas = inner
            .get("likelyAreas")
            .and_then(|a| a.as_array())
            .cloned()
            .unwrap_or_default();
        let read_first_items = inner
            .get("readFirst")
            .and_then(|a| a.as_array())
            .cloned()
            .unwrap_or_default();
        let top_areas: Vec<Value> = likely_areas
            .iter()
            .take(5)
            .map(|area| {
                let name = area.get("name").and_then(|v| v.as_str()).unwrap_or("");
                let file = area.get("file").and_then(|v| v.as_str()).unwrap_or("");
                let confidence = area
                    .get("confidence")
                    .and_then(|v| v.as_f64())
                    .unwrap_or(0.0);
                let reasons = area
                    .get("reasons")
                    .and_then(|r| r.as_array())
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|v| v.as_str().map(String::from))
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                let rank = area.get("rank").and_then(|v| v.as_u64()).unwrap_or(0);
                json!({
                    "rank": rank,
                    "name": name,
                    "file": file,
                    "symbol": name,
                    "confidence": confidence,
                    "reasons": reasons,
                    "staticOnly": true
                })
            })
            .collect();
        let top_read: Vec<Value> = read_first_items.iter().take(3).cloned().collect();
        let top_area_names: Vec<&str> = top_areas
            .iter()
            .take(3)
            .filter_map(|a| a["name"].as_str())
            .collect();
        let diagnosis_summary_text = if top_areas.is_empty() {
            "No likely areas found from symptom matching.".to_string()
        } else {
            format!(
                "Found {} likely areas; start with {} because {}.",
                top_areas.len(),
                top_areas
                    .first()
                    .and_then(|a| a["file"].as_str())
                    .unwrap_or("unknown file"),
                top_areas
                    .first()
                    .and_then(|a| a["reasons"].as_array())
                    .map(|r| r
                        .iter()
                        .filter_map(|v| v.as_str())
                        .collect::<Vec<_>>()
                        .join(", "))
                    .unwrap_or("highest score".to_string())
            )
        };
        json!({
            "riskLevel": diagnose_summary["riskLevel"].as_str().unwrap_or("unknown"),
            "mode": mode,
            "likelyAreaCount": diagnose_summary["likelyAreaCount"],
            "topConfidence": diagnose_summary["topConfidence"],
            "topLikelyAreas": top_areas,
            "readFirst": top_read,
            "diagnosisSummary": diagnosis_summary_text,
            "missingEvidence": [
                {"kind": "runtime_verification", "explanation": "Diagnosis is static-only. No runtime logs, test results, or coverage data were used."},
                {"kind": "no_code_execution", "explanation": "Target code was not executed. Verify hypotheses with targeted tests."}
            ],
            "detailHint": "Use compact=false or mode=job + job_detail for full diagnosis data.",
            "suspectedSymbols": top_area_names
        })
    } else {
        json!({"riskLevel":"low","mode":mode})
    };
    let mut next_actions: Vec<&str> = if matches!(mode, "quick" | "standard" | "deep") {
        project_depth_next_actions(mode)
    } else if mode == "diagnose" {
        vec![
            "Read result.readFirst in order before editing.",
            "Use codelattice_symbol context/callers/callees for the top likelyArea.",
            "Use codelattice_change_review mode=impact before changing a likelyArea.",
        ]
    } else {
        vec!["Use codelattice_symbol search to explore symbols"]
    };

    // workspace root 检测：project 收到 workspace root 时给出建议
    let diag = diagnose_root(root, language);
    let diag_kind = diag.get("kind").and_then(|v| v.as_str()).unwrap_or("");
    if diag_kind == "workspace"
        && !diag
            .get("recommendedProjectRoots")
            .and_then(|v| v.as_array())
            .map(|a| a.is_empty())
            .unwrap_or(true)
    {
        let mut new_next_actions: Vec<&str> = Vec::new();
        new_next_actions.push("This root appears to be a workspace. For single-project analysis, use a sub-project root from the recommendedProjectRoots list in rootDiagnosis.");
        new_next_actions.push("Or use codelattice_workspace for cross-project analysis.");
        next_actions = new_next_actions;
    }

    Ok(tool_result(&if mode == "quick" && compact {
        let detected_language = inner
            .get("language")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .unwrap_or_else(|| language.to_string());
        let facade = wrap_facade_output(
            inner,
            "codelattice_project",
            mode,
            language,
            root,
            summary,
            next_actions,
            underlying,
            compact,
        );
        let freshness = quick_freshness.as_deref().unwrap_or("fresh_snapshot");
        let evidence: Vec<Value> = facade
            .get("result")
            .and_then(|r| r.get("aiDigest"))
            .and_then(|d| d.get("topRisks"))
            .and_then(|v| v.as_array())
            .map(|arr| {
                arr.iter()
                    .take(5)
                    .map(|r| {
                        json!({
                            "risk": r.get("riskNote").and_then(|v| v.as_str()).unwrap_or(""),
                            "file": r.get("file").and_then(|v| v.as_str()).unwrap_or(""),
                            "score": r.get("rawRiskScore").and_then(|v| v.as_f64()).unwrap_or(0.0),
                        })
                    })
                    .collect()
            })
            .unwrap_or_default();
        let symbol_count = facade
            .get("result")
            .and_then(|r| r.get("summary"))
            .and_then(|s| s.get("symbolCount"))
            .and_then(|v| v.as_u64())
            .unwrap_or(0);
        let source_file_count = facade
            .get("result")
            .and_then(|r| r.get("summary"))
            .and_then(|s| s.get("sourceFileCount"))
            .and_then(|v| v.as_u64())
            .unwrap_or(0);
        let risk_level = facade
            .get("summary")
            .and_then(|s| s.get("riskLevel"))
            .and_then(|v| v.as_str())
            .unwrap_or("unknown");
        let confidence_level = match risk_level {
            "high" | "critical" => "high",
            "medium" => "medium",
            _ => "low",
        };
        let root_kind = facade
            .get("rootDiagnosis")
            .and_then(|d| d.get("kind"))
            .and_then(|v| v.as_str())
            .unwrap_or("unknown");
        let answer_summary = json!({
            "mode": "quick",
            "language": detected_language,
            "riskLevel": risk_level,
            "rootKind": root_kind,
            "symbolCount": symbol_count,
            "sourceFileCount": source_file_count,
            "topRiskCount": evidence.len(),
        });
        let estimated_bytes = answer_summary.to_string().len() + evidence.len() * 80;
        let mut decision_card = json!({
            "answerSummary": answer_summary,
            "freshness": freshness,
            "evidence": evidence,
            "confidence": {
                "level": confidence_level,
                "missingEvidence": [
                    {"kind": "runtime_verification", "explanation": "No runtime logs, test results, or coverage data were used."},
                    {"kind": "no_code_execution", "explanation": "Target code was not executed. Verify hypotheses with targeted tests."}
                ],
            },
            "omitted": {
                "fields": ["fullResult", "fileMetrics", "qualityMetrics", "docsSignals", "riskMap", "sourceOnlyEntries"],
                "detailAvailableVia": "codelattice_project mode=standard compact=false",
            },
            "tokenBudget": {
                "used": estimated_bytes,
                "max": 8192,
                "estimated": true,
            },
            "symbolCount": symbol_count,
        });
        let request_context = FacadeRequestContext::unrouted(
            "codelattice_project",
            mode,
            root,
            requested_language,
            language,
            compact,
        );
        attach_facade_contract(&mut decision_card, &request_context);
        decision_card
    } else {
        wrap_facade_output(
            inner,
            "codelattice_project",
            mode,
            language,
            root,
            summary,
            next_actions,
            underlying,
            compact,
        )
    }))
}

// ── codelattice_symbol ───────────────────────────────────────────────

struct WorkspaceAutoRouteDecision {
    selected_root: String,
    selected_language: String,
    router: Value,
}

fn workspace_project_absolute_root(workspace_root: &str, project: &Value) -> String {
    let project_path = project["path"].as_str().unwrap_or(".");
    let path = Path::new(project_path);
    if path.is_absolute() {
        return path.to_string_lossy().to_string();
    }

    let workspace = Path::new(workspace_root)
        .canonicalize()
        .unwrap_or_else(|_| PathBuf::from(workspace_root));
    workspace.join(path).to_string_lossy().to_string()
}

fn workspace_route_query(params: &Value) -> String {
    for key in ["query", "symbol", "name", "symbolId", "file"] {
        if let Some(value) = params[key].as_str().filter(|s| !s.trim().is_empty()) {
            return value.trim().to_string();
        }
    }
    if let Some(change) = params["change"].as_str().filter(|s| !s.trim().is_empty()) {
        let extracted = extract_symbol_from_question(change);
        if !extracted.is_empty() {
            return extracted;
        }
        return change.trim().to_string();
    }
    String::new()
}

fn workspace_query_tokens(query: &str) -> Vec<String> {
    query
        .split(|c: char| !(c.is_ascii_alphanumeric() || c == '_'))
        .map(str::trim)
        .filter(|s| s.len() >= 3)
        .map(|s| s.to_lowercase())
        .collect()
}

fn workspace_project_text(project: &Value) -> String {
    [
        project["name"].as_str().unwrap_or(""),
        project["relativePath"].as_str().unwrap_or(""),
        project["path"].as_str().unwrap_or(""),
        project["language"].as_str().unwrap_or(""),
    ]
    .join(" ")
    .to_lowercase()
}

fn workspace_symbol_evidence(gv: &GraphView, query: &str) -> (usize, Vec<Value>) {
    if query.trim().is_empty() {
        return (0, Vec::new());
    }
    let matches = gv.find_symbols(query, None, 5);
    let evidence = matches
        .iter()
        .take(3)
        .map(|node| {
            json!({
                "name": node_display_name(node),
                "file": node_source_path(node),
                "line": node_line_start(node),
                "symbolId": node["id"],
                "reason": "symbol query matched this project"
            })
        })
        .collect::<Vec<_>>();
    (matches.len(), evidence)
}

fn workspace_root_selection_guidance(
    root: &str,
    requested_language: &str,
    tool_name: &str,
    mode: &str,
) -> Option<Value> {
    let diag = diagnose_root(root, requested_language);
    let is_workspace = diag.get("kind").and_then(|v| v.as_str()) == Some("workspace");
    let recommended = diag
        .get("recommendedProjectRoots")
        .and_then(|v| v.as_array())
        .cloned()
        .unwrap_or_default();
    if !is_workspace || recommended.is_empty() {
        return None;
    }

    Some(json!({
        "schemaVersion": "codelattice.rootRouter.v1",
        "status": "needs_project_selection",
        "message": format!("{tool_name} {mode} needs a concrete project root. This workspace root has multiple candidate projects and no confident auto-route."),
        "root": root,
        "rootRouter": {
            "routed": false,
            "originalRoot": root,
            "reason": "no confident project match from query/symbol/change text",
            "confidence": "low",
            "candidates": recommended.iter().take(5).map(|project| {
                let mut candidate = project.clone();
                if let Some(obj) = candidate.as_object_mut() {
                    obj.insert("root".to_string(), json!(workspace_project_absolute_root(root, project)));
                }
                candidate
            }).collect::<Vec<_>>()
        },
        "recommendedProjectRoots": recommended.iter().take(5).cloned().collect::<Vec<_>>(),
        "recommendedNextCalls": recommended.iter().take(3).map(|project| {
            let project_root = workspace_project_absolute_root(root, project);
            let language = project.get("language").and_then(|v| v.as_str()).unwrap_or(requested_language);
            json!({
                "tool": tool_name,
                "mode": mode,
                "arguments": {
                    "root": project_root,
                    "language": language,
                    "compact": true
                }
            })
        }).collect::<Vec<_>>(),
        "analysisSemantics": {
            "staticAnalysisExecuted": false,
            "targetCodeExecuted": false,
            "runtimeProof": false,
            "coverageProof": false
        }
    }))
}

fn workspace_root_selection_error(
    root: &str,
    requested_language: &str,
    tool_name: &str,
    mode: &str,
) -> Option<Value> {
    workspace_root_selection_guidance(root, requested_language, tool_name, mode)
}

fn workspace_auto_route_decision(
    cache: &mut McpCache,
    root: &str,
    requested_language: &str,
    params: &Value,
    tool_name: &str,
    mode: &str,
) -> Option<Result<WorkspaceAutoRouteDecision, Value>> {
    let diag = diagnose_root(root, requested_language);
    let is_workspace = diag.get("kind").and_then(|v| v.as_str()) == Some("workspace");
    let recommended = diag
        .get("recommendedProjectRoots")
        .and_then(|v| v.as_array())
        .cloned()
        .unwrap_or_default();
    if !is_workspace || recommended.is_empty() {
        return None;
    }

    let query = workspace_route_query(params);
    let query_lower = query.to_lowercase();
    let query_tokens = workspace_query_tokens(&query);
    let mut candidates = Vec::new();

    for project in recommended.iter().take(5) {
        let selected_root = workspace_project_absolute_root(root, project);
        let selected_language = project["language"]
            .as_str()
            .filter(|s| !s.is_empty())
            .unwrap_or(requested_language)
            .to_string();
        let mut score = project["score"].as_f64().unwrap_or(0.0) / 10.0;
        let mut reasons: Vec<String> = vec!["workspace recommended project root".to_string()];
        let mut evidence: Vec<Value> = Vec::new();
        let mut symbol_match_count = 0usize;
        let mut large_project_deferred = false;

        if !query_lower.is_empty() {
            let project_text = workspace_project_text(project);
            if query_tokens
                .iter()
                .any(|token| project_text.contains(token))
                || (!query_lower.is_empty() && project_text.contains(&query_lower))
            {
                score += 30.0;
                reasons.push("query text matches project name/path/language".to_string());
            }

            if ask_large_project_info(&selected_root, &selected_language).is_some() {
                large_project_deferred = true;
                reasons.push(
                    "large project not synchronously probed; routed call can submit/read job"
                        .to_string(),
                );
            } else if let Ok((gv, _result, _cache_meta)) =
                cache.get_or_analyze(&PathBuf::from(&selected_root), &selected_language, false)
            {
                let (matches, match_evidence) = workspace_symbol_evidence(&gv, &query);
                if matches > 0 {
                    score += 100.0 + matches as f64;
                    symbol_match_count = matches;
                    evidence = match_evidence;
                    reasons.push(format!("{matches} symbol match(es) found in project graph"));
                }
            } else {
                reasons
                    .push("project graph probe failed; kept recommendation score only".to_string());
            }
        }

        candidates.push(json!({
            "root": selected_root,
            "language": selected_language,
            "project": project,
            "score": score,
            "symbolMatchCount": symbol_match_count,
            "largeProjectDeferred": large_project_deferred,
            "evidence": evidence,
            "reasons": reasons
        }));
    }

    candidates.sort_by(|a, b| {
        b["score"]
            .as_f64()
            .unwrap_or(0.0)
            .partial_cmp(&a["score"].as_f64().unwrap_or(0.0))
            .unwrap_or(std::cmp::Ordering::Equal)
    });

    let Some(best) = candidates.first().cloned() else {
        return workspace_root_selection_guidance(root, requested_language, tool_name, mode)
            .map(|guidance| Err(guidance));
    };

    let best_score = best["score"].as_f64().unwrap_or(0.0);
    let best_matches = best["symbolMatchCount"].as_u64().unwrap_or(0);
    let best_large_deferred = best["largeProjectDeferred"].as_bool().unwrap_or(false);
    let confident = best_matches > 0
        || (!query.is_empty() && best_score >= 30.0)
        || (recommended.len() == 1 && (best_score > 0.0 || best_large_deferred));

    if !confident {
        return workspace_root_selection_guidance(root, requested_language, tool_name, mode)
            .map(|guidance| Err(guidance));
    }

    let selected_root = best["root"].as_str().unwrap_or(root).to_string();
    let selected_language = best["language"]
        .as_str()
        .unwrap_or(requested_language)
        .to_string();
    let confidence = if best_matches > 0 {
        "high"
    } else if best_large_deferred {
        "medium"
    } else {
        "medium"
    };
    let router = json!({
        "schemaVersion": "codelattice.rootRouter.v1",
        "routed": true,
        "tool": tool_name,
        "mode": mode,
        "originalRoot": root,
        "selectedRoot": selected_root,
        "selectedLanguage": selected_language,
        "selectedProject": best["project"].clone(),
        "query": query,
        "confidence": confidence,
        "reason": if best_matches > 0 {
            "selected project because the query matched symbols in its graph"
        } else if best_large_deferred {
            "selected highest-ranked project without synchronous large-project probing"
        } else {
            "selected project from workspace ranking and query/project-name heuristics"
        },
        "candidates": candidates.into_iter().take(5).collect::<Vec<_>>(),
        "analysisSemantics": {
            "staticAnalysisExecuted": true,
            "targetCodeExecuted": false,
            "runtimeProof": false,
            "coverageProof": false
        }
    });

    Some(Ok(WorkspaceAutoRouteDecision {
        selected_root,
        selected_language,
        router,
    }))
}

fn attach_root_router_to_tool_result(result: Value, router: Value) -> Value {
    let mut inner = unwrap_tool_result(&result);
    let context = FacadeRequestContext::from_routed_tool_result(&inner, &router);
    if let Some(obj) = inner.as_object_mut() {
        obj.insert("rootRouter".to_string(), router);
        if let Some(summary) = obj.get_mut("summary").and_then(|v| v.as_object_mut()) {
            summary.insert("routedFromWorkspace".to_string(), json!(true));
        }
    }
    attach_facade_request_context(&mut inner, &context);
    tool_result(&inner)
}

fn handle_symbol(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["mode"].as_str().unwrap_or("search");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let requested_language = params["language"].as_str().unwrap_or("auto");
    validate_facade_mode(
        mode,
        &[
            "search",
            "context",
            "callers",
            "callees",
            "graph",
            "call_chains",
            "job",
            "job_status",
            "job_detail",
            "job_cancel",
        ],
        "codelattice_symbol",
    )?;

    if matches!(mode, "job_status" | "job_detail" | "job_cancel") {
        return handle_facade_job(
            "",
            requested_language,
            mode,
            "codelattice_symbol",
            params,
            compact,
        );
    }
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    if matches!(mode, "job" | "job_status" | "job_detail" | "job_cancel") {
        return handle_facade_job(
            root,
            requested_language,
            mode,
            "codelattice_symbol",
            params,
            compact,
        );
    }

    let validated_root = validate_root_path(root)?;
    if let Some(route) = workspace_auto_route_decision(
        cache,
        root,
        requested_language,
        params,
        "codelattice_symbol",
        mode,
    ) {
        match route {
            Ok(route) => {
                let mut routed_params = params.clone();
                routed_params["root"] = json!(route.selected_root);
                routed_params["language"] = json!(route.selected_language);
                let routed_result = handle_symbol(cache, &routed_params)?;
                return Ok(attach_root_router_to_tool_result(
                    routed_result,
                    route.router,
                ));
            }
            Err(guidance) => return Ok(tool_result(&guidance)),
        }
    }
    let language_owned = resolve_auto_language_for_root(&validated_root, requested_language)?;
    let language = language_owned.as_str();
    let request_context = FacadeRequestContext::unrouted(
        "codelattice_symbol",
        mode,
        root,
        requested_language,
        language,
        compact,
    );
    let mut effective_params = params.clone();
    effective_params["language"] = json!(language);
    let analysis_params = &effective_params;

    // 分析面 mode 的自动 job 化：大项目 cache miss → 异步 job
    if matches!(mode, "search" | "context" | "callers" | "callees" | "graph") {
        if let Some(auto_job_resp) = facade_auto_job_check(
            cache,
            root,
            requested_language,
            language,
            "codelattice_symbol",
            mode,
            analysis_params,
        ) {
            return Ok(tool_result(&auto_job_resp));
        }
    }

    let root_diag = diagnose_root(root, language);

    let (inner, underlying): (Value, Vec<&str>) = match mode {
        "search" => {
            let r = handle_symbol_search(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_symbol_search"])
        }
        "context" => {
            let r = handle_symbol_context(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_symbol_context"])
        }
        "callers" => {
            let mut call_params = analysis_params.clone();
            if call_params.get("symbol").and_then(|v| v.as_str()).is_none() {
                if let Some(name) = call_params
                    .get("name")
                    .and_then(|v| v.as_str())
                    .or_else(|| call_params.get("query").and_then(|v| v.as_str()))
                {
                    call_params["symbol"] = json!(name);
                }
            }
            let r = handle_calls_to(cache, &call_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_calls_to"])
        }
        "callees" => {
            let mut call_params = analysis_params.clone();
            if call_params.get("symbol").and_then(|v| v.as_str()).is_none() {
                if let Some(name) = call_params
                    .get("name")
                    .and_then(|v| v.as_str())
                    .or_else(|| call_params.get("query").and_then(|v| v.as_str()))
                {
                    call_params["symbol"] = json!(name);
                }
            }
            let r = handle_calls_from(cache, &call_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_calls_from"])
        }
        "graph" => {
            let r = handle_query_graph(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_query_graph"])
        }
        "call_chains" => {
            let direction = analysis_params["direction"].as_str().unwrap_or("both");
            let max_depth = analysis_params["maxDepth"].as_u64().unwrap_or(4).min(6) as usize;
            let limit = analysis_params["limit"].as_u64().unwrap_or(8).min(20) as usize;
            let query = analysis_params["query"]
                .as_str()
                .or_else(|| analysis_params["name"].as_str())
                .unwrap_or("")
                .to_string();
            let root_path = PathBuf::from(root);

            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                let result_body = json!({
                    "schemaVersion": "codelattice.callChains.v1",
                    "target": query,
                    "candidates": [],
                    "callChains": [],
                    "readFirst": sample_files.iter().take(5).map(|path| json!({
                        "kind": "source-sample",
                        "path": path,
                        "reason": "large project sample; run job analysis for complete call-chain evidence"
                    })).collect::<Vec<_>>(),
                    "readOrder": [],
                    "filesInvolved": sample_files,
                    "entryPoints": [],
                    "exitPoints": [],
                    "chainSummary": format!("Call-chain traversal deferred for large project with {} source files.", file_count),
                    "ambiguity": "",
                    "missingEvidence": [{
                        "kind": "large_project_deferred",
                        "explanation": "Synchronous call_chains skipped full graph analysis to avoid blocking MCP."
                    }],
                    "generatedFrom": "large-project-deferred-static-discovery",
                    "analysisSemantics": {
                        "staticAnalysis": true,
                        "targetCodeExecuted": false,
                        "runtimeVerified": false,
                        "scriptsExecuted": false
                    },
                    "nextActions": ask_large_project_next_actions(root, language, if query.is_empty() { None } else { Some(&query) }, "call_chains"),
                    "detailHint": "Use codelattice_project(mode=job), then job_detail pages, before asking for deep call chains on this large project."
                });
                let content_text = serde_json::to_string_pretty(&result_body)
                    .unwrap_or_else(|_| result_body.to_string());
                return Ok(json!({
                    "content": [{"type": "text", "text": content_text}],
                }));
            }

            let (
                candidates,
                call_chains,
                chain_read_first,
                chain_missing,
                chain_next,
                read_order,
                files_involved,
                entry_points,
                exit_points,
                chain_summary,
            ) = build_call_chains_result(&root_path, language, &query, direction, max_depth, limit);

            let chain_count = call_chains.len();
            let chains_output = if compact {
                call_chains.into_iter().take(5).collect::<Vec<_>>()
            } else {
                call_chains
            };

            let result_body = json!({
                "schemaVersion": "codelattice.callChains.v1",
                "target": query,
                "candidates": candidates,
                "callChains": chains_output,
                "readFirst": chain_read_first,
                "readOrder": read_order,
                "filesInvolved": files_involved,
                "entryPoints": entry_points,
                "exitPoints": exit_points,
                "chainSummary": chain_summary,
                "ambiguity": if candidates.len() > 5 { "multiple candidates found, consider narrowing query" } else { "" },
                "missingEvidence": chain_missing,
                "generatedFrom": "static-call-graph",
                "analysisSemantics": {
                    "staticAnalysis": true,
                    "targetCodeExecuted": false,
                    "runtimeVerified": false,
                    "scriptsExecuted": false
                },
                "nextActions": chain_next,
                "detailHint": if compact && chain_count > 5 { "Use compact=false or increase limit for more chains" } else { "" }
            });

            let content_text = serde_json::to_string_pretty(&result_body)
                .unwrap_or_else(|_| result_body.to_string());

            return Ok(json!({
                "content": [{"type": "text", "text": content_text}],
            }));
        }
        _ => unreachable!(),
    };

    // workspace root 误用检测: 如果 root 是 workspace 且搜索返回 0 结果
    let root_kind = root_diag
        .get("kind")
        .and_then(|v| v.as_str())
        .unwrap_or("unknown");
    let workspace_misuse = matches!(root_kind, "workspace" | "unsupported_or_mixed_workspace");

    // ⬇ check for empty search results
    let has_symbols = inner
        .get("symbols")
        .or_else(|| inner.get("results"))
        .and_then(|v| v.as_array())
        .map(|a| !a.is_empty())
        .unwrap_or(true);
    let has_edges = inner
        .get("edges")
        .and_then(|v| v.as_array())
        .map(|a| !a.is_empty())
        .unwrap_or(true);

    let mut next_actions = vec!["Use context mode for full symbol details"];

    if workspace_misuse && !has_symbols && !has_edges {
        // 构建 workspace misuse help 输出
        let recommendations = root_diag
            .get("recommendedProjectRoots")
            .cloned()
            .unwrap_or_else(|| json!([]));
        let explanation = root_diag
            .get("explanation")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let cautions = root_diag
            .get("cautions")
            .cloned()
            .unwrap_or_else(|| json!([]));

        let help_output = json!({
            "mode": mode,
            "rootDiagnosis": {
                "kind": root_kind,
                "inputRoot": root,
                "explanation": explanation,
                "cautions": cautions
            },
            "workspaceRootMisuse": {
                "detected": true,
                "diagnosis": format!(
                    "The root '{}' is a {} root. codelattice_symbol expects a single project root, not a workspace root.",
                    root, root_kind
                ),
                "fix": "Use one of the recommendedProjectRoots as the root parameter for codelattice_symbol.",
                "recommendedProjectRoots": recommendations,
                "recommendedTool": "codelattice_workspace"
            },
            "result": inner
        });

        next_actions = vec![
            "Use codelattice_workspace mode=graph to see project structure",
            "Re-run codelattice_symbol with a specific project root from recommendedProjectRoots",
        ];
        let mut output = wrap_facade_output(
            help_output,
            "codelattice_symbol",
            mode,
            language,
            root,
            json!({"riskLevel":"low","mode":mode,"workspaceRootMisuse":true}),
            next_actions,
            underlying,
            compact,
        );
        attach_facade_request_context(&mut output, &request_context);
        return Ok(tool_result(&output));
    }

    let mut summary = json!({"riskLevel":"low","mode":mode});
    if compact && mode == "search" {
        if let Some(obj) = summary.as_object_mut() {
            if let Some(count) = inner.get("matchCount") {
                obj.insert("matchCount".to_string(), count.clone());
            }
            let top_matches = inner
                .get("matches")
                .and_then(|v| v.as_array())
                .map(|items| items.iter().take(5).cloned().collect::<Vec<_>>())
                .unwrap_or_default();
            obj.insert("topMatches".to_string(), json!(top_matches));
        }
    }

    let mut output = wrap_facade_output(
        inner,
        "codelattice_symbol",
        mode,
        language,
        root,
        summary,
        next_actions,
        underlying,
        compact,
    );
    attach_facade_request_context(&mut output, &request_context);
    Ok(tool_result(&output))
}

// ── codelattice_change_review ────────────────────────────────────────

fn handle_change_review(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["mode"].as_str().unwrap_or("impact");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let requested_language = params["language"].as_str().unwrap_or("auto");
    validate_facade_mode(
        mode,
        &[
            "changed_symbols",
            "impact",
            "production_assist",
            "breaking_change",
            "consistency",
            "full_review",
            "native_review",
            "safe_cleanup_review",
            "dead_code",
            "reachability",
            "external_api",
            "framework_entries",
            "release_check",
            "docs_tests",
            "config_examples",
            "root_cause",
            "job",
            "job_status",
            "job_detail",
            "job_cancel",
            "whatif",
        ],
        "codelattice_change_review",
    )?;

    // ═══ Engine 1.3 job runtime ═══
    if matches!(mode, "job_status" | "job_detail" | "job_cancel") {
        return handle_facade_job(
            "",
            requested_language,
            mode,
            "codelattice_change_review",
            params,
            compact,
        );
    }
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    if matches!(mode, "job" | "job_status" | "job_detail") {
        return handle_facade_job(
            root,
            requested_language,
            mode,
            "codelattice_change_review",
            params,
            compact,
        );
    }

    let validated_root = validate_root_path(root)?;
    if let Some(route) = workspace_auto_route_decision(
        cache,
        root,
        requested_language,
        params,
        "codelattice_change_review",
        mode,
    ) {
        match route {
            Ok(route) => {
                let mut routed_params = params.clone();
                routed_params["root"] = json!(route.selected_root);
                routed_params["language"] = json!(route.selected_language);
                let routed_result = handle_change_review(cache, &routed_params)?;
                return Ok(attach_root_router_to_tool_result(
                    routed_result,
                    route.router,
                ));
            }
            Err(guidance) => return Ok(tool_result(&guidance)),
        }
    }
    let language_owned = resolve_auto_language_for_root(&validated_root, requested_language)?;
    let language = language_owned.as_str();
    let mut effective_params = params.clone();
    effective_params["language"] = json!(language);
    let analysis_params = &effective_params;

    // 分析面 mode 的自动 job 化：大项目 cache miss → 异步 job
    if matches!(
        mode,
        "impact"
            | "breaking_change"
            | "consistency"
            | "full_review"
            | "native_review"
            | "safe_cleanup_review"
            | "dead_code"
            | "reachability"
            | "whatif"
    ) {
        if let Some(auto_job_resp) = facade_auto_job_check(
            cache,
            root,
            requested_language,
            language,
            "codelattice_change_review",
            mode,
            analysis_params,
        ) {
            return Ok(tool_result(&auto_job_resp));
        }
    }

    let (inner, underlying): (Value, Vec<&str>) = match mode {
        "changed_symbols" => {
            let r = handle_changed_symbols(cache, analysis_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_changed_symbols"])
        }
        "impact" => {
            let mut impact_params = analysis_params.clone();
            if impact_params
                .get("symbol")
                .and_then(|v| v.as_str())
                .is_none()
            {
                if let Some(name) = impact_params
                    .get("query")
                    .and_then(|v| v.as_str())
                    .or_else(|| impact_params.get("name").and_then(|v| v.as_str()))
                    .or_else(|| impact_params.get("symbolId").and_then(|v| v.as_str()))
                {
                    impact_params["symbol"] = json!(name);
                }
            }
            let r = handle_impact_preview(cache, &impact_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_impact_preview"])
        }
        "production_assist" => {
            let r = handle_production_assist(cache, analysis_params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_production_assist"],
            )
        }
        "breaking_change" => {
            let r = handle_breaking_change_review(cache, analysis_params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_breaking_change_review"],
            )
        }
        "consistency" => {
            let r = handle_consistency_review(cache, analysis_params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_consistency_review"],
            )
        }
        "safe_cleanup_review"
        | "dead_code"
        | "reachability"
        | "external_api"
        | "framework_entries" => {
            let mut cleanup_params = analysis_params.clone();
            cleanup_params["mode"] = json!(mode);
            let r = handle_cleanup(cache, &cleanup_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_cleanup"])
        }
        "release_check" => {
            let mut release_params = analysis_params.clone();
            release_params["mode"] = json!("full");
            let r = handle_release_check(cache, &release_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_release_check"])
        }
        "docs_tests" => {
            let mut release_params = analysis_params.clone();
            release_params["mode"] = json!("docs_tests");
            let r = handle_release_check(cache, &release_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_release_check"])
        }
        "config_examples" => {
            let mut release_params = analysis_params.clone();
            release_params["mode"] = json!("config");
            let r = handle_release_check(cache, &release_params)?;
            (unwrap_tool_result(&r), vec!["codelattice_release_check"])
        }
        "root_cause" => {
            let r = handle_root_cause_assistant(cache, analysis_params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_root_cause_assistant"],
            )
        }
        "full_review" => {
            let mut merged = json!({});
            let mut errors = Vec::new();
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "changedSymbols",
                "changed_symbols",
                || {
                    Ok(unwrap_tool_result(&handle_changed_symbols(
                        cache,
                        analysis_params,
                    )?))
                },
            );
            safe_insert_tool(&mut merged, &mut errors, "impact", "impact", || {
                Ok(unwrap_tool_result(&handle_impact_preview(
                    cache,
                    analysis_params,
                )?))
            });
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "breakingChange",
                "breaking_change",
                || {
                    Ok(unwrap_tool_result(&handle_breaking_change_review(
                        cache,
                        analysis_params,
                    )?))
                },
            );
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "consistency",
                "consistency",
                || {
                    Ok(unwrap_tool_result(&handle_consistency_review(
                        cache,
                        analysis_params,
                    )?))
                },
            );
            if let Some(obj) = merged.as_object_mut() {
                if !errors.is_empty() {
                    obj.insert("errors".into(), json!(errors));
                }
            }
            return Ok(tool_result(&wrap_facade_output(
                merged,
                "codelattice_change_review",
                mode,
                language,
                root,
                json!({"riskLevel":"varies"}),
                vec!["Review changedSymbols first"],
                vec![
                    "codelattice_changed_symbols",
                    "codelattice_impact_preview",
                    "codelattice_breaking_change_review",
                    "codelattice_consistency_review",
                ],
                compact,
            )));
        }
        "native_review" => {
            // native_review: MCP facade 入口，编排 changed_symbols + production_assist
            // 完整 workspace-aware change intelligence 请使用 CLI detect-changes
            let mut merged = json!({});
            let mut errors = Vec::new();
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "changedSymbols",
                "changed_symbols",
                || {
                    Ok(unwrap_tool_result(&handle_changed_symbols(
                        cache,
                        analysis_params,
                    )?))
                },
            );
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "productionAssist",
                "production_assist",
                || {
                    Ok(unwrap_tool_result(&handle_production_assist(
                        cache,
                        analysis_params,
                    )?))
                },
            );
            if let Some(obj) = merged.as_object_mut() {
                if !errors.is_empty() {
                    obj.insert("errors".into(), json!(errors));
                }
                obj.insert("nativeReviewNote".into(), json!(
                    "For full workspace-aware change intelligence (fileOwners, affectedProjects, crossProjectRisk, unsupportedBoundaryHits), use CLI: codelattice detect-changes --root <root> --language <lang>"
                ));
            }
            return Ok(tool_result(&wrap_facade_output(
                merged,
                "codelattice_change_review",
                mode,
                language,
                root,
                json!({"riskLevel":"see-changedSymbols-and-productionAssist"}),
                vec!["Use CLI detect-changes for full workspace change intelligence including fileOwners, crossProjectRisk, and unsupportedBoundaryHits"],
                vec![
                    "codelattice_changed_symbols",
                    "codelattice_production_assist",
                ],
                compact,
            )));
        }
        "whatif" => {
            let change = analysis_params["change"].as_str().unwrap_or("").to_string();
            let symbol_param = analysis_params["symbol"].as_str().unwrap_or("").to_string();
            let file_param = analysis_params["file"].as_str().unwrap_or("").to_string();
            let action = analysis_params["action"].as_str().unwrap_or("").to_string();
            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                let query = if !symbol_param.is_empty() {
                    symbol_param.clone()
                } else {
                    extract_symbol_from_question(&change)
                };
                let result_body = build_deferred_whatif_value(
                    root,
                    language,
                    &change,
                    &query,
                    file_count,
                    &sample_files,
                );
                let content_text = serde_json::to_string_pretty(&result_body)
                    .unwrap_or_else(|_| result_body.to_string());
                return Ok(json!({"content": [{"type": "text", "text": content_text}]}));
            }
            let (
                change_intent,
                target_candidates,
                direct_impact,
                indirect_impact,
                risk,
                safe_alts,
                tests,
                read_first,
                missing,
                next_actions,
                action_plan,
            ) = build_whatif_result(root, language, &change, &symbol_param, &file_param, &action);

            let result_body = json!({
                "schemaVersion": "codelattice.whatIf.v1",
                "changeIntent": change_intent,
                "targetCandidates": target_candidates,
                "directImpact": direct_impact,
                "indirectImpact": if compact { indirect_impact.into_iter().take(5).collect::<Vec<_>>() } else { indirect_impact },
                "risk": risk,
                "safeAlternatives": safe_alts,
                "testsToRun": tests,
                "readFirst": read_first,
                "missingEvidence": missing,
                "actionPlan": action_plan,
                "recommendedNextCalls": next_actions,
                "analysisSemantics": {
                    "staticAnalysisExecuted": true,
                    "targetCodeExecuted": false,
                    "runtimeVerified": false,
                    "scriptsExecuted": false
                }
            });
            let content_text = serde_json::to_string_pretty(&result_body)
                .unwrap_or_else(|_| result_body.to_string());
            return Ok(json!({"content": [{"type": "text", "text": content_text}]}));
        }
        _ => unreachable!(),
    };
    Ok(tool_result(&wrap_facade_output(
        inner,
        "codelattice_change_review",
        mode,
        language,
        root,
        json!({"riskLevel":"medium","mode":mode}),
        vec!["Use full_review mode for comprehensive analysis"],
        underlying,
        compact,
    )))
}

// ── codelattice_cleanup ──────────────────────────────────────────────

fn handle_cleanup(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    let mode = params["mode"].as_str().unwrap_or("dead_code");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let language = params["language"].as_str().unwrap_or("auto");
    validate_facade_mode(
        mode,
        &[
            "dead_code",
            "reachability",
            "external_api",
            "framework_entries",
            "safe_cleanup_review",
        ],
        "codelattice_cleanup",
    )?;
    let (inner, underlying): (Value, Vec<&str>) = match mode {
        "dead_code" => {
            let r = handle_dead_code_candidates(cache, params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_dead_code_candidates"],
            )
        }
        "reachability" => {
            let r = handle_reachability_map(cache, params)?;
            (unwrap_tool_result(&r), vec!["codelattice_reachability_map"])
        }
        "external_api" => {
            let r = handle_external_api_surface(cache, params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_external_api_surface"],
            )
        }
        "framework_entries" => {
            let r = handle_framework_entry_hints(cache, params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_framework_entry_hints"],
            )
        }
        "safe_cleanup_review" => {
            let mut merged = json!({});
            let mut errors = Vec::new();
            safe_insert_tool(&mut merged, &mut errors, "deadCode", "dead_code", || {
                Ok(unwrap_tool_result(&handle_dead_code_candidates(
                    cache, params,
                )?))
            });
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "reachability",
                "reachability",
                || Ok(unwrap_tool_result(&handle_reachability_map(cache, params)?)),
            );
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "externalApi",
                "external_api",
                || {
                    Ok(unwrap_tool_result(&handle_external_api_surface(
                        cache, params,
                    )?))
                },
            );
            safe_insert_tool(
                &mut merged,
                &mut errors,
                "frameworkEntries",
                "framework_entries",
                || {
                    Ok(unwrap_tool_result(&handle_framework_entry_hints(
                        cache, params,
                    )?))
                },
            );
            if let Some(obj) = merged.as_object_mut() {
                if !errors.is_empty() {
                    obj.insert("errors".into(), json!(errors));
                }
            }
            return Ok(tool_result(&wrap_facade_output(
                merged,
                "codelattice_cleanup",
                mode,
                language,
                root,
                json!({"riskLevel":"high — do not delete without review"}),
                vec!["Cross-reference deadCode with reachability"],
                vec![
                    "codelattice_dead_code_candidates",
                    "codelattice_reachability_map",
                    "codelattice_external_api_surface",
                    "codelattice_framework_entry_hints",
                ],
                compact,
            )));
        }
        _ => unreachable!(),
    };
    Ok(tool_result(&wrap_facade_output(
        inner,
        "codelattice_cleanup",
        mode,
        language,
        root,
        json!({"riskLevel":"medium","mode":mode}),
        vec!["Use safe_cleanup_review for comprehensive review"],
        underlying,
        compact,
    )))
}

// ── codelattice_workspace ────────────────────────────────────────────

fn handle_workspace(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["mode"].as_str().unwrap_or("graph");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let language = "auto";
    validate_facade_mode(
        mode,
        &[
            "graph",
            "impact",
            "overview",
            "full",
            "job",
            "job_status",
            "job_detail",
            "job_cancel",
        ],
        "codelattice_workspace",
    )?;

    // ═══ Engine 1.3 job runtime ═══
    if matches!(mode, "job_status" | "job_detail" | "job_cancel") {
        return handle_facade_job("", "auto", mode, "codelattice_workspace", params, compact);
    }
    let root = params["root"]
        .as_str()
        .ok_or_else(|| mcp_error("missing_parameter", "Missing required parameter: root"))?;
    if matches!(mode, "job" | "job_status" | "job_detail") {
        return handle_facade_job(root, "auto", mode, "codelattice_workspace", params, compact);
    }

    let (inner, underlying): (Value, Vec<&str>) = match mode {
        "graph" => {
            let r = handle_workspace_graph(cache, params)?;
            (unwrap_tool_result(&r), vec!["codelattice_workspace_graph"])
        }
        "impact" => {
            let r = handle_cross_project_impact(cache, params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_cross_project_impact"],
            )
        }
        "overview" => {
            let r = handle_workspace_graph(cache, params)?;
            let g = unwrap_tool_result(&r);
            (
                g.get("summary").cloned().unwrap_or(json!({})),
                vec!["codelattice_workspace_graph"],
            )
        }
        "full" => {
            let mut merged = json!({});
            let mut errors = Vec::new();
            safe_insert_tool(&mut merged, &mut errors, "graph", "graph", || {
                Ok(unwrap_tool_result(&handle_workspace_graph(cache, params)?))
            });
            if let Some(obj) = merged.as_object_mut() {
                if !errors.is_empty() {
                    obj.insert("errors".into(), json!(errors));
                }
            }
            return Ok(tool_result(&wrap_facade_output(
                merged,
                "codelattice_workspace",
                mode,
                language,
                root,
                json!({"riskLevel":"low"}),
                vec!["Use impact mode with a target"],
                vec![
                    "codelattice_workspace_graph",
                    "codelattice_cross_project_impact",
                ],
                compact,
            )));
        }
        _ => unreachable!(),
    };
    Ok(tool_result(&wrap_facade_output(
        inner,
        "codelattice_workspace",
        mode,
        language,
        root,
        json!({"riskLevel":"low","mode":mode}),
        vec!["Use impact mode to analyze specific targets"],
        underlying,
        compact,
    )))
}

