// ── codelattice_cache ────────────────────────────────────────────────

fn handle_cache(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["mode"].as_str().unwrap_or("status");
    let compact = params["compact"].as_bool().unwrap_or(false);
    validate_facade_mode(mode, &["status", "clear", "explain"], "codelattice_cache")?;
    let (inner, underlying, persistent_enabled): (Value, Vec<&str>, bool) = match mode {
        "status" => {
            let r = handle_cache_status(cache, params)?;
            let raw = unwrap_tool_result(&r);
            let has_persistent = raw
                .get("persistent")
                .and_then(|p| p.get("enabled"))
                .and_then(|e| e.as_bool())
                .unwrap_or(false);
            (raw, vec!["codelattice_cache_status"], has_persistent)
        }
        "clear" => {
            let r = handle_cache_clear(cache, params)?;
            (
                unwrap_tool_result(&r),
                vec!["codelattice_cache_clear"],
                false,
            )
        }
        "explain" => (
            json!({"layers":["memory","persistent"],"disable":"CODELATTICE_CACHE=off","clear":"Use mode=clear","prewarm":"Use codelattice_cache_prewarm"}),
            vec!["codelattice_cache_status"],
            false,
        ),
        _ => unreachable!(),
    };
    let mut output = wrap_facade_output(
        inner,
        "codelattice_cache",
        mode,
        "n/a",
        "n/a",
        json!({"riskLevel":"low","mode":mode}),
        vec!["Use clear to reset cache"],
        underlying,
        compact,
    );
    // 添加 cacheSemantics
    if let Some(obj) = output.as_object_mut() {
        obj.insert(
            "cacheSemantics".to_string(),
            build_cache_semantics(persistent_enabled),
        );
    }
    Ok(tool_result(&output))
}

// ── codelattice_workflow ─────────────────────────────────────────────

fn workflow_base_args(root: &str, language: &str, mode: &str) -> Value {
    let mut args = json!({
        "mode": mode,
        "language": language,
        "compact": true
    });
    if !root.is_empty() {
        args["root"] = json!(root);
    }
    args
}

fn workflow_explore_depth(params: &Value) -> u64 {
    params["depth"].as_u64().unwrap_or(1).clamp(1, 3)
}

fn workflow_project_mode_for_depth(depth: u64) -> &'static str {
    match depth {
        1 => "quick",
        2 => "standard",
        _ => "deep",
    }
}

fn workflow_recommended_project_args(
    workspace_root: &str,
    fallback_language: &str,
    root_diagnosis: &Value,
    mode: &str,
) -> Option<Value> {
    let project = root_diagnosis
        .get("recommendedProjectRoots")
        .and_then(|v| v.as_array())
        .and_then(|items| items.first())?;
    let project_root = workspace_project_absolute_root(workspace_root, project);
    let language = project
        .get("language")
        .and_then(|v| v.as_str())
        .filter(|s| !s.is_empty())
        .unwrap_or(fallback_language);
    Some(json!({
        "mode": mode,
        "root": project_root,
        "language": language,
        "compact": true,
        "workspaceRoot": workspace_root,
        "selectedFromWorkspace": true
    }))
}

fn build_workflow_exploration_plan(
    root: &str,
    language: &str,
    depth: u64,
    focus: &str,
    root_diagnosis: &Value,
    evidence: &[Value],
) -> Value {
    let root_kind = root_diagnosis
        .get("kind")
        .and_then(|v| v.as_str())
        .unwrap_or("unknown");
    let mut read_first: Vec<Value> = Vec::new();
    let mut drill_down_options: Vec<Value> = Vec::new();

    for item in evidence {
        let digest = item.get("summary").and_then(|s| s.get("aiDigest"));
        if let Some(digest) = digest {
            read_first.extend(take_json_items(&digest["readFirst"], 5));
            drill_down_options.extend(take_json_items(&digest["drillDownOptions"], 5));
        }
        if read_first.is_empty() {
            read_first.extend(take_json_items(&item["readFirst"], 5));
        }
    }

    if read_first.is_empty() {
        if root_kind == "workspace" || root_kind == "unsupported_or_mixed_workspace" {
            for item in take_json_items(&root_diagnosis["recommendedProjectRoots"], 5) {
                read_first.push(json!({
                    "kind": "projectRoot",
                    "path": item["path"].clone(),
                    "root": workspace_project_absolute_root(root, &item),
                    "language": item["language"].clone(),
                    "reason": "workspace root: choose a concrete project root before symbol-level exploration"
                }));
            }
        } else {
            read_first.push(json!({
                "kind": "project",
                "root": root,
                "reason": "start with codelattice_project mode=quick to get entry points, components, and top risks"
            }));
        }
    }

    if drill_down_options.is_empty() {
        drill_down_options = vec![
            json!({"tool": "codelattice_project", "mode": "standard", "when": "you need module boundaries and risk review"}),
            json!({"tool": "codelattice_project", "mode": "deep", "when": "you need full static detail"}),
            json!({"tool": "codelattice_workflow", "mode": "diagnose_issue", "when": "you have a symptom/error/query"}),
            json!({"tool": "codelattice_workflow", "mode": "before_edit", "when": "you have picked a concrete symbol"}),
        ];
    }

    json!({
        "schemaVersion": "codelattice.progressiveExplore.v1",
        "depth": depth,
        "focus": if focus.is_empty() { Value::Null } else { json!(focus) },
        "rootKind": root_kind,
        "recommendedProjectMode": workflow_project_mode_for_depth(depth),
        "objective": match depth {
            1 => "Orient quickly: identify project kind, entry points, first files, and obvious hotspots.",
            2 => "Review component boundaries, architecture risk, and areas to inspect before edits.",
            _ => "Gather detailed static evidence and prepare targeted follow-up calls.",
        },
        "readFirst": read_first,
        "drillDownOptions": drill_down_options,
        "nextQueries": [
            {"mode": "explore", "depth": (depth + 1).min(3), "reason": "go one level deeper after reading the first files"},
            {"mode": "diagnose_issue", "reason": "switch to issue localization once you have a symptom"},
            {"mode": "before_edit", "reason": "switch to change safety once you choose a symbol"}
        ],
        "analysisSemantics": build_analysis_semantics(),
        "language": language
    })
}

fn workflow_action(tool: &str, arguments: Value, why: &str, required: bool) -> Value {
    json!({
        "tool": tool,
        "arguments": arguments,
        "why": why,
        "required": required
    })
}

fn workflow_action_targets_project(action: &Value) -> bool {
    match action["tool"].as_str().unwrap_or("") {
        "codelattice_project" | "codelattice_symbol" | "codelattice_change_review" => true,
        "codelattice_workflow" => matches!(
            action["arguments"]["mode"].as_str().unwrap_or(""),
            "before_edit"
                | "diagnose_issue"
                | "explain_symbol"
                | "delete_code"
                | "root_cause"
                | "public_api_change"
                | "framework_route_change"
                | "docs_tests_sync"
                | "config_examples_sync"
        ),
        _ => false,
    }
}

fn workflow_rewrite_actions_for_project(
    actions: &mut [Value],
    selected_root: &str,
    selected_language: &str,
    workspace_root: &str,
) {
    for action in actions {
        if !workflow_action_targets_project(action) {
            continue;
        }
        if let Some(args) = action.get_mut("arguments").and_then(|v| v.as_object_mut()) {
            args.insert("root".to_string(), json!(selected_root));
            args.insert("language".to_string(), json!(selected_language));
            args.insert("workspaceRoot".to_string(), json!(workspace_root));
            args.insert("selectedFromWorkspace".to_string(), json!(true));
        }
    }
}

fn workflow_missing(name: &str, reason: &str, suggestion: &str) -> Value {
    json!({
        "name": name,
        "reason": reason,
        "suggestion": suggestion
    })
}

fn workflow_static_cautions(mode: &str) -> Vec<Value> {
    let mut cautions = vec![
        json!("static analysis only — no runtime proof"),
        json!("scripts executed: false"),
        json!("coverage verified: false"),
    ];
    if mode == "delete_code" {
        cautions.push(json!("NOT deletion-proof: do not delete solely from static reachability/dead-code candidates"));
    }
    if mode == "cross_project_impact" {
        cautions.push(json!(
            "workspace graph impact is heuristic and may include config/script adjacency"
        ));
    }
    if mode == "root_cause" || mode == "diagnose_issue" {
        cautions.push(json!(
            "diagnosis/root-cause hypotheses need runtime or reproduction evidence before being treated as confirmed"
        ));
    }
    cautions
}

fn workflow_action_mode(action: &Value) -> String {
    action["arguments"]["mode"]
        .as_str()
        .unwrap_or("default")
        .to_string()
}

fn workflow_evidence(tool: &str, args: &Value, result: &Value) -> Value {
    let mode = args["mode"].as_str().unwrap_or("default");
    let mut item = json!({
        "tool": tool,
        "mode": mode,
        "ok": true
    });
    if let Some(obj) = item.as_object_mut() {
        if let Some(summary) = result.get("summary") {
            obj.insert("summary".to_string(), summary.clone());
        }
        if let Some(risk) = result.get("risk").or_else(|| result.get("riskLevel")) {
            obj.insert("risk".to_string(), risk.clone());
        }
        if let Some(overall) = result.get("overallRisk").or_else(|| result.get("overall")) {
            obj.insert("overall".to_string(), overall.clone());
        }
        if let Some(count) = result.get("matchCount") {
            obj.insert("matchCount".to_string(), count.clone());
        }
        if let Some(selected) = result.get("selected") {
            obj.insert("selected".to_string(), selected.clone());
        }
        if let Some(metrics) = result.get("impactMetrics") {
            obj.insert("impactMetrics".to_string(), metrics.clone());
        }
        // Include callers/callees summaries if present (before_edit context)
        if let Some(callers) = result.get("callers") {
            if let Some(arr) = callers.as_array() {
                obj.insert("callerCount".to_string(), json!(arr.len()));
            }
        }
        if let Some(callees) = result.get("callees") {
            if let Some(arr) = callees.as_array() {
                obj.insert("calleeCount".to_string(), json!(arr.len()));
            }
        }
        let likely_areas =
            workflow_take_array(result, &[&["result", "likelyAreas"], &["likelyAreas"]], 5);
        if !likely_areas.is_empty() {
            obj.insert("likelyAreas".to_string(), json!(likely_areas));
        }
        let read_first =
            workflow_take_array(result, &[&["result", "readFirst"], &["readFirst"]], 5);
        if !read_first.is_empty() {
            obj.insert("readFirst".to_string(), json!(read_first));
        }
        let entry_points =
            workflow_take_array(result, &[&["result", "entryPoints"], &["entryPoints"]], 5);
        if !entry_points.is_empty() {
            obj.insert("entryPoints".to_string(), json!(entry_points));
        }
        let impact_hints =
            workflow_take_array(result, &[&["result", "impactHints"], &["impactHints"]], 5);
        if !impact_hints.is_empty() {
            obj.insert("impactHints".to_string(), json!(impact_hints));
        }
    }
    item
}

fn execute_workflow_action(cache: &mut McpCache, tool: &str, args: &Value) -> Result<Value, Value> {
    match tool {
        "codelattice_project" => handle_project(cache, args),
        "codelattice_symbol" => handle_symbol(cache, args),
        "codelattice_change_review" => handle_change_review(cache, args),
        "codelattice_cleanup" => handle_cleanup(cache, args),
        "codelattice_workspace" => handle_workspace(cache, args),
        "codelattice_release_check" => handle_release_check(cache, args),
        "codelattice_cache" => handle_cache(cache, args),
        "codelattice_root_cause_assistant" => handle_root_cause_assistant(cache, args),
        _ => Err(mcp_error(
            "unsupported_workflow_action",
            &format!("Workflow executor cannot execute action tool '{tool}'"),
        )),
    }
}

fn workflow_answer_summary(mode: &str, completed: &[Value], failed: &[Value]) -> String {
    if completed.is_empty() && failed.is_empty() {
        return format!("{mode}: no actions were executed.");
    }
    let executed_tools: Vec<&str> = completed
        .iter()
        .filter_map(|c| c["tool"].as_str())
        .collect();
    let tool_list = executed_tools.join(", ");
    if failed.is_empty() {
        format!(
            "{mode}: executed {} CodeLattice action(s) — {}. Review evidence and cautions before editing.",
            completed.len(), tool_list
        )
    } else {
        format!(
            "{mode}: executed {} action(s), {} action(s) failed — {}. Treat the result as partial.",
            completed.len(),
            failed.len(),
            tool_list
        )
    }
}

fn workflow_missing_summary(mode: &str, missing_inputs: &[Value]) -> String {
    let names = missing_inputs
        .iter()
        .filter_map(|m| m["name"].as_str())
        .collect::<Vec<_>>()
        .join(", ");
    format!("{mode}: execution paused because required input is missing ({names}). Follow nextActions to discover it.")
}

fn workflow_array_at<'a>(value: &'a Value, paths: &[&[&str]]) -> Option<&'a Vec<Value>> {
    for path in paths {
        let mut cur = value;
        let mut found = true;
        for segment in *path {
            match cur.get(*segment) {
                Some(next) => cur = next,
                None => {
                    found = false;
                    break;
                }
            }
        }
        if found {
            if let Some(items) = cur.as_array() {
                return Some(items);
            }
        }
    }
    None
}

fn workflow_take_array(value: &Value, paths: &[&[&str]], limit: usize) -> Vec<Value> {
    workflow_array_at(value, paths)
        .map(|items| items.iter().take(limit).cloned().collect())
        .unwrap_or_default()
}

fn workflow_execution_args(tool: &str, args: &Value) -> Value {
    let mut exec_args = args.clone();
    // Diagnosis is intentionally small and benefits from returning readFirst/likelyAreas.
    // Keeping the action compact would hide the exact evidence the workflow report needs.
    if tool == "codelattice_project" && args["mode"].as_str() == Some("diagnose") {
        exec_args["compact"] = json!(false);
    }
    exec_args
}

fn workflow_evidence_found(evidence: &[Value], completed: &[Value]) -> Vec<Value> {
    let mut found = Vec::new();
    for item in evidence {
        let tool = item["tool"].as_str().unwrap_or("unknown");
        let mode = item["mode"].as_str().unwrap_or("default");
        let likely_areas = workflow_take_array(item, &[&["likelyAreas"]], 3);
        let read_first = workflow_take_array(item, &[&["readFirst"]], 3);
        let entry_points = workflow_take_array(item, &[&["entryPoints"]], 3);
        let mut evidence_item = json!({
            "tool": tool,
            "mode": mode,
            "kind": "static_action_result",
            "summary": item.get("summary").cloned().unwrap_or_else(|| json!({})),
            "interpretation": "CodeLattice completed this static facade action. Treat it as an investigation lead, not runtime proof."
        });
        if let Some(obj) = evidence_item.as_object_mut() {
            if !likely_areas.is_empty() {
                obj.insert("likelyAreas".to_string(), json!(likely_areas));
            }
            if !read_first.is_empty() {
                obj.insert("readFirst".to_string(), json!(read_first));
            }
            if !entry_points.is_empty() {
                obj.insert("entryPoints".to_string(), json!(entry_points));
            }
            if let Some(metrics) = item.get("impactMetrics") {
                obj.insert("impactMetrics".to_string(), metrics.clone());
            }
        }
        found.push(evidence_item);
    }

    if found.is_empty() {
        for action in completed {
            found.push(json!({
                "tool": action["tool"].as_str().unwrap_or("unknown"),
                "mode": action["mode"].as_str().unwrap_or("default"),
                "kind": "static_action_completed",
                "interpretation": "The action completed, but no compact evidence fields were exposed."
            }));
        }
    }
    found
}

fn workflow_hypotheses(mode: &str, evidence: &[Value], completed: &[Value]) -> Vec<Value> {
    let mut hypotheses = Vec::new();
    for item in evidence {
        let tool = item["tool"].as_str().unwrap_or("unknown");
        let action_mode = item["mode"].as_str().unwrap_or("default");
        for area in workflow_take_array(item, &[&["likelyAreas"]], 5) {
            hypotheses.push(json!({
                "sourceTool": tool,
                "sourceMode": action_mode,
                "candidate": area.get("name").cloned().unwrap_or_else(|| json!("unknown")),
                "file": area.get("file").cloned().unwrap_or(Value::Null),
                "line": area.get("line").cloned().unwrap_or(Value::Null),
                "confidence": area.get("confidence").cloned().unwrap_or(Value::Null),
                "reason": area.get("reason").cloned().unwrap_or_else(|| json!("static ranking signal")),
                "nextAction": area.get("nextAction").cloned().unwrap_or_else(|| json!("Read this candidate and confirm with targeted tests."))
            }));
        }
    }

    if hypotheses.is_empty() && !completed.is_empty() {
        hypotheses.push(json!({
            "sourceMode": mode,
            "candidate": "static workflow result",
            "confidence": "medium",
            "reason": "Workflow actions completed; inspect evidenceFound before editing.",
            "nextAction": "Read returned evidence and run targeted verification outside CodeLattice."
        }));
    }
    hypotheses
}

fn workflow_read_first(evidence: &[Value], next_actions: &[Value]) -> Vec<Value> {
    let mut read_first = Vec::new();
    for item in evidence {
        let tool = item["tool"].as_str().unwrap_or("unknown");
        let mode = item["mode"].as_str().unwrap_or("default");
        for entry in workflow_take_array(item, &[&["readFirst"]], 8) {
            let mut enriched = entry;
            if let Some(obj) = enriched.as_object_mut() {
                obj.insert("sourceTool".to_string(), json!(tool));
                obj.insert("sourceMode".to_string(), json!(mode));
            }
            read_first.push(enriched);
            if read_first.len() >= 8 {
                return read_first;
            }
        }
    }

    for (idx, action) in next_actions.iter().enumerate().take(5) {
        read_first.push(json!({
            "priority": idx + 1,
            "kind": "tool_action",
            "tool": action["tool"].as_str().unwrap_or("unknown"),
            "mode": action["arguments"]["mode"].as_str().unwrap_or("default"),
            "reason": action["why"].as_str().unwrap_or("Follow this workflow action."),
            "nextAction": "Run or inspect this action before making code changes."
        }));
    }
    read_first
}

fn workflow_evidence_missing(
    mode: &str,
    execute: bool,
    missing_inputs: &[Value],
    failed: &[Value],
    skipped: &[Value],
) -> Vec<Value> {
    let mut missing = vec![
        json!({
            "kind": "runtime_reproduction",
            "status": "not_checked",
            "reason": "CodeLattice does not execute target project code.",
            "nextAction": "Run the smallest reproduction, test, or command outside CodeLattice."
        }),
        json!({
            "kind": "targeted_tests",
            "status": "not_checked",
            "reason": "Static graph analysis is not test or coverage proof.",
            "nextAction": "Run targeted tests for the selected file/symbol before committing."
        }),
        json!({
            "kind": "coverage",
            "status": "not_checked",
            "reason": "Coverage was not measured.",
            "nextAction": "Use coverage/runtime tools if the risk depends on exercised paths."
        }),
    ];

    if !execute {
        missing.push(json!({
            "kind": "workflow_execution",
            "status": "not_requested",
            "reason": "execute=true was not set.",
            "nextAction": "Run codelattice_workflow with execute=true or execute nextActions manually."
        }));
    }
    for item in missing_inputs {
        missing.push(json!({
            "kind": "required_input",
            "status": "missing",
            "name": item["name"].as_str().unwrap_or("unknown"),
            "reason": item["reason"].as_str().unwrap_or("required input missing"),
            "nextAction": item["suggestion"].as_str().unwrap_or("Provide the missing input.")
        }));
    }
    for item in failed {
        missing.push(json!({
            "kind": "failed_action",
            "status": "failed",
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "reason": item.get("error").cloned().unwrap_or_else(|| json!("workflow action failed")),
            "nextAction": "Retry this action directly after checking parameters and root selection."
        }));
    }
    for item in skipped {
        missing.push(json!({
            "kind": "skipped_action",
            "status": "skipped",
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "reason": item["reason"].as_str().unwrap_or("action skipped by workflow executor"),
            "nextAction": "Run this action manually if it is needed for the decision."
        }));
    }
    if mode == "delete_code" {
        missing.push(json!({
            "kind": "deletion_safety",
            "status": "not_proven",
            "reason": "Static dead-code or reachability hints are not deletion proof.",
            "nextAction": "Confirm public API, framework entries, runtime paths, and tests before deleting."
        }));
    }
    missing
}

fn workflow_human_verification_needed(mode: &str) -> Vec<Value> {
    let mut items = vec![
        json!({
            "check": "Read the suggested files/symbols before editing.",
            "why": "Static ranking can point to likely areas but cannot understand intent by itself."
        }),
        json!({
            "check": "Run targeted tests or a reproduction outside CodeLattice.",
            "why": "CodeLattice did not execute target project code."
        }),
        json!({
            "check": "Review graph gaps and low-confidence hints before treating impact as complete.",
            "why": "Framework, dynamic dispatch, generated code, and runtime config may hide edges."
        }),
    ];
    if mode == "before_edit" || mode == "diagnose_issue" {
        items.push(json!({
            "check": "After choosing the likely symbol, run before_edit or impact review on that concrete symbol.",
            "why": "The first workflow pass narrows the area; the second pass estimates blast radius."
        }));
    }
    items
}

fn workflow_next_tool_calls(
    failed: &[Value],
    skipped: &[Value],
    next_actions: &[Value],
) -> Vec<Value> {
    let mut calls = Vec::new();
    for item in failed {
        calls.push(json!({
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "reason": "Retry failed workflow action after checking parameters."
        }));
    }
    for item in skipped {
        calls.push(json!({
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "reason": item["reason"].as_str().unwrap_or("action skipped by workflow executor")
        }));
    }
    if calls.is_empty() {
        for action in next_actions
            .iter()
            .filter(|a| !a["required"].as_bool().unwrap_or(false))
            .take(3)
        {
            calls.push(json!({
                "tool": action["tool"].as_str().unwrap_or("unknown"),
                "mode": action["arguments"]["mode"].as_str().unwrap_or("default"),
                "reason": action["why"].as_str().unwrap_or("Optional follow-up action.")
            }));
        }
    }
    calls
}

fn workflow_ai_decision_trace(
    mode: &str,
    execute: bool,
    missing_inputs: &[Value],
    next_actions: &[Value],
    completed: &[Value],
    failed: &[Value],
    skipped: &[Value],
) -> Vec<Value> {
    let mut trace = vec![json!({
        "event": "workflow_routed",
        "mode": mode,
        "reason": "Matched user intent to a CodeLattice workflow."
    })];
    trace.push(json!({
        "event": if execute { "execution_requested" } else { "execution_not_requested" },
        "actionCount": next_actions.len(),
        "reason": if execute { "execute=true was set." } else { "Caller should follow nextActions manually." }
    }));
    if !missing_inputs.is_empty() {
        trace.push(json!({
            "event": "execution_paused",
            "reason": "Required input is missing.",
            "missingInputs": missing_inputs
        }));
    }
    for item in completed {
        trace.push(json!({
            "event": "action_completed",
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "required": item["required"].as_bool().unwrap_or(false)
        }));
    }
    for item in failed {
        trace.push(json!({
            "event": "action_failed",
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "error": item.get("error").cloned().unwrap_or_else(|| json!("unknown error"))
        }));
    }
    for item in skipped {
        trace.push(json!({
            "event": "action_skipped",
            "tool": item["tool"].as_str().unwrap_or("unknown"),
            "mode": item["mode"].as_str().unwrap_or("default"),
            "reason": item["reason"].as_str().unwrap_or("skipped")
        }));
    }
    trace.push(json!({
        "event": "static_gaps_recorded",
        "reason": "Runtime, targeted tests, and coverage remain outside CodeLattice static analysis."
    }));
    trace
}

fn workflow_investigation_plan(
    mode: &str,
    execution: &Value,
    evidence: &[Value],
    completed: &[Value],
    failed: &[Value],
    skipped: &[Value],
    next_actions: &[Value],
    evidence_found: &[Value],
    evidence_missing: &[Value],
    human_verification: &[Value],
) -> Value {
    json!({
        "schemaVersion": "codelattice.workflowInvestigation.v1",
        "mode": mode,
        "status": execution["status"].as_str().unwrap_or("unknown"),
        "hypotheses": workflow_hypotheses(mode, evidence, completed),
        "readFirst": workflow_read_first(evidence, next_actions),
        "evidenceFound": evidence_found,
        "evidenceMissing": evidence_missing,
        "humanVerificationNeeded": human_verification,
        "nextToolCalls": workflow_next_tool_calls(failed, skipped, next_actions),
        "staticOnly": true,
        "targetCodeExecuted": false
    })
}

fn workflow_execute_next_actions(
    cache: &mut McpCache,
    mode: &str,
    execute: bool,
    missing_inputs: &[Value],
    next_actions: &[Value],
) -> (
    Value,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    String,
) {
    if !execute {
        return (
            json!({"requested": false, "status": "not_requested"}),
            Vec::new(),
            Vec::new(),
            Vec::new(),
            Vec::new(),
            "Execution not requested; follow nextActions manually.".to_string(),
        );
    }
    if !missing_inputs.is_empty() {
        return (
            json!({"requested": true, "status": "needs_input"}),
            Vec::new(),
            Vec::new(),
            Vec::new(),
            Vec::new(),
            workflow_missing_summary(mode, missing_inputs),
        );
    }

    let mut completed = Vec::new();
    let mut failed = Vec::new();
    let mut skipped = Vec::new();
    let mut evidence = Vec::new();

    for action in next_actions {
        let tool = action["tool"].as_str().unwrap_or("");
        let args = workflow_execution_args(tool, &action["arguments"]);
        if tool.is_empty() || tool == "codelattice_workflow" {
            skipped.push(json!({
                "tool": tool,
                "mode": workflow_action_mode(action),
                "reason": "recursive or empty workflow action is not executed automatically"
            }));
            continue;
        }
        match execute_workflow_action(cache, tool, &args) {
            Ok(result) => {
                let inner = unwrap_tool_result(&result);
                completed.push(json!({
                    "tool": tool,
                    "mode": args["mode"].as_str().unwrap_or("default"),
                    "required": action["required"].as_bool().unwrap_or(false)
                }));
                evidence.push(workflow_evidence(tool, &args, &inner));
            }
            Err(err) => {
                failed.push(json!({
                    "tool": tool,
                    "mode": args["mode"].as_str().unwrap_or("default"),
                    "required": action["required"].as_bool().unwrap_or(false),
                    "error": err
                }));
            }
        }
    }

    let status = if failed.is_empty() && !completed.is_empty() {
        "completed"
    } else if !completed.is_empty() {
        "partial"
    } else if !skipped.is_empty() {
        "skipped"
    } else {
        "no_actions"
    };
    let summary = workflow_answer_summary(mode, &completed, &failed);
    (
        json!({"requested": true, "status": status}),
        completed,
        failed,
        skipped,
        evidence,
        summary,
    )
}

fn handle_workflow(cache: &mut McpCache, params: &Value) -> Result<Value, Value> {
    let mode = params["intent"]
        .as_str()
        .or_else(|| params["mode"].as_str())
        .unwrap_or("onboarding");
    let compact = params["compact"].as_bool().unwrap_or(false);
    let execute = params["execute"].as_bool().unwrap_or(false);
    let language = params["language"].as_str().unwrap_or("auto");
    let root = params["root"].as_str().unwrap_or("");
    let symbol = params["symbol"]
        .as_str()
        .or_else(|| params["name"].as_str())
        .unwrap_or("");
    let root_diagnosis = if root.is_empty() {
        json!({"kind": "not_applicable", "explanation": "No root path provided."})
    } else if compact {
        diagnose_root_compact(root, language)
    } else {
        diagnose_root(root, language)
    };
    let root_kind = root_diagnosis
        .get("kind")
        .and_then(|v| v.as_str())
        .unwrap_or("unknown");
    let root_is_workspace = matches!(root_kind, "workspace" | "unsupported_or_mixed_workspace");
    validate_facade_mode(
        mode,
        &[
            "onboarding",
            "explore",
            "before_edit",
            "after_edit",
            "delete_code",
            "release_check",
            "legacy_cleanup",
            "workspace_review",
            "cross_project_impact",
            "diagnose_issue",
            "explain_symbol",
            "root_cause",
            "docs_tests_sync",
            "config_examples_sync",
            "public_api_change",
            "framework_route_change",
            "ask",
        ],
        "codelattice_workflow",
    )?;

    if mode == "ask" {
        let question = params["question"].as_str().unwrap_or("").to_string();
        let ask_compact = compact;
        let ask_execute = execute;
        let ask_job_id = params["jobId"].as_str().unwrap_or("").to_string();
        if !ask_job_id.is_empty() {
            let job_status = crate::mcp_job::get_job_status(&ask_job_id);
            let page = params["page"].as_u64().unwrap_or(0) as usize;
            let page_size = params["pageSize"].as_u64().unwrap_or(50) as usize;
            let job_detail = crate::mcp_job::MCP_JOBS.get_detail_page(
                &ask_job_id,
                page,
                page_size.clamp(1, 200),
            );

            match (job_status, job_detail) {
                (Some(status), Some(detail)) => {
                    let job_id = status["jobId"].as_str().unwrap_or(&ask_job_id);
                    let job_status_val = status["status"].as_str().unwrap_or("unknown");
                    let total_items = detail["totalItems"].as_u64().unwrap_or(0);
                    let has_more = detail["hasMore"].as_bool().unwrap_or(false);
                    let summary = detail["summary"].as_str().unwrap_or("Job completed");
                    let items_on_page = detail["items"].as_array().map(|a| a.len()).unwrap_or(0);
                    let job_root = status["root"].as_str().unwrap_or(root);
                    let job_language = status["language"].as_str().unwrap_or(language);

                    let answer_summary = format!(
                        "Job {} ({}): {} total items, page {} shows {} items. {}",
                        job_id, job_status_val, total_items, page, items_on_page, summary
                    );

                    let mut next_actions = Vec::new();
                    if has_more {
                        next_actions.push(json!({
                            "tool": "codelattice_workflow",
                            "mode": "ask",
                            "why": "Continue reading next page of job results",
                            "arguments": {"jobId": job_id, "root": job_root, "language": job_language, "page": page + 1, "pageSize": page_size, "compact": true}
                        }));
                    }
                    next_actions.push(json!({
                        "tool": "codelattice_project",
                        "mode": "job_status",
                        "why": "Check current job status",
                        "arguments": {"jobId": job_id, "root": job_root, "language": job_language, "compact": true}
                    }));
                    if let Some(q) = question.strip_prefix("继续") {
                        if !q.trim().is_empty() {
                            next_actions.push(json!({
                                "tool": "codelattice_symbol",
                                "mode": "call_chains",
                                "why": "Dive deeper into specific symbols",
                                "arguments": {"query": q.trim(), "root": job_root, "language": job_language, "direction": "both", "maxDepth": 4, "compact": true}
                            }));
                        }
                    }

                    let job_followup = json!({
                        "schemaVersion": "codelattice.ask.v2",
                        "intent": "job_followup",
                        "question": question,
                        "targetQuery": null,
                        "answerSummary": answer_summary,
                        "orchestration": {"stepsAttempted": ["job_status:read", "job_detail:read"], "stepsSkipped": []},
                        "job": {
                            "submitted": true,
                            "jobId": job_id,
                            "status": job_status_val,
                            "detailPageHint": format!("codelattice_project(mode=job_detail, jobId={}, page={}, pageSize={})", job_id, page, page_size)
                        },
                        "jobDigest": {
                            "totalItems": total_items,
                            "page": page,
                            "pageSize": page_size,
                            "hasMore": has_more,
                            "summary": summary
                        },
                        "callChains": [],
                        "readOrder": [],
                        "projectDigest": Value::Null,
                        "triagePlan": Value::Null,
                        "whatIf": Value::Null,
                        "filesInvolved": [],
                        "missingEvidence": [{"kind": "static_only", "explanation": "Job results are from static analysis. No runtime execution or test verification was performed."}],
                        "recommendedNextCalls": next_actions,
                        "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false, "runtimeVerified": false, "scriptsExecuted": false},
                        "generatedFrom": {"engine": "intent-router", "version": "v2"}
                    });
                    let text = serde_json::to_string_pretty(&job_followup)
                        .unwrap_or_else(|_| job_followup.to_string());
                    return Ok(json!({"content": [{"type": "text", "text": text}]}));
                }
                _ => {
                    let err_result = json!({
                        "schemaVersion": "codelattice.ask.v2",
                        "intent": "job_followup_error",
                        "question": question,
                        "targetQuery": null,
                        "answerSummary": format!("Job '{}' not found or has no detail pages.", ask_job_id),
                        "orchestration": {"stepsAttempted": ["job_status:lookup"], "stepsSkipped": ["job_detail:not_found"]},
                        "job": {"submitted": false, "jobId": ask_job_id, "error": "Job not found in registry"},
                        "jobDigest": Value::Null,
                        "callChains": [],
                        "readOrder": [],
                        "projectDigest": Value::Null,
                        "triagePlan": Value::Null,
                        "whatIf": Value::Null,
                        "filesInvolved": [],
                        "missingEvidence": [{"kind": "job_not_found", "explanation": format!("No job with ID '{}' found. Submit a new analysis first.", ask_job_id)}],
                        "recommendedNextCalls": [{"tool": "codelattice_workflow", "mode": "ask", "why": "Ask a new question to start fresh", "arguments": {"question": question}}],
                        "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false, "runtimeVerified": false, "scriptsExecuted": false},
                        "generatedFrom": {"engine": "intent-router", "version": "v2"}
                    });
                    let text = serde_json::to_string_pretty(&err_result)
                        .unwrap_or_else(|_| err_result.to_string());
                    return Ok(json!({"content": [{"type": "text", "text": text}]}));
                }
            }
        }

        if question.is_empty() {
            let empty_result = json!({
                "schemaVersion": "codelattice.ask.v2",
                "intent": "unknown",
                "question": "",
                "targetQuery": null,
                "answerSummary": "No question provided.",
                "orchestration": {"stepsAttempted": [], "stepsSkipped": []},
                "callChains": [],
                "readOrder": [],
                "filesInvolved": [],
                "missingEvidence": [{"kind": "missing_input", "explanation": "question parameter is required"}],
                "recommendedNextCalls": [{"tool": "codelattice_workflow", "mode": "ask", "why": "Retry with a question", "arguments": {"question": "your question here"}}],
                "analysisSemantics": {"staticAnalysis": true, "targetCodeExecuted": false, "runtimeVerified": false, "scriptsExecuted": false},
                "generatedFrom": {"engine": "intent-router", "version": "v2"}
            });
            let empty_text = serde_json::to_string_pretty(&empty_result)
                .unwrap_or_else(|_| empty_result.to_string());
            return Ok(json!({
                "content": [{"type": "text", "text": empty_text}],
            }));
        }

        let mut ask_root = root.to_string();
        let mut ask_language = language.to_string();
        let mut ask_root_router = Value::Null;
        if root_is_workspace {
            let mut route_params = params.clone();
            if workspace_route_query(&route_params).is_empty() {
                let question_query = extract_symbol_from_question(&question);
                if let Some(obj) = route_params.as_object_mut() {
                    if !question_query.is_empty() {
                        obj.insert("query".to_string(), json!(question_query));
                    } else {
                        obj.insert("query".to_string(), json!(question.clone()));
                    }
                }
            }
            if let Some(route_result) = workspace_auto_route_decision(
                cache,
                root,
                language,
                &route_params,
                "codelattice_workflow",
                "ask",
            ) {
                match route_result {
                    Ok(route) => {
                        ask_root = route.selected_root;
                        ask_language = route.selected_language;
                        ask_root_router = route.router;
                    }
                    Err(guidance) => {
                        ask_root_router = guidance
                            .get("rootRouter")
                            .cloned()
                            .unwrap_or_else(|| Value::Null);
                    }
                }
            }
        }
        let ask_root_ref = ask_root.as_str();
        let ask_language_ref = ask_language.as_str();
        let ask_request_context = if ask_root_ref.is_empty() {
            Value::Null
        } else if ask_root_router.is_null() {
            FacadeRequestContext::unrouted(
                "codelattice_workflow",
                "ask",
                root,
                language,
                ask_language_ref,
                ask_compact,
            )
            .to_json()
        } else {
            FacadeRequestContext::new(
                "codelattice_workflow",
                "ask",
                root,
                ask_root_ref,
                language,
                ask_language_ref,
                ask_compact,
                ask_root_router.clone(),
            )
            .to_json()
        };

        let (
            intent,
            answer_summary,
            target_query,
            evidence,
            call_chains,
            _read_first,
            missing_evidence,
            files_involved,
            read_order,
            triage_plan,
            project_digest,
            orchestration,
            auto_job,
            next_actions,
            ai_guidance,
            confidence,
        ) = route_ask_intent(
            cache,
            ask_root_ref,
            ask_language_ref,
            &question,
            ask_compact,
            ask_execute,
        );

        let what_if = if intent == "before_edit" || intent == "whatif" {
            let query = target_query.as_ref().unwrap_or(&String::new()).clone();
            if !ask_root_ref.is_empty() && !query.is_empty() {
                if let Some((file_count, sample_files)) =
                    ask_large_project_info(ask_root_ref, ask_language_ref)
                {
                    build_deferred_whatif_value(
                        ask_root_ref,
                        ask_language_ref,
                        &question,
                        &query,
                        file_count,
                        &sample_files,
                    )
                } else {
                    let (ci, tc, di, ii, risk, sa, tests, rf, me, _na, ap) = build_whatif_result(
                        ask_root_ref,
                        ask_language_ref,
                        &question,
                        &query,
                        "",
                        "",
                    );
                    json!({
                        "schemaVersion": "codelattice.whatIf.v1",
                        "changeIntent": ci,
                        "targetCandidates": tc,
                        "directImpact": di,
                        "indirectImpact": ii.into_iter().take(5).collect::<Vec<_>>(),
                        "risk": risk,
                        "safeAlternatives": sa,
                        "testsToRun": tests,
                        "readFirst": rf,
                        "evidenceGaps": me,
                        "actionPlan": ap,
                        "analysisSemantics": {
                            "staticAnalysisExecuted": true,
                            "targetCodeExecuted": false,
                            "runtimeVerified": false,
                            "scriptsExecuted": false
                        }
                    })
                }
            } else {
                Value::Null
            }
        } else {
            Value::Null
        };

        let mut ask_result = json!({
            "schemaVersion": "codelattice.ask.v2",
            "intent": intent,
            "question": question,
            "root": if root.is_empty() { Value::Null } else { json!(root) },
            "language": language,
            "effectiveRoot": if ask_root_ref.is_empty() { Value::Null } else { json!(ask_root_ref) },
            "effectiveLanguage": ask_language_ref,
            "rootRouter": ask_root_router,
            "requestContext": ask_request_context,
            "runtimeCapabilities": facade_language_runtime_capabilities(ask_language_ref),
            "targetQuery": target_query,
            "answerSummary": answer_summary,
            "evidence": evidence.into_iter().take(5).collect::<Vec<_>>(),
            "confidence": confidence,
            "aiGuidance": ai_guidance,
            "orchestration": orchestration,
            "job": auto_job,
            "callChains": call_chains,
            "readOrder": read_order,
            "projectDigest": project_digest,
            "triagePlan": triage_plan,
            "whatIf": what_if,
            "filesInvolved": files_involved,
            "missingEvidence": missing_evidence,
            "recommendedNextCalls": next_actions,
            "analysisSemantics": {
                "staticAnalysis": true,
                "targetCodeExecuted": false,
                "runtimeVerified": false,
                "scriptsExecuted": false
            },
            "generatedFrom": {
                "engine": "intent-router",
                "version": "v2"
            }
        });
        if ask_compact {
            if let Some(obj) = ask_result.as_object_mut() {
                obj.insert(
                    "omitted".to_string(),
                    json!([
                        {"field": "full project graph", "reason": "ask compact mode returns direct evidence and follow-up calls instead"},
                        {"field": "runtime proof", "reason": "ask uses static analysis only"}
                    ]),
                );
            }
            let estimated_bytes = serde_json::to_string(&ask_result)
                .map(|s| s.len())
                .unwrap_or(0);
            if let Some(obj) = ask_result.as_object_mut() {
                obj.insert(
                    "tokenBudget".to_string(),
                    json!({
                        "used": estimated_bytes,
                        "max": 16 * 1024,
                        "estimated": true,
                        "policy": "compact ask responses should stay within the AI decision budget"
                    }),
                );
            }
        }
        let ask_text =
            serde_json::to_string_pretty(&ask_result).unwrap_or_else(|_| ask_result.to_string());
        return Ok(json!({
            "content": [{"type": "text", "text": ask_text}],
        }));
    }

    let mut missing_inputs: Vec<Value> = Vec::new();
    let mut next_actions: Vec<Value> = Vec::new();
    let mut findings: Vec<Value> = Vec::new();
    let mut underlying = vec!["codelattice_workflow_presets"];
    let mut risk_level = "low";
    let situation;
    let human_review_needed = true;
    let mut root_router = Value::Null;

    if root.is_empty() {
        missing_inputs.push(workflow_missing(
            "root",
            "Most CodeLattice analysis actions need a project or workspace root.",
            "Pass root as an absolute project/workspace path.",
        ));
    }

    match mode {
        "explore" => {
            let depth = workflow_explore_depth(params);
            let focus = params["focus"].as_str().unwrap_or("");
            risk_level = "low";
            situation = if root_is_workspace {
                "Progressive workspace exploration: start with project selection, then drill into one project root."
            } else {
                "Progressive project exploration: start with a compact map, then deepen only when needed."
            };
            if root_is_workspace {
                next_actions.push(workflow_action(
                    "codelattice_workspace",
                    json!({"mode":"overview","root":root,"compact":true}),
                    "Summarize workspace shape and choose likely main project roots.",
                    true,
                ));
                if let Some(args) = workflow_recommended_project_args(
                    root,
                    language,
                    &root_diagnosis,
                    workflow_project_mode_for_depth(depth),
                ) {
                    next_actions.push(workflow_action(
                        "codelattice_project",
                        args,
                        "Get the quick AI map for the top recommended project root.",
                        false,
                    ));
                } else {
                    next_actions.push(workflow_action(
                        "codelattice_project",
                        json!({"mode":"quick","root":"<choose from rootDiagnosis.recommendedProjectRoots>","language":"auto","compact":true}),
                        "After choosing a concrete subproject, get the quick AI project map.",
                        false,
                    ));
                }
            } else {
                let mut args =
                    workflow_base_args(root, language, workflow_project_mode_for_depth(depth));
                args["compact"] = json!(true);
                if !focus.is_empty() {
                    args["focus"] = json!(focus);
                }
                next_actions.push(workflow_action(
                    "codelattice_project",
                    args,
                    "Get the progressive project map for this depth.",
                    true,
                ));
                if depth < 3 {
                    next_actions.push(workflow_action(
                        "codelattice_workflow",
                        json!({"mode":"explore","root":root,"language":language,"depth":depth + 1,"focus":focus,"compact":true}),
                        "Go one level deeper after reading the first recommendations.",
                        false,
                    ));
                }
            }
            underlying = vec![
                "codelattice_project_insights",
                "codelattice_workspace_graph",
            ];
        }
        "onboarding" => {
            situation = "Start with a project map, then inspect hotspots and read-first files.";
            next_actions.push(workflow_action(
                "codelattice_project",
                workflow_base_args(root, language, "quick"),
                "Get the compact AI project map first; deepen only if needed.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_workflow",
                json!({"mode":"before_edit","root":root,"language":language,"compact":true}),
                "Use this after choosing a symbol or file to change.",
                false,
            ));
        }
        "before_edit" => {
            risk_level = if symbol.is_empty() {
                "unknown"
            } else {
                "medium"
            };
            situation = if symbol.is_empty() {
                "Before-edit review needs a target symbol. I will route you to symbol discovery instead of failing."
            } else {
                "Before editing, inspect symbol context and impact radius first."
            };
            if symbol.is_empty() {
                missing_inputs.push(workflow_missing(
                    "symbol",
                    "Impact preview needs the symbol you plan to edit.",
                    "Run codelattice_symbol mode=search, then retry before_edit with symbol.",
                ));
                let mut search_args = workflow_base_args(root, language, "search");
                search_args["query"] = json!("");
                next_actions.push(workflow_action(
                    "codelattice_symbol",
                    search_args,
                    "Find candidate symbols before choosing an edit target.",
                    true,
                ));
            } else {
                let mut ctx_args = workflow_base_args(root, language, "context");
                ctx_args["name"] = json!(symbol);
                next_actions.push(workflow_action(
                    "codelattice_symbol",
                    ctx_args,
                    "Read the exact symbol location, snippet, docs, and candidates.",
                    true,
                ));
                let mut impact_args = workflow_base_args(root, language, "impact");
                impact_args["symbol"] = json!(symbol);
                next_actions.push(workflow_action(
                    "codelattice_change_review",
                    impact_args,
                    "Estimate blast radius and risk reasons before editing.",
                    true,
                ));
                let mut callers_args = workflow_base_args(root, language, "callers");
                callers_args["name"] = json!(symbol);
                next_actions.push(workflow_action(
                    "codelattice_symbol",
                    callers_args,
                    "Inspect direct callers that may need updates.",
                    false,
                ));
            }
        }
        "after_edit" => {
            risk_level = "medium";
            situation = "After editing, derive changed symbols, then check impact, docs/tests/config consistency, and release readiness.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "native_review"),
                "Auto-detect changed symbols and produce a static review checklist.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "docs_tests"),
                "Check whether docs and tests appear stale or missing.",
                false,
            ));
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "config_examples"),
                "Check configs/examples for stale references after the edit.",
                false,
            ));
        }
        "delete_code" => {
            risk_level = "high";
            situation = "Deletion requires conservative review: dead-code signals are investigation leads, not deletion proof.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "safe_cleanup_review"),
                "Combine dead code, reachability, public API, and framework entry signals.",
                true,
            ));
            if symbol.is_empty() {
                missing_inputs.push(workflow_missing(
                    "symbol",
                    "Deletion review is stronger when the candidate symbol is known.",
                    "Pass symbol when reviewing a specific deletion.",
                ));
            } else {
                let mut impact_args = workflow_base_args(root, language, "impact");
                impact_args["symbol"] = json!(symbol);
                next_actions.push(workflow_action(
                    "codelattice_change_review",
                    impact_args,
                    "Check callers and downstream impact before deleting the symbol.",
                    true,
                ));
            }
        }
        "release_check" => {
            risk_level = "medium";
            situation = "Release check should combine quality, compatibility, docs/tests, and config/example consistency.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "release_check"),
                "Run the consolidated release review.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "full_review"),
                "Review current diff for breaking-change and consistency risks.",
                false,
            ));
        }
        "legacy_cleanup" => {
            risk_level = "medium";
            situation = "Legacy cleanup starts with hotspots/read-first areas, then uses conservative cleanup review.";
            next_actions.push(workflow_action(
                "codelattice_project",
                workflow_base_args(root, language, "insights"),
                "Identify hotspots, read-first files, and low-confidence zones.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "safe_cleanup_review"),
                "Review cleanup candidates without treating them as safe-to-delete proof.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_workspace",
                json!({"mode":"graph","root":root,"compact":true}),
                "If this is a multi-project workspace, inspect cross-project boundaries.",
                false,
            ));
        }
        "workspace_review" => {
            situation = "Workspace review starts with the cross-project graph, then drills into risky project boundaries.";
            next_actions.push(workflow_action(
                "codelattice_workspace",
                json!({"mode":"graph","root":root,"compact":true}),
                "Build the static cross-project graph.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_workspace",
                json!({"mode":"overview","root":root,"compact":true}),
                "Summarize the workspace graph before choosing targets.",
                false,
            ));
        }
        "cross_project_impact" => {
            underlying = vec![
                "codelattice_workspace_graph",
                "codelattice_cross_project_impact",
            ];
            let target = params.get("target").cloned().unwrap_or(Value::Null);
            if target.is_null() || target.as_object().map(|o| o.is_empty()).unwrap_or(true) {
                risk_level = "unknown";
                situation = "Cross-project impact needs a target. I will route you to the workspace graph to choose one.";
                missing_inputs.push(workflow_missing(
                    "target",
                    "Impact traversal needs nodeId, projectId, path, or query.",
                    "Run codelattice_workspace mode=graph, then retry with target.",
                ));
                next_actions.push(workflow_action(
                    "codelattice_workspace",
                    json!({"mode":"graph","root":root,"compact":true}),
                    "List projects/configs/scripts and choose a stable target.",
                    true,
                ));
            } else {
                risk_level = "medium";
                situation = "Cross-project target provided. Traverse workspace graph to estimate affected projects and boundaries.";
                next_actions.push(workflow_action(
                    "codelattice_workspace",
                    json!({"mode":"impact","root":root,"target":target,"direction":"both","maxDepth":3,"compact":true}),
                    "Run cross-project impact from the target.",
                    true,
                ));
            }
        }
        "diagnose_issue" => {
            let symptom = params["symptom"]
                .as_str()
                .or_else(|| params["errorText"].as_str())
                .or_else(|| params["query"].as_str())
                .or_else(|| params["issue"].as_str())
                .or_else(|| params["observedError"].as_str())
                .unwrap_or("");
            let changed_path = params["changedPath"].as_str().unwrap_or("");
            risk_level = if symptom.is_empty() && changed_path.is_empty() {
                "unknown"
            } else {
                "medium"
            };
            situation = if symptom.is_empty() && changed_path.is_empty() {
                "Issue diagnosis needs a symptom, errorText, query, or changedPath."
            } else {
                "Diagnose likely files/symbols to read first from the static graph."
            };
            if symptom.is_empty() && changed_path.is_empty() {
                missing_inputs.push(workflow_missing(
                    "symptom",
                    "Diagnosis needs at least a symptom, errorText, query, changedPath, issue, or observedError.",
                    "Pass symptom/errorText/query or changedPath, then retry diagnose_issue.",
                ));
            }
            let mut diag_args = workflow_base_args(root, language, "diagnose");
            if !symptom.is_empty() {
                diag_args["symptom"] = json!(symptom);
            }
            if let Some(error_text) = params["errorText"].as_str() {
                diag_args["errorText"] = json!(error_text);
            }
            if let Some(query) = params["query"].as_str() {
                diag_args["query"] = json!(query);
            }
            if !changed_path.is_empty() {
                diag_args["changedPath"] = json!(changed_path);
            }
            if execute && !root.is_empty() && (!symptom.is_empty() || !changed_path.is_empty()) {
                let diag_result = execute_workflow_action(cache, "codelattice_project", &diag_args);
                match diag_result {
                    Ok(diag_value) => {
                        let diag_facade = unwrap_tool_result(&diag_value);
                        let diag_summary = diag_facade.get("summary");
                        let diag_top_areas = diag_summary
                            .and_then(|s| s.get("topLikelyAreas").and_then(|a| a.as_array()))
                            .map(|arr| arr.iter().take(3).cloned().collect::<Vec<_>>())
                            .unwrap_or_default();
                        let diag_risk = diag_summary
                            .and_then(|s| s["riskLevel"].as_str())
                            .unwrap_or("unknown");
                        let diag_area_count = diag_summary
                            .and_then(|s| s.get("likelyAreaCount").cloned())
                            .unwrap_or(json!(0));
                        findings.push(json!({
                            "tool": "codelattice_project",
                            "mode": "diagnose",
                            "riskLevel": diag_risk,
                            "likelyAreaCount": diag_area_count,
                            "topAreas": diag_top_areas
                        }));
                    }
                    Err(e) => {
                        missing_inputs.push(json!({
                            "kind": "diagnosis_failed",
                            "explanation": format!("Project diagnosis failed: {}", e["message"].as_str().unwrap_or("unknown error"))
                        }));
                    }
                }
            }
            next_actions.push(workflow_action(
                "codelattice_project",
                diag_args,
                "Rank likely files/symbols, read-first order, and static impact hints.",
                true,
            ));
            next_actions.push(workflow_action(
                "codelattice_workflow",
                json!({"mode":"before_edit","root":root,"language":language,"compact":true}),
                "After choosing a likely symbol, run before_edit before modifying code.",
                false,
            ));
        }
        "explain_symbol" => {
            risk_level = "low";
            situation = if symbol.is_empty() {
                "Symbol explanation needs a symbol name. I will route you to symbol search first."
            } else {
                "Explain a symbol by reading context, callers, and callees."
            };
            if symbol.is_empty() {
                missing_inputs.push(workflow_missing(
                    "symbol",
                    "Symbol explanation needs a symbol/name.",
                    "Run codelattice_symbol mode=search or pass name/symbol directly.",
                ));
                let mut search_args = workflow_base_args(root, language, "search");
                search_args["query"] = json!("");
                next_actions.push(workflow_action(
                    "codelattice_symbol",
                    search_args,
                    "Find candidate symbols to explain.",
                    true,
                ));
            } else {
                for (mode_name, why) in [
                    ("context", "Read source snippet and related docs."),
                    ("callers", "Find who calls this symbol."),
                    ("callees", "Find what this symbol calls."),
                ] {
                    let mut args = workflow_base_args(root, language, mode_name);
                    args["name"] = json!(symbol);
                    next_actions.push(workflow_action("codelattice_symbol", args, why, true));
                }
            }
        }
        "root_cause" => {
            let issue = params["issue"]
                .as_str()
                .or_else(|| params["observedError"].as_str())
                .unwrap_or("");
            risk_level = if issue.is_empty() {
                "unknown"
            } else {
                "medium"
            };
            situation = if issue.is_empty() {
                "Root-cause analysis needs a bug report or observed symptom. I will ask for the smallest useful issue description."
            } else {
                "Use static graph evidence plus already-granted AI capabilities to form root-cause hypotheses and the next evidence action."
            };
            if issue.is_empty() {
                missing_inputs.push(workflow_missing(
                    "issue",
                    "Root-cause evidence planning needs the observed symptom, error, or debugging question.",
                    "Pass issue or observedError with the failing behavior.",
                ));
            }
            let mut args = workflow_base_args(root, language, "root_cause");
            args["issue"] = json!(issue);
            if let Some(caps) = params.get("availableCapabilities") {
                args["availableCapabilities"] = caps.clone();
            }
            if let Some(evidence) = params.get("runtimeEvidence") {
                args["runtimeEvidence"] = evidence.clone();
            }
            next_actions.push(workflow_action(
                "codelattice_change_review",
                args,
                "Create hypotheses, evidence gaps, and the smallest next evidence action without re-asking for already granted permissions.",
                true,
            ));
        }
        "docs_tests_sync" => {
            risk_level = "medium";
            situation = "Check whether documentation and tests appear synchronized with the current change.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "docs_tests"),
                "Review stale/missing docs and related tests.",
                true,
            ));
        }
        "config_examples_sync" => {
            risk_level = "medium";
            situation = "Check whether configs and examples still point at existing files/symbols.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "config_examples"),
                "Review package/tsconfig/examples/CI/Docker references.",
                true,
            ));
        }
        "public_api_change" => {
            risk_level = "high";
            situation = "Public API changes need compatibility and release-note review.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "external_api"),
                "Identify public/external API surface signals.",
                true,
            ));
            let mut breaking_args = workflow_base_args(root, language, "breaking_change");
            if !symbol.is_empty() {
                breaking_args["changedSymbols"] = json!([symbol]);
            } else {
                missing_inputs.push(workflow_missing(
                    "symbol",
                    "Public API review is stronger with the symbol that will change.",
                    "Pass symbol, or follow external_api_surface results to choose a public symbol.",
                ));
            }
            next_actions.push(workflow_action(
                "codelattice_change_review",
                breaking_args,
                "Review compatibility and release-note risk.",
                true,
            ));
        }
        "framework_route_change" => {
            risk_level = "high";
            situation = "Framework routes/callbacks are often called implicitly, so static reachability can under-report them.";
            next_actions.push(workflow_action(
                "codelattice_change_review",
                workflow_base_args(root, language, "framework_entries"),
                "Find route/callback/lifecycle entry hints.",
                true,
            ));
            let mut breaking_args = workflow_base_args(root, language, "breaking_change");
            if !symbol.is_empty() {
                breaking_args["changedSymbols"] = json!([symbol]);
            } else {
                missing_inputs.push(workflow_missing(
                    "symbol",
                    "Framework route/callback review is stronger with the entry symbol.",
                    "Pass symbol after inspecting framework entry hints.",
                ));
            }
            next_actions.push(workflow_action(
                "codelattice_change_review",
                breaking_args,
                "Review route/callback compatibility risk.",
                false,
            ));
        }
        _ => unreachable!(),
    }

    let symbol_project_workflow = matches!(
        mode,
        "before_edit"
            | "diagnose_issue"
            | "explain_symbol"
            | "delete_code"
            | "root_cause"
            | "public_api_change"
            | "framework_route_change"
            | "docs_tests_sync"
            | "config_examples_sync"
    );
    if root_is_workspace && symbol_project_workflow {
        let route = workspace_auto_route_decision(
            cache,
            root,
            language,
            params,
            "codelattice_workflow",
            mode,
        );
        if let Some(Ok(route)) = route {
            findings.push(json!(format!(
                "Workspace root auto-routed to project root {} for {}.",
                route.selected_root, mode
            )));
            workflow_rewrite_actions_for_project(
                &mut next_actions,
                &route.selected_root,
                &route.selected_language,
                root,
            );
            root_router = route.router;
        } else {
            findings.push(json!(
                "The provided root is a workspace root. Symbol-level actions need a specific project root; workspace actions remain available."
            ));
            missing_inputs.push(workflow_missing(
                "projectRoot",
                "This workflow needs a single project root before using codelattice_symbol or project-level change review.",
                "Choose one entry from rootDiagnosis.recommendedProjectRoots, or run codelattice_workspace mode=graph first.",
            ));
            let mut workspace_actions = vec![workflow_action(
                "codelattice_workspace",
                json!({"mode":"graph","root":root,"compact":true}),
                "Inspect the workspace graph and choose the concrete project root before symbol-level analysis.",
                true,
            )];
            if !symbol.is_empty() {
                workspace_actions.push(workflow_action(
                    "codelattice_workspace",
                    json!({"mode":"impact","root":root,"target":{"query":symbol},"direction":"both","maxDepth":3,"compact":true}),
                    "Optional: estimate cross-project impact from a workspace-level query while choosing the project root.",
                    false,
                ));
            }
            next_actions = workspace_actions;
            risk_level = "unknown";
            if !underlying.contains(&"codelattice_workspace_graph") {
                underlying.push("codelattice_workspace_graph");
            }
        }
    }

    if missing_inputs.is_empty() {
        findings.push(json!(
            "All required routing inputs for this intent are present."
        ));
    } else {
        findings.push(json!(
            "Some inputs are missing; nextActions include discovery calls instead of failing."
        ));
    }

    let (execution, completed_actions, failed_actions, skipped_actions, evidence, answer_summary) =
        workflow_execute_next_actions(cache, mode, execute, &missing_inputs, &next_actions);
    let evidence_found = workflow_evidence_found(&evidence, &completed_actions);
    let evidence_missing = workflow_evidence_missing(
        mode,
        execute,
        &missing_inputs,
        &failed_actions,
        &skipped_actions,
    );
    let human_verification_needed = workflow_human_verification_needed(mode);
    let investigation_plan = workflow_investigation_plan(
        mode,
        &execution,
        &evidence,
        &completed_actions,
        &failed_actions,
        &skipped_actions,
        &next_actions,
        &evidence_found,
        &evidence_missing,
        &human_verification_needed,
    );
    let ai_decision_trace = workflow_ai_decision_trace(
        mode,
        execute,
        &missing_inputs,
        &next_actions,
        &completed_actions,
        &failed_actions,
        &skipped_actions,
    );
    let exploration_plan = if mode == "explore" {
        build_workflow_exploration_plan(
            root,
            language,
            workflow_explore_depth(params),
            params["focus"].as_str().unwrap_or(""),
            &root_diagnosis,
            &evidence,
        )
    } else {
        Value::Null
    };
    let workflow_effective_root = root_router["selectedRoot"].as_str().unwrap_or(root);
    let workflow_effective_language = root_router["selectedLanguage"].as_str().unwrap_or(language);
    let workflow_request_context = if root.is_empty() {
        Value::Null
    } else if root_router.is_null() {
        FacadeRequestContext::unrouted(
            "codelattice_workflow",
            mode,
            root,
            language,
            workflow_effective_language,
            compact,
        )
        .to_json()
    } else {
        FacadeRequestContext::new(
            "codelattice_workflow",
            mode,
            root,
            workflow_effective_root,
            language,
            workflow_effective_language,
            compact,
            root_router.clone(),
        )
        .to_json()
    };

    let mut out = json!({
        "schemaVersion": "ai.workflow.v1",
        "tool": "codelattice_workflow",
        "mode": mode,
        "language": language,
        "root": if root.is_empty() { Value::Null } else { json!(root) },
        "effectiveRoot": if workflow_effective_root.is_empty() { Value::Null } else { json!(workflow_effective_root) },
        "effectiveLanguage": workflow_effective_language,
        "rootDiagnosis": root_diagnosis,
        "rootRouter": root_router,
        "requestContext": workflow_request_context,
        "analysisSemantics": build_analysis_semantics(),
        "runtimeCapabilities": facade_language_runtime_capabilities(workflow_effective_language),
        "situation": situation,
        "riskLevel": risk_level,
        "confidence": "medium",
        "findings": findings,
        "missingInputs": missing_inputs,
        "nextActions": next_actions,
        "execution": execution,
        "completedActions": completed_actions,
        "failedActions": failed_actions,
        "skippedActions": skipped_actions,
        "evidence": evidence,
        "evidenceFound": evidence_found,
        "evidenceMissing": evidence_missing,
        "humanVerificationNeeded": human_verification_needed,
        "investigationPlan": investigation_plan,
        "explorationPlan": exploration_plan,
        "aiDecisionTrace": ai_decision_trace,
        "answerSummary": answer_summary,
        "cautions": workflow_static_cautions(mode),
        "humanReviewNeeded": human_review_needed,
        "safeToProceed": if mode == "delete_code" { "no" } else { "unknown" },
        "generatedFrom": {
            "staticAnalysis": true,
            "runtimeVerified": false,
            "scriptsExecuted": false,
            "coverageVerified": false,
            "analysisExecuted": false,
            "routerOnly": true
        },
        "compact": compact,
        "underlyingTools": underlying
    });
    if compact {
        if let Some(obj) = out.as_object_mut() {
            obj.insert(
                "omitted".to_string(),
                json!([
                    {"field": "rootDiagnosis.sourceOnlyEntries", "reason": "compact workflow output keeps root summaries and routing hints"},
                    {"field": "completedActions.fullPayloads", "reason": "workflow compact output keeps evidence summaries and nextActions"}
                ]),
            );
        }
        let estimated_bytes = serde_json::to_string(&out).map(|s| s.len()).unwrap_or(0);
        if let Some(obj) = out.as_object_mut() {
            obj.insert(
                "tokenBudget".to_string(),
                json!({
                    "used": estimated_bytes,
                    "max": 16 * 1024,
                    "estimated": true,
                    "policy": "compact workflow responses should stay within the AI decision budget"
                }),
            );
        }
    }
    Ok(tool_result(&out))
}

pub fn run_mcp_server() -> Result<(), String> {
    eprintln!("[mcp] CodeLattice MCP v0.8 server starting on stdin/stdout");

    let cache = Arc::new(Mutex::new(McpCache::new()));

    // 注册全局 facade 缓存预热器：job worker 完成后把分析结果灌入 McpCache
    crate::mcp_job::register_facade_cache(Box::new(McpCacheWarmer {
        cache: Arc::clone(&cache),
    }));

    let active_tool_calls = Arc::new(AtomicUsize::new(0));
    let (request_tx, request_rx) = mpsc::channel::<Option<String>>();
    let (response_tx, response_rx) = mpsc::channel::<Value>();

    thread::spawn(move || {
        let stdin = std::io::stdin();
        let mut stdin = stdin.lock();
        let mut line = String::new();
        loop {
            line.clear();
            match stdin.read_line(&mut line) {
                Ok(0) => {
                    let _ = request_tx.send(None);
                    break;
                }
                Ok(_) => {
                    if request_tx.send(Some(line.clone())).is_err() {
                        break;
                    }
                }
                Err(e) => {
                    eprintln!("[mcp] stdin read error: {e}");
                    let _ = request_tx.send(None);
                    break;
                }
            }
        }
    });

    let mut stdout = std::io::stdout();
    let mut stdin_eof = false;

    loop {
        while let Ok(response) = response_rx.try_recv() {
            let response_str = serde_json::to_string(&response).unwrap_or_default();
            let _ = writeln!(stdout, "{}", response_str);
            let _ = stdout.flush();
        }

        if stdin_eof && active_tool_calls.load(Ordering::SeqCst) == 0 {
            eprintln!("[mcp] stdin EOF, shutting down");
            break;
        }

        let line = match request_rx.recv_timeout(Duration::from_millis(25)) {
            Ok(Some(line)) => line,
            Ok(None) => {
                stdin_eof = true;
                continue;
            }
            Err(mpsc::RecvTimeoutError::Timeout) => continue,
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                stdin_eof = true;
                continue;
            }
        };
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }

        // Parse JSON-RPC request
        let request: Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(e) => {
                eprintln!("[mcp] JSON parse error: {e}");
                let error_response = json!({
                    "jsonrpc": "2.0",
                    "id": null,
                    "error": { "code": -32700, "message": format!("Parse error: {e}") }
                });
                let _ = writeln!(
                    stdout,
                    "{}",
                    serde_json::to_string(&error_response).unwrap_or_default()
                );
                let _ = stdout.flush();
                continue;
            }
        };

        eprintln!("[mcp] -> {}", request["method"].as_str().unwrap_or("?"));

        if request["method"].as_str() == Some("tools/call") {
            let id = request.get("id").cloned().unwrap_or(Value::Null);
            let tool_name = request["params"]["name"].as_str().unwrap_or("");
            let arguments = request
                .get("params")
                .and_then(|p| p.get("arguments"))
                .cloned()
                .unwrap_or(json!({}));

            // 控制面调用：不需要 McpCache 锁，不受 busy guard 限制，主线程同步处理
            let root_str = arguments["root"].as_str().unwrap_or("");
            let lang_str = arguments["language"].as_str().unwrap_or("auto");
            let mode_str = arguments["mode"].as_str().unwrap_or("");
            if is_control_plane_call(tool_name, &arguments) {
                let response = match handle_control_plane_call(tool_name, &arguments) {
                    Some(Ok(result)) => make_response(&id, result),
                    Some(Err(err)) => make_response(
                        &id,
                        json!({
                            "content": [{ "type": "text", "text": serde_json::to_string(&err).unwrap_or_default() }],
                            "isError": true
                        }),
                    ),
                    None => make_error_response(&id, -32603, "Control plane handler returned None"),
                };
                let response_str = serde_json::to_string(&response).unwrap_or_default();
                let _ = writeln!(stdout, "{}", response_str);
                let _ = stdout.flush();
                continue;
            }

            let _ = (root_str, lang_str, mode_str);

            active_tool_calls.fetch_add(1, Ordering::SeqCst);
            let request_for_worker = request.clone();
            let cache_for_worker = Arc::clone(&cache);
            let response_tx_for_worker = response_tx.clone();
            let active_for_worker = Arc::clone(&active_tool_calls);
            thread::spawn(move || {
                let response =
                    std::panic::catch_unwind(std::panic::AssertUnwindSafe(
                        || match cache_for_worker.lock() {
                            Ok(mut cache) => handle_request(&request_for_worker, &mut cache),
                            Err(_) => {
                                let id =
                                    request_for_worker.get("id").cloned().unwrap_or(Value::Null);
                                Some(make_error_response(
                                    &id,
                                    -32000,
                                    "Internal MCP cache lock is poisoned",
                                ))
                            }
                        },
                    ))
                    .unwrap_or_else(|_| {
                        let id = request_for_worker.get("id").cloned().unwrap_or(Value::Null);
                        Some(make_error_response(
                            &id,
                            -32000,
                            "Internal MCP tool call panicked",
                        ))
                    });
                if let Some(response) = response {
                    let _ = response_tx_for_worker.send(response);
                }
                active_for_worker.fetch_sub(1, Ordering::SeqCst);
            });
            continue;
        }

        let mut direct_cache = McpCache::new();
        if let Some(response) = handle_request(&request, &mut direct_cache) {
            let response_str = serde_json::to_string(&response).unwrap_or_default();
            let _ = writeln!(stdout, "{}", response_str);
            let _ = stdout.flush();
        }

        // Check for shutdown
        if request["method"].as_str() == Some("shutdown")
            || request["method"].as_str() == Some("exit")
        {
            break;
        }
    }

    eprintln!("[mcp] server stopped");
    Ok(())
}

fn run_rust_analysis_if_available(root: &Path, language: &str) -> Option<Value> {
    let lang = if language == "auto" { "rust" } else { language };
    run_analyze_subprocess(root, lang, "json", false).ok()
}

const ASK_SYNC_FILE_LIMIT: usize = 80;

fn ask_large_project_info(root: &str, language: &str) -> Option<(usize, Vec<String>)> {
    if root.is_empty() {
        return None;
    }
    let lang = if language == "auto" { "rust" } else { language };
    let adapter = crate::engine_bridge::get_adapter_for_language(lang)?;
    let files = adapter.discover_files(root).ok()?;
    let file_count = files.len();
    if file_count <= ASK_SYNC_FILE_LIMIT {
        return None;
    }

    let root_path = Path::new(root);
    let sample_files = files
        .into_iter()
        .take(8)
        .map(|unit| {
            let path = Path::new(&unit.path);
            path.strip_prefix(root_path)
                .unwrap_or(path)
                .to_string_lossy()
                .to_string()
        })
        .collect();
    Some((file_count, sample_files))
}

fn ask_large_project_next_actions(
    root: &str,
    language: &str,
    query: Option<&str>,
    question: &str,
) -> Vec<Value> {
    let mut actions = vec![
        json!({
            "tool": "codelattice_project",
            "mode": "job",
            "why": "Run non-blocking Analysis Engine job for this large project",
            "arguments": {"root": root, "language": language, "compact": true, "parallel": true}
        }),
        json!({
            "tool": "codelattice_project",
            "mode": "job_detail",
            "why": "Page through the completed large-project analysis job",
            "arguments": {"root": root, "language": language, "jobId": "<jobId from mode=job>", "page": 0, "pageSize": 50}
        }),
    ];

    if let Some(symbol) = query.filter(|q| !q.is_empty()) {
        actions.push(json!({
            "tool": "codelattice_symbol",
            "mode": "call_chains",
            "why": format!("Trace '{}' after the project graph is available", symbol),
            "arguments": {"root": root, "language": language, "query": symbol, "direction": "both", "maxDepth": 4, "compact": true}
        }));
        actions.push(json!({
            "tool": "codelattice_change_review",
            "mode": "impact",
            "why": format!("Assess focused impact for '{}'", symbol),
            "arguments": {"root": root, "language": language, "symbol": symbol, "compact": true}
        }));
    } else {
        actions.push(json!({
            "tool": "codelattice_workflow",
            "mode": "ask",
            "why": "Ask again with a specific symbol or file after orientation",
            "arguments": {"root": root, "language": language, "question": question, "compact": true}
        }));
    }

    actions
}

fn ask_submit_auto_job(root: &str, language: &str) -> Value {
    match crate::mcp_job::submit_project_job(root, language, "parallel") {
        Ok(job_response) => {
            let job_id = job_response
                .get("jobId")
                .and_then(|v| v.as_str())
                .unwrap_or("")
                .to_string();
            let status = job_response
                .get("status")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown")
                .to_string();
            json!({
                "submitted": true,
                "jobId": job_id,
                "status": status,
                "detailPageHint": format!("codelattice_project(mode=job_detail, jobId={}, page=0, pageSize=50)", job_id)
            })
        }
        Err(e) => json!({
            "submitted": false,
            "error": e,
            "fallback": "Use codelattice_project(mode=job) manually"
        }),
    }
}

fn ask_job_next_actions(
    root: &str,
    language: &str,
    job: &Value,
    query: Option<&str>,
) -> Vec<Value> {
    let mut actions = Vec::new();
    if job["submitted"].as_bool().unwrap_or(false) {
        let job_id = job["jobId"].as_str().unwrap_or("");
        actions.push(json!({
            "tool": "codelattice_project",
            "mode": "job_status",
            "why": "Check auto-submitted job status",
            "arguments": {"jobId": job_id, "root": root, "language": language, "compact": true}
        }));
        actions.push(json!({
            "tool": "codelattice_project",
            "mode": "job_detail",
            "why": "Page through the auto-submitted job results",
            "arguments": {"jobId": job_id, "page": 0, "pageSize": 50, "root": root, "language": language, "compact": true}
        }));
    } else {
        actions.push(json!({
            "tool": "codelattice_project",
            "mode": "job",
            "why": "Auto-job submission failed; submit manually",
            "arguments": {"root": root, "language": language, "compact": true, "parallel": true}
        }));
    }
    if let Some(q) = query {
        if !q.is_empty() {
            actions.push(json!({
                "tool": "codelattice_symbol",
                "mode": "call_chains",
                "why": format!("Trace call chains for '{}' after job completes", q),
                "arguments": {"query": q, "language": language, "root": root, "direction": "both", "maxDepth": 4, "compact": true}
            }));
        }
    }
    actions
}

/// 检测路由/handler 候选文件：搜索 api/routes/handlers 目录中的源文件
#[allow(clippy::too_many_arguments)]
fn collect_source_files(
    dir: &std::path::Path,
    language: &str,
    max_depth: usize,
    out: &mut Vec<String>,
    depth: usize,
) {
    if depth > max_depth || out.len() >= 30 {
        return;
    }
    if let Ok(entries) = std::fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            let fname = path
                .file_name()
                .map(|n| n.to_string_lossy().to_lowercase())
                .unwrap_or_default();
            if fname == "target" || fname == "node_modules" || fname.starts_with('.') {
                continue;
            }
            if path.is_dir() {
                collect_source_files(&path, language, max_depth, out, depth + 1);
            } else if path.is_file() {
                let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("");
                let valid = matches!(ext, "rs" | "ts" | "tsx" | "js" | "jsx");
                let is_route = fname.contains("route")
                    || fname.contains("handler")
                    || fname.contains("controller")
                    || fname.contains("api")
                    || path.to_string_lossy().to_lowercase().contains("/api/")
                    || path.to_string_lossy().to_lowercase().contains("/routes/")
                    || path.to_string_lossy().to_lowercase().contains("/handlers/")
                    || path
                        .to_string_lossy()
                        .to_lowercase()
                        .contains("/controllers/");
                if valid
                    && is_route
                    && !fname.ends_with(".d.ts")
                    && !fname.contains(".test.")
                    && !fname.contains(".spec.")
                {
                    out.push(path.display().to_string());
                }
            }
        }
    }
}

fn detect_route_handlers(root: &str, language: &str, _strict: bool) -> Value {
    let mut route_files: Vec<String> = Vec::new();
    let path_patterns = [
        "api",
        "routes",
        "handlers",
        "controllers",
        "handler",
        "route",
    ];
    collect_source_files(std::path::Path::new(root), language, 4, &mut route_files, 0);
    if let Ok(dir) = std::fs::read_dir(root) {
        for entry in dir.flatten() {
            let name = entry.file_name().to_string_lossy().to_lowercase();
            for pat in &path_patterns {
                if name.contains(pat) && entry.path().is_dir() {
                    collect_source_files(&entry.path(), language, 3, &mut route_files, 0);
                }
            }
            // Also check the root dir itself for handler-like files
            if entry.path().is_file() {
                let fname = entry.file_name().to_string_lossy().to_lowercase();
                if fname.contains("route")
                    || fname.contains("handler")
                    || fname.contains("controller")
                    || fname.contains("api")
                {
                    let ext = std::path::Path::new(&fname)
                        .extension()
                        .and_then(|e| e.to_str())
                        .unwrap_or("");
                    let valid = matches!(ext, "rs" | "ts" | "tsx" | "js" | "jsx");
                    if valid && !fname.ends_with(".d.ts") {
                        route_files.push(entry.path().display().to_string());
                    }
                }
            }
        }
    }
    route_files.sort();
    route_files.dedup();
    // 截断到合理数量
    route_files.truncate(20);
    let read_order: Vec<Value> = route_files
        .iter()
        .take(10)
        .map(|p| {
            json!({
                "kind": "handler_candidate", "path": p,
                "reason": "file lives in api/routes/handlers directory"
            })
        })
        .collect();
    let next_actions: Vec<Value> = route_files.iter().take(3).map(|p| json!({
        "tool": "codelattice_symbol", "mode": "search",
        "why": format!("Search symbols inside handler candidate: {}", p),
        "arguments": {"root": root, "language": language, "query": "", "kind": "Function", "compact": true}
    })).collect();
    json!({
        "routeCandidates": route_files,
        "callChains": [],
        "filesInvolved": route_files,
        "readOrder": read_order,
        "recommendedNextCalls": next_actions,
        "analysisSemantics": {
            "staticAnalysis": true, "targetCodeExecuted": false, "runtimeVerified": false
        }
    })
}

fn build_large_project_digest(
    root: &str,
    language: &str,
    file_count: usize,
    sample_files: &[String],
) -> Value {
    json!({
        "root": root,
        "language": language,
        "sourceFileCount": file_count,
        "symbolCount": Value::Null,
        "callsEdgeCount": Value::Null,
        "topFiles": sample_files.iter().map(|path| json!({
            "path": path,
            "kind": "source-file-sample"
        })).collect::<Vec<_>>(),
        "analysisDeferred": true,
        "deferReason": "large_project",
        "recommendedMode": "job",
        "staticOnly": true,
        "targetCodeExecuted": false
    })
}

fn build_deferred_whatif_value(
    root: &str,
    language: &str,
    change: &str,
    query: &str,
    file_count: usize,
    sample_files: &[String],
) -> Value {
    let read_first = sample_files
        .iter()
        .take(3)
        .map(|path| {
            json!({
                "kind": "source-sample",
                "path": path,
                "reason": "large project sample; run job_detail for complete graph evidence"
            })
        })
        .collect::<Vec<_>>();
    let mut action_plan = vec![
        json!({
            "action": "runJob",
            "target": root,
            "reason": format!("Large project has {} source files; synchronous whatif was deferred to avoid blocking MCP", file_count),
            "confidence": 0.90,
            "staticOnly": true
        }),
        json!({
            "action": "readFirst",
            "target": sample_files.first().cloned().unwrap_or_default(),
            "reason": "Start with sampled project files while the job result is paged",
            "confidence": 0.45,
            "staticOnly": true
        }),
    ];
    if !query.is_empty() {
        action_plan.push(json!({
            "action": "followUpImpact",
            "target": query,
            "reason": "Run focused impact/call-chain review after job graph is available",
            "confidence": 0.60,
            "staticOnly": true
        }));
    }

    json!({
        "schemaVersion": "codelattice.whatIf.v1",
        "changeIntent": {
            "rawChange": change,
            "action": if change.contains("删除") || change.to_lowercase().contains("delete") { "delete" } else { "modify" },
            "targetQuery": query,
            "targetFile": "",
            "confidence": if query.is_empty() { 0.0 } else { 0.55 }
        },
        "targetCandidates": [],
        "directImpact": [],
        "indirectImpact": [],
        "risk": {
            "level": "unknown",
            "reasons": ["large project whatif deferred; run codelattice_project mode=job before trusting impact"],
            "staticOnly": true,
            "fanIn": Value::Null,
            "fanOut": Value::Null,
            "indirectCount": Value::Null
        },
        "safeAlternatives": [
            {"suggestion": "Run non-blocking job analysis before editing this large project", "priority": "high"},
            {"suggestion": "Prefer compatibility wrapper or incremental migration until impact is verified", "priority": "medium"}
        ],
        "testsToRun": [
            {"suggestion": "Run targeted tests for affected modules after static job review", "automated": false}
        ],
        "readFirst": read_first,
        "evidenceGaps": [
            {
                "kind": "large_project_deferred",
                "explanation": format!("Synchronous ask/whatif skipped full graph analysis for {} files.", file_count)
            }
        ],
        "actionPlan": action_plan.into_iter().take(5).collect::<Vec<_>>(),
        "recommendedNextCalls": ask_large_project_next_actions(root, language, if query.is_empty() { None } else { Some(query) }, change),
        "analysisSemantics": {
            "staticAnalysisExecuted": true,
            "targetCodeExecuted": false,
            "runtimeVerified": false,
            "scriptsExecuted": false
        }
    })
}

fn build_call_chains_result(
    root: &Path,
    language: &str,
    query: &str,
    direction: &str,
    max_depth: usize,
    limit: usize,
) -> (
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    String,
) {
    let mut candidates = Vec::new();
    let mut call_chains = Vec::new();
    let mut read_first = Vec::new();
    let mut missing = Vec::new();
    let mut next_actions = Vec::new();
    let mut read_order = Vec::new();
    let mut files_involved = Vec::new();
    let mut entry_points = Vec::new();
    let mut exit_points = Vec::new();

    let analyze_result = run_rust_analysis_if_available(root, language);
    match analyze_result {
        Some(graph_data) => {
            let graph = graph_data.get("graph").unwrap_or(&Value::Null);
            let nodes = graph
                .get("nodes")
                .and_then(|n| n.as_array())
                .cloned()
                .unwrap_or_default();
            let edges = graph
                .get("edges")
                .and_then(|e| e.as_array())
                .cloned()
                .unwrap_or_default();

            let query_lower = query.to_lowercase();
            for node in &nodes {
                let is_symbol = node
                    .get("label")
                    .and_then(|l| l.as_str())
                    .map(|l| l == "symbol")
                    .unwrap_or(false)
                    || node
                        .get("kind")
                        .and_then(|k| k.as_str())
                        .map(|k| k == "symbol")
                        .unwrap_or(false);
                if !is_symbol {
                    continue;
                }
                let name = node
                    .get("properties")
                    .and_then(|p| p.get("name"))
                    .and_then(|n| n.as_str())
                    .unwrap_or("");
                if name.to_lowercase().contains(&query_lower) {
                    candidates.push(json!({
                        "name": name,
                        "file": node["properties"]["sourcePath"].as_str().unwrap_or(""),
                        "line": node["properties"]["lineStart"].as_u64().unwrap_or(0),
                        "kind": node["properties"]["symbolKind"].as_str().unwrap_or("unknown"),
                        "id": node["id"]
                    }));
                }
            }

            let calls_edges: Vec<_> = edges
                .iter()
                .filter(|e| {
                    let has_calls_type = e
                        .get("type")
                        .and_then(|t| t.as_str())
                        .map(|t| t == "CALLS")
                        .unwrap_or(false);
                    let has_call_kind = e
                        .get("properties")
                        .and_then(|p| p.get("callKind"))
                        .is_some();
                    has_calls_type || has_call_kind
                })
                .collect();

            for candidate in candidates.iter().take(limit) {
                let id = candidate["id"].as_str().unwrap_or("");

                if direction == "upstream" || direction == "both" {
                    let mut chain = Vec::new();
                    let mut chain_ids = Vec::new();
                    let mut files = BTreeSet::new();
                    let mut edge_kinds = Vec::new();
                    let mut current = id.to_string();

                    for _ in 0..max_depth {
                        let caller = calls_edges.iter().find(|e| {
                            e.get("target").and_then(|t| t.as_str()) == Some(current.as_str())
                        });
                        match caller {
                            Some(edge) => {
                                let source_id =
                                    edge.get("source").and_then(|s| s.as_str()).unwrap_or("");
                                let source_name = nodes
                                    .iter()
                                    .find(|n| n["id"].as_str() == Some(source_id))
                                    .and_then(|n| n["properties"]["name"].as_str())
                                    .unwrap_or(source_id);
                                chain.push(source_name.to_string());
                                chain_ids.push(source_id.to_string());
                                edge_kinds.push("CALLS");
                                if let Some(f) = nodes
                                    .iter()
                                    .find(|n| n["id"].as_str() == Some(source_id))
                                    .and_then(|n| n["properties"]["sourcePath"].as_str())
                                {
                                    files.insert(f.to_string());
                                }
                                current = source_id.to_string();
                            }
                            None => break,
                        }
                    }
                    chain.push(candidate["name"].as_str().unwrap_or(query).to_string());

                    if chain.len() > 1 {
                        let entry_file = nodes
                            .iter()
                            .find(|n| {
                                n["id"].as_str()
                                    == Some(chain_ids.first().map(|s| s.as_str()).unwrap_or(""))
                            })
                            .and_then(|n| n["properties"]["sourcePath"].as_str())
                            .unwrap_or("")
                            .to_string();
                        call_chains.push(json!({
                            "chain": chain,
                            "depth": chain.len() - 1,
                            "direction": "upstream",
                            "confidence": 0.70,
                            "confidenceReason": "static-call-graph-heuristic",
                            "entryFile": entry_file,
                            "exitFile": candidate["file"].as_str().unwrap_or(""),
                            "files": files,
                            "edgeKinds": edge_kinds
                        }));
                    }
                }

                if direction == "downstream" || direction == "both" {
                    let mut chain = vec![candidate["name"].as_str().unwrap_or(query).to_string()];
                    let mut chain_ids = vec![id.to_string()];
                    let mut files = BTreeSet::new();
                    let mut edge_kinds = Vec::new();
                    let mut current = id.to_string();
                    files.insert(candidate["file"].as_str().unwrap_or("").to_string());

                    for _ in 0..max_depth {
                        let callee = calls_edges.iter().find(|e| {
                            e.get("source").and_then(|s| s.as_str()) == Some(current.as_str())
                        });
                        match callee {
                            Some(edge) => {
                                let target_id =
                                    edge.get("target").and_then(|t| t.as_str()).unwrap_or("");
                                let target_name = nodes
                                    .iter()
                                    .find(|n| n["id"].as_str() == Some(target_id))
                                    .and_then(|n| n["properties"]["name"].as_str())
                                    .unwrap_or(target_id);
                                chain.push(target_name.to_string());
                                chain_ids.push(target_id.to_string());
                                edge_kinds.push("CALLS");
                                if let Some(f) = nodes
                                    .iter()
                                    .find(|n| n["id"].as_str() == Some(target_id))
                                    .and_then(|n| n["properties"]["sourcePath"].as_str())
                                {
                                    files.insert(f.to_string());
                                }
                                current = target_id.to_string();
                            }
                            None => break,
                        }
                    }

                    if chain.len() > 1 {
                        let exit_file = nodes
                            .iter()
                            .find(|n| {
                                n["id"].as_str()
                                    == Some(chain_ids.last().map(|s| s.as_str()).unwrap_or(""))
                            })
                            .and_then(|n| n["properties"]["sourcePath"].as_str())
                            .unwrap_or("")
                            .to_string();
                        call_chains.push(json!({
                            "chain": chain,
                            "depth": chain.len() - 1,
                            "direction": "downstream",
                            "confidence": 0.70,
                            "confidenceReason": "static-call-graph-heuristic",
                            "entryFile": candidate["file"].as_str().unwrap_or(""),
                            "exitFile": exit_file,
                            "files": files,
                            "edgeKinds": edge_kinds
                        }));
                    }
                }
            }

            if !candidates.is_empty() {
                read_first.push(json!({
                    "kind": "source",
                    "path": candidates[0]["file"],
                    "reason": "Primary candidate source file"
                }));
            }
        }
        None => {
            missing.push(json!({
                "kind": "no_graph_data",
                "explanation": format!("No graph data available for {} at {}. Run analyze first.", language, root.display())
            }));
        }
    }

    if candidates.is_empty() {
        missing.push(json!({
            "kind": "symbol_not_found",
            "explanation": format!("No symbols matching '{}' found in the graph.", query)
        }));
        next_actions.push(json!({
            "tool": "codelattice_symbol",
            "mode": "search",
            "why": format!("Try a broader search for '{}'", query),
            "arguments": { "query": query }
        }));
    }

    next_actions.push(json!({
        "tool": "codelattice_symbol",
        "mode": "context",
        "why": "Get full context for the target symbol",
        "arguments": { "name": query }
    }));

    if !candidates.is_empty() {
        read_order.push(json!({
            "order": 1,
            "kind": "source",
            "path": candidates[0]["file"],
            "symbol": candidates[0]["name"],
            "reason": "Primary candidate definition"
        }));
    }
    for chain in &call_chains {
        if let Some(arr) = chain["chain"].as_array() {
            if let Some(first) = arr.first() {
                let name = first.as_str().unwrap_or("");
                if !entry_points
                    .iter()
                    .any(|e: &Value| e["name"].as_str() == Some(name))
                {
                    entry_points.push(json!({
                        "name": name,
                        "file": chain["entryFile"].as_str().unwrap_or(""),
                        "reason": "chain entry (caller)"
                    }));
                }
            }
            if let Some(last) = arr.last() {
                let name = last.as_str().unwrap_or("");
                if !exit_points
                    .iter()
                    .any(|e: &Value| e["name"].as_str() == Some(name))
                {
                    exit_points.push(json!({
                        "name": name,
                        "file": chain["exitFile"].as_str().unwrap_or(""),
                        "reason": "chain exit (callee)"
                    }));
                }
            }
        }
        if let Some(files) = chain["files"].as_array() {
            for f in files {
                let fp = f.as_str().unwrap_or("");
                if !fp.is_empty()
                    && !files_involved
                        .iter()
                        .any(|fi: &Value| fi.as_str() == Some(fp))
                {
                    files_involved.push(Value::String(fp.to_string()));
                }
            }
        }
    }
    let mut all_files_set: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
    for c in &candidates {
        if let Some(f) = c["file"].as_str() {
            if !f.is_empty() {
                all_files_set.insert(f.to_string());
            }
        }
    }
    for f in &files_involved {
        if let Some(fp) = f.as_str() {
            all_files_set.insert(fp.to_string());
        }
    }
    files_involved = all_files_set.into_iter().map(Value::String).collect();
    let chain_summary = if call_chains.is_empty() {
        format!(
            "0 chains found for '{}'. {}",
            query,
            if candidates.is_empty() {
                "No matching symbols found in the graph."
            } else {
                "Symbol found but no CALLS edges traced."
            }
        )
    } else {
        let summaries: Vec<String> = call_chains
            .iter()
            .map(|c| {
                let dir = c["direction"].as_str().unwrap_or("?");
                let depth = c["depth"].as_u64().unwrap_or(0);
                if let Some(arr) = c["chain"].as_array() {
                    format!(
                        "{} (depth={}, {})",
                        arr.iter()
                            .filter_map(|v| v.as_str())
                            .collect::<Vec<_>>()
                            .join(" -> "),
                        depth,
                        dir
                    )
                } else {
                    format!("chain (depth={}, {})", depth, dir)
                }
            })
            .collect();
        format!(
            "{} chain(s) for '{}': {}",
            call_chains.len(),
            query,
            summaries.join("; ")
        )
    };

    (
        candidates,
        call_chains,
        read_first,
        missing,
        next_actions,
        read_order,
        files_involved,
        entry_points,
        exit_points,
        chain_summary,
    )
}

fn issue_triage_from_project_diagnose(diagnose: &Value, target_query: Option<&str>) -> Value {
    let likely_areas = take_json_items(&diagnose["likelyAreas"], 5);
    let read_first = take_json_items(&diagnose["readFirst"], 5);
    let impact_hints = take_json_items(&diagnose["impactHints"], 5);
    let hypotheses: Vec<Value> = likely_areas
        .iter()
        .take(5)
        .enumerate()
        .map(|(idx, area)| {
            json!({
                "priority": idx + 1,
                "candidate": area.get("name").cloned().unwrap_or_else(|| json!("unknown")),
                "file": area.get("file").cloned().unwrap_or(Value::Null),
                "line": area.get("line").cloned().unwrap_or(Value::Null),
                "confidence": area.get("confidence").cloned().unwrap_or(Value::Null),
                "reason": area.get("reason").cloned().unwrap_or_else(|| json!("static ranking signal")),
                "nextAction": area.get("nextAction").cloned().unwrap_or_else(|| json!("Read this candidate and confirm with targeted tests."))
            })
        })
        .collect();

    json!({
        "schemaVersion": "codelattice.issueTriage.v1",
        "targetQuery": target_query,
        "summary": diagnose.get("summary").cloned().unwrap_or_else(|| json!({})),
        "answerSummary": diagnose.get("answerSummary").cloned().unwrap_or_else(|| json!("Static issue triage generated from project diagnosis.")),
        "likelyAreas": likely_areas,
        "readFirst": read_first,
        "impactHints": impact_hints,
        "hypotheses": hypotheses,
        "evidenceGaps": [
            {
                "kind": "runtime_reproduction",
                "status": "not_checked",
                "reason": "CodeLattice did not execute target project code.",
                "nextAction": "Run the smallest reproduction or failing test outside CodeLattice."
            },
            {
                "kind": "targeted_tests",
                "status": "not_checked",
                "reason": "Static diagnosis is not test or coverage proof.",
                "nextAction": "Run targeted tests after choosing the likely file/symbol."
            },
            {
                "kind": "dynamic_runtime_edges",
                "status": "not_proven",
                "reason": "Framework dispatch, dynamic calls, trait objects, and generated code may hide edges.",
                "nextAction": "Confirm runtime/framework paths manually before editing."
            }
        ],
        "staticOnly": true,
        "targetCodeExecuted": false,
        "runtimeVerified": false
    })
}

fn issue_triage_from_call_context(
    target_query: Option<&str>,
    call_chains: &[Value],
    read_order: &[Value],
    files_involved: &[Value],
) -> Value {
    let likely_areas: Vec<Value> = read_order
        .iter()
        .take(5)
        .enumerate()
        .map(|(idx, item)| {
            json!({
                "id": item.get("symbol").cloned().unwrap_or_else(|| json!(target_query.unwrap_or("unknown"))),
                "name": item.get("symbol").cloned().unwrap_or_else(|| json!(target_query.unwrap_or("unknown"))),
                "kind": item.get("kind").cloned().unwrap_or_else(|| json!("source")),
                "file": item.get("path").or_else(|| item.get("file")).cloned().unwrap_or(Value::Null),
                "line": item.get("line").cloned().unwrap_or(Value::Null),
                "confidence": 0.7,
                "reason": item.get("reason").cloned().unwrap_or_else(|| json!("call-chain evidence")),
                "nextAction": "Read this file/symbol first, then inspect callers/callees before editing.",
                "priority": idx + 1
            })
        })
        .collect();
    let read_first: Vec<Value> = read_order
        .iter()
        .take(5)
        .enumerate()
        .map(|(idx, item)| {
            json!({
                "priority": idx + 1,
                "kind": "file",
                "file": item.get("path").or_else(|| item.get("file")).cloned().unwrap_or(Value::Null),
                "symbol": item.get("symbol").cloned().unwrap_or(Value::Null),
                "reason": item.get("reason").cloned().unwrap_or_else(|| json!("call-chain read order")),
                "nextAction": "Read this before editing; confirm with runtime evidence or targeted tests."
            })
        })
        .collect();
    let hypotheses: Vec<Value> = likely_areas
        .iter()
        .take(5)
        .enumerate()
        .map(|(idx, area)| {
            json!({
                "priority": idx + 1,
                "candidate": area.get("name").cloned().unwrap_or_else(|| json!("unknown")),
                "file": area.get("file").cloned().unwrap_or(Value::Null),
                "confidence": area.get("confidence").cloned().unwrap_or(Value::Null),
                "reason": "call-chain context matched the issue target",
                "nextAction": "Inspect this candidate and its immediate callers/callees."
            })
        })
        .collect();

    json!({
        "schemaVersion": "codelattice.issueTriage.v1",
        "targetQuery": target_query,
        "summary": {
            "likelyAreaCount": likely_areas.len(),
            "readFirstCount": read_first.len(),
            "callChainCount": call_chains.len(),
            "fileCount": files_involved.len()
        },
        "answerSummary": format!(
            "Static issue triage used call-chain context for {}.",
            target_query.unwrap_or("the target")
        ),
        "likelyAreas": likely_areas,
        "readFirst": read_first,
        "impactHints": call_chains.iter().take(5).cloned().collect::<Vec<_>>(),
        "hypotheses": hypotheses,
        "filesInvolved": files_involved,
        "evidenceGaps": [
            {
                "kind": "runtime_reproduction",
                "status": "not_checked",
                "reason": "CodeLattice did not execute target project code.",
                "nextAction": "Run the smallest reproduction or failing test outside CodeLattice."
            },
            {
                "kind": "targeted_tests",
                "status": "not_checked",
                "reason": "Static call-chain triage is not test or coverage proof.",
                "nextAction": "Run targeted tests after choosing the likely file/symbol."
            },
            {
                "kind": "dynamic_runtime_edges",
                "status": "not_proven",
                "reason": "Runtime dispatch can hide additional paths.",
                "nextAction": "Confirm dynamic/framework behavior manually before editing."
            }
        ],
        "staticOnly": true,
        "targetCodeExecuted": false,
        "runtimeVerified": false
    })
}

fn route_ask_intent(
    cache: &mut McpCache,
    root: &str,
    language: &str,
    question: &str,
    compact: bool,
    execute: bool,
) -> (
    String,
    String,
    Option<String>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    Vec<Value>,
    serde_json::Value,
    serde_json::Value,
    serde_json::Value,
    serde_json::Value,
    Vec<Value>,
    String,
    serde_json::Value, // confidence: { level, reason }
) {
    let q = question.to_lowercase();

    let flow_keywords = [
        "流程",
        "怎么运行",
        "调用链",
        "call flow",
        "执行路径",
        "call chain",
        "how does",
        "execution path",
        "调用关系",
    ];
    let find_keywords = [
        "在哪",
        "找",
        "搜索",
        "哪个函数",
        "which symbol",
        "where is",
        "find",
        "search",
    ];
    let inspect_keywords = [
        "了解项目",
        "项目结构",
        "入口",
        "架构",
        "overview",
        "project structure",
        "entry point",
        "architecture",
        "这个项目",
    ];
    let route_keywords = [
        "api route",
        "route handler",
        "路由",
        "api endpoint",
        "show api",
        "有哪些 api",
        "有哪些路由",
        "handler",
        "api handler",
        "route list",
        "endpoint",
    ];
    let edit_keywords = [
        "如果改",
        "删除",
        "重命名",
        "影响",
        "风险",
        "what if",
        "delete",
        "rename",
        "impact",
        "risk",
        "如果删除",
        "如果修改",
    ];
    let issue_keywords = [
        "bug", "error", "fail", "crash", "异常", "报错", "问题", "定位", "locate", "issue",
        "debug", "调试",
    ];

    let intent;
    let mut answer_summary;
    let mut evidence = Vec::new();
    let mut call_chains = Vec::new();
    let mut read_first = Vec::new();
    let mut missing_evidence = Vec::new();
    let mut next_actions = Vec::new();
    let ai_guidance;
    let mut target_query: Option<String> = None;
    let mut files_involved = Vec::new();
    let mut read_order_out = Vec::new();
    let mut triage_plan = Value::Null;
    let mut project_digest = Value::Null;
    let mut orchestration = json!({"stepsAttempted": [], "stepsSkipped": []});
    let mut auto_job = Value::Null;
    let mut confidence = json!({"level": "low", "reason": "default"});

    if flow_keywords.iter().any(|k| q.contains(k)) {
        intent = "explain_flow".to_string();
        let query = extract_symbol_from_question(question);
        target_query = if query.is_empty() {
            None
        } else {
            Some(query.clone())
        };
        orchestration["stepsAttempted"] = json!(["intent-classification:explain_flow"]);
        if !root.is_empty() && !query.is_empty() {
            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                answer_summary = format!(
                    "Call-chain ask for '{}' deferred: project has {} source files. Start a non-blocking job first.",
                    query, file_count
                );
                files_involved = sample_files.iter().cloned().map(Value::String).collect();
                read_order_out = sample_files
                    .iter()
                    .take(5)
                    .map(|path| json!({"kind": "source-sample", "path": path, "reason": "large project sample"}))
                    .collect();
                missing_evidence.push(json!({
                    "kind": "large_project_deferred",
                    "explanation": "Synchronous call-chain traversal skipped full graph analysis to avoid blocking MCP."
                }));
                auto_job = ask_submit_auto_job(root, language);
                next_actions = ask_job_next_actions(root, language, &auto_job, Some(&query));
                orchestration["stepsSkipped"] = json!(["call_chains:deferred_large_project"]);
                orchestration["resultsSummary"] = json!({
                    "largeProject": {"sourceFileCount": file_count, "recommendedMode": "job"}
                });
            } else {
                let root_path = Path::new(root);
                let (candidates, chains, rf, me, na, ro, fi, _, _, _) =
                    build_call_chains_result(root_path, language, &query, "both", 4, 8);
                call_chains = chains;
                read_first = rf;
                missing_evidence = me;
                next_actions = na;
                next_actions.push(json!({
                    "tool": "codelattice_symbol",
                    "mode": "call_chains",
                    "why": format!("Get full call chains for '{}'", query),
                    "arguments": {"query": query, "language": language, "root": root, "direction": "both", "maxDepth": 4, "compact": true}
                }));
                read_order_out = ro;
                files_involved = fi;
                orchestration["stepsAttempted"] =
                    json!(["intent-classification:explain_flow", "call_chains:executed"]);
                if !candidates.is_empty() {
                    answer_summary = format!(
                        "Found {} candidates and {} call chains for '{}'.",
                        candidates.len(),
                        call_chains.len(),
                        query
                    );
                    evidence.push(json!({
                        "kind": "candidates_found",
                        "count": candidates.len(),
                        "topCandidate": candidates[0]
                    }));
                } else {
                    answer_summary = format!("No symbols matching '{}' found in the graph.", query);
                    missing_evidence.push(json!({
                        "kind": "symbol_not_found",
                        "explanation": format!("'{}' not found in static graph", query)
                    }));
                }
            }
        } else {
            answer_summary =
                "Call chain analysis requires a valid root path and symbol name.".to_string();
            missing_evidence.push(json!({
                "kind": "missing_input",
                "explanation": "root path or symbol not provided"
            }));
        }
        ai_guidance = "Call chains are derived from static analysis only. Runtime dispatch, trait objects, and dynamic calls are not captured. Use the readFirst entries to verify the actual code flow.".to_string();
    } else if find_keywords.iter().any(|k| q.contains(k)) {
        intent = "find_symbol".to_string();
        let query = extract_symbol_from_question(question);
        target_query = if query.is_empty() {
            None
        } else {
            Some(query.clone())
        };
        answer_summary = if query.is_empty() {
            "Please specify which symbol you're looking for.".to_string()
        } else {
            format!("Searching for '{}' in the codebase.", query)
        };
        next_actions.push(json!({
            "tool": "codelattice_symbol",
            "mode": "search",
            "why": format!("Search for symbols matching '{}'", query),
            "arguments": {"query": query, "language": language, "root": root}
        }));
        ai_guidance =
            "Use codelattice_symbol(mode=search) to find the symbol, then mode=context for details."
                .to_string();
    } else if inspect_keywords.iter().any(|k| q.contains(k)) {
        intent = "inspect_project".to_string();
        orchestration["stepsAttempted"] = json!(["intent-classification:inspect_project"]);
        if !root.is_empty() {
            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                answer_summary = format!(
                    "Large project at {} ({}): {} source files discovered. Full graph analysis is deferred to job mode.",
                    root, language, file_count
                );
                project_digest =
                    build_large_project_digest(root, language, file_count, &sample_files);
                orchestration["stepsAttempted"] = json!([
                    "intent-classification:inspect_project",
                    "project_quick:lightweight"
                ]);
                orchestration["stepsSkipped"] = json!(["full_graph:deferred_large_project"]);
                orchestration["resultsSummary"] = json!({
                    "largeProject": {"sourceFileCount": file_count, "recommendedMode": "job"}
                });
                evidence.push(json!({
                    "kind": "large_project_digest",
                    "sourceFileCount": file_count,
                    "analysisDeferred": true
                }));
                missing_evidence.push(json!({
                    "kind": "full_graph_deferred",
                    "explanation": "Large project ask uses lightweight discovery; run codelattice_project(mode=job) for complete graph details."
                }));
                auto_job = ask_submit_auto_job(root, language);
                next_actions = ask_job_next_actions(root, language, &auto_job, None);
            } else {
                let root_path = Path::new(root);
                let analyze_result = run_rust_analysis_if_available(root_path, language);
                match analyze_result {
                    Some(graph_data) => {
                        let graph = graph_data.get("graph").unwrap_or(&Value::Null);
                        let nodes = graph
                            .get("nodes")
                            .and_then(|n| n.as_array())
                            .cloned()
                            .unwrap_or_default();
                        let edges = graph
                            .get("edges")
                            .and_then(|e| e.as_array())
                            .cloned()
                            .unwrap_or_default();
                        let source_files: Vec<Value> = nodes.iter().filter(|n| {
                            n.get("label").and_then(|l| l.as_str()) == Some("source-file")
                                || n.get("kind").and_then(|k| k.as_str()) == Some("source-file")
                        }).map(|n| json!({
                            "path": n["properties"]["sourcePath"].as_str().unwrap_or(n["id"].as_str().unwrap_or("")),
                            "kind": "source-file"
                        })).take(10).collect();
                        let symbol_count = nodes
                            .iter()
                            .filter(|n| {
                                n.get("label").and_then(|l| l.as_str()) == Some("symbol")
                                    || n.get("kind").and_then(|k| k.as_str()) == Some("symbol")
                            })
                            .count();
                        let calls_count = edges
                            .iter()
                            .filter(|e| {
                                e.get("type").and_then(|t| t.as_str()) == Some("CALLS")
                                    || e.get("properties")
                                        .and_then(|p| p.get("callKind"))
                                        .is_some()
                            })
                            .count();
                        answer_summary = format!(
                            "Project at {} ({}): {} source files, {} symbols, {} CALLS edges. Static analysis only.",
                            root, language, source_files.len(), symbol_count, calls_count
                        );
                        project_digest = json!({
                            "sourceFileCount": source_files.len(),
                            "symbolCount": symbol_count,
                            "callsEdgeCount": calls_count,
                            "topFiles": source_files,
                            "staticOnly": true
                        });
                        orchestration["stepsAttempted"] = json!([
                            "intent-classification:inspect_project",
                            "project_quick:executed"
                        ]);
                        orchestration["resultsSummary"] = json!({
                            "project_quick": format!("{} files, {} symbols, {} CALLS", source_files.len(), symbol_count, calls_count)
                        });
                        evidence.push(json!({
                            "kind": "project_digest",
                            "sourceFileCount": source_files.len(),
                            "symbolCount": symbol_count,
                            "callsEdgeCount": calls_count
                        }));
                        missing_evidence.push(json!({
                            "kind": "runtime_verification",
                            "explanation": "Project overview is static-only. No tests were run, no build was attempted."
                        }));
                    }
                    None => {
                        answer_summary = format!(
                            "Project overview for {} ({}). Could not run analysis.",
                            root, language
                        );
                        orchestration["stepsSkipped"] = json!(["project_quick:no_analysis_data"]);
                        missing_evidence.push(json!({
                            "kind": "no_graph_data",
                            "explanation": "Could not run static analysis for this project."
                        }));
                    }
                }
            }
            next_actions.push(json!({
                "tool": "codelattice_project",
                "mode": "quick",
                "why": "Get more detailed project overview",
                "arguments": {"root": root, "language": language, "compact": true}
            }));
            next_actions.push(json!({
                "tool": "codelattice_project",
                "mode": "standard",
                "why": "Get comprehensive project analysis",
                "arguments": {"root": root, "language": language, "compact": true}
            }));
        } else {
            answer_summary = "Please provide a root path to inspect.".to_string();
            orchestration["stepsSkipped"] = json!(["project_quick:no_root"]);
            missing_evidence.push(json!({
                "kind": "missing_input",
                "explanation": "root path required"
            }));
        }
        ai_guidance = "Use codelattice_project(mode=quick) for a fast project overview, or mode=standard for more detail.".to_string();
    } else if route_keywords.iter().any(|k| q.contains(k)) {
        intent = "inspect_routes".to_string();
        answer_summary =
            "Searching for API routes and handler functions — static analysis only.".to_string();
        orchestration["stepsAttempted"] = json!(["intent-classification:inspect_routes"]);
        if !root.is_empty() {
            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                // 大项目：提交异步 job + 回退建议
                files_involved = sample_files.iter().cloned().map(Value::String).collect();
                auto_job = ask_submit_auto_job(root, language);
                next_actions = ask_job_next_actions(root, language, &auto_job, None);
                answer_summary = format!("Route inspection deferred: project has {} source files. Submit a job first, then re-ask.", file_count);
                ai_guidance =
                    "Route inspection deferred to background job. Poll job_status until complete."
                        .to_string();
            } else {
                let route_hints = detect_route_handlers(root, language, false);
                call_chains = route_hints["callChains"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default();
                files_involved = route_hints["filesInvolved"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default()
                    .into_iter()
                    .map(|v| Value::String(v.as_str().unwrap_or("").to_string()))
                    .collect();
                read_order_out = route_hints["readOrder"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default();
                next_actions = route_hints["recommendedNextCalls"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default()
                    .into_iter()
                    .map(|v| v.clone())
                    .collect();
                if !files_involved.is_empty() {
                    answer_summary = format!("Found {} handler/candidate files in {}. Use recommendedNextCalls to inspect further.", files_involved.len(), root);
                }
                ai_guidance = "Route inspection is static-only. Framework routing configs and dynamic dispatch may register additional handlers not visible in static analysis.".to_string();
            }
        } else {
            ai_guidance = "Provide a project root to inspect API routes and handlers.".to_string();
        }
    } else if edit_keywords.iter().any(|k| q.contains(k)) {
        intent = "before_edit".to_string();
        let query = extract_symbol_from_question(question);
        target_query = if query.is_empty() {
            None
        } else {
            Some(query.clone())
        };
        orchestration["stepsAttempted"] = json!(["intent-classification:before_edit"]);
        if !root.is_empty() && !query.is_empty() {
            if let Some((file_count, sample_files)) = ask_large_project_info(root, language) {
                let deferred = build_deferred_whatif_value(
                    root,
                    language,
                    question,
                    &query,
                    file_count,
                    &sample_files,
                );
                answer_summary = format!(
                    "Whatif preview for '{}' deferred: project has {} source files. Use job mode before editing.",
                    query, file_count
                );
                orchestration["stepsAttempted"] = json!([
                    "intent-classification:before_edit",
                    "whatif:deferred_large_project"
                ]);
                orchestration["stepsSkipped"] = json!(["full_whatif:deferred_large_project"]);
                orchestration["resultsSummary"] = json!({
                    "whatif": {"riskLevel": "unknown", "analysisDeferred": true, "sourceFileCount": file_count}
                });
                evidence.push(json!({
                    "kind": "whatif_deferred",
                    "sourceFileCount": file_count,
                    "risk": "unknown"
                }));
                read_order_out = deferred["readFirst"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default()
                    .into_iter()
                    .take(5)
                    .collect();
                files_involved = sample_files.into_iter().map(Value::String).collect();
                missing_evidence = deferred["evidenceGaps"]
                    .as_array()
                    .cloned()
                    .unwrap_or_default();
                auto_job = ask_submit_auto_job(root, language);
                next_actions = ask_job_next_actions(root, language, &auto_job, Some(&query));
            } else {
                let (_ci, tc, di, ii, risk, _sa, _tests, rf, me, _na, _ap) =
                    build_whatif_result(root, language, &question, &query, "", "");
                answer_summary = if !tc.is_empty() {
                    format!(
                        "Whatif preview for '{}': {} direct impacts, {} indirect. Risk: {}. {}",
                        query,
                        di.len(),
                        ii.len(),
                        risk["level"].as_str().unwrap_or("unknown"),
                        risk["reasons"]
                            .as_array()
                            .map(|r| r
                                .iter()
                                .filter_map(|v| v.as_str())
                                .collect::<Vec<_>>()
                                .join("; "))
                            .unwrap_or_default()
                    )
                } else {
                    format!(
                        "Whatif preview for '{}': no matching symbols found in graph.",
                        query
                    )
                };
                orchestration["stepsAttempted"] =
                    json!(["intent-classification:before_edit", "whatif:executed"]);
                orchestration["resultsSummary"] = json!({
                    "whatif": {
                        "targetCandidates": tc.len(),
                        "directImpact": di.len(),
                        "indirectImpact": ii.len(),
                        "riskLevel": risk["level"]
                    }
                });
                evidence.push(json!({
                    "kind": "whatif_preview",
                    "targetCandidates": tc.len(),
                    "directImpact": di.len(),
                    "risk": risk["level"]
                }));
                files_involved = rf
                    .iter()
                    .filter_map(|v| {
                        v.get("path")
                            .and_then(|p| p.as_str())
                            .map(|s| Value::String(s.to_string()))
                    })
                    .collect();
                read_order_out = rf.into_iter().take(5).collect();
                missing_evidence.extend(me);
                next_actions.push(json!({
                    "tool": "codelattice_change_review",
                    "mode": "whatif",
                    "why": format!("Get full whatif analysis for '{}'", query),
                    "arguments": {"change": question, "symbol": query, "language": language, "root": root, "compact": true}
                }));
                next_actions.push(json!({
                    "tool": "codelattice_change_review",
                    "mode": "impact",
                    "why": format!("Assess impact of changing '{}'", query),
                    "arguments": {"symbol": query, "language": language, "root": root, "compact": true}
                }));
                next_actions.push(json!({
                    "tool": "codelattice_symbol",
                    "mode": "call_chains",
                    "why": format!("Trace call chains for '{}'", query),
                    "arguments": {"query": query, "language": language, "root": root, "direction": "both", "maxDepth": 4, "compact": true}
                }));
            }
        } else {
            answer_summary = format!(
                "Risk assessment for editing '{}'. Provide a root path for whatif preview.",
                query
            );
            orchestration["stepsSkipped"] = json!(["whatif:no_root_or_symbol"]);
            next_actions.push(json!({
                "tool": "codelattice_change_review",
                "mode": "whatif",
                "why": "Run whatif preview",
                "arguments": {"change": question, "language": language, "root": root, "compact": true}
            }));
        }
        ai_guidance = "Impact analysis is static-only. Review test coverage and runtime behavior manually before making changes.".to_string();
    } else if issue_keywords.iter().any(|k| q.contains(k)) {
        intent = "locate_issue".to_string();
        let query = extract_symbol_from_question(question);
        target_query = if query.is_empty() {
            None
        } else {
            Some(query.clone())
        };
        orchestration["stepsAttempted"] = json!(["intent-classification:locate_issue"]);
        let large_issue = ask_large_project_info(root, language);
        if let Some((file_count, sample_files)) = &large_issue {
            answer_summary = format!(
                "Issue triage for '{}' deferred: project has {} source files. Start a non-blocking job, then inspect paged details.",
                if query.is_empty() { question } else { &query },
                file_count
            );
            read_order_out = sample_files
                .iter()
                .take(5)
                .map(|path| json!({"kind": "source-sample", "path": path, "reason": "large project sample"}))
                .collect();
            files_involved = sample_files.iter().cloned().map(Value::String).collect();
            triage_plan = json!({
                "schemaVersion": "codelattice.issueTriage.v1",
                "targetQuery": target_query.clone(),
                "likelyAreas": [],
                "readFirst": read_order_out,
                "evidenceGaps": [{
                    "kind": "large_project_deferred",
                    "explanation": "Synchronous call-chain and project diagnosis skipped full graph analysis for a large project."
                }],
                "staticOnly": true,
                "analysisDeferred": true,
                "sourceFileCount": file_count
            });
            missing_evidence.push(json!({
                "kind": "large_project_deferred",
                "explanation": "Run codelattice_project(mode=job) for complete issue triage evidence."
            }));
            orchestration["stepsAttempted"] = json!([
                "intent-classification:locate_issue",
                "large_project:lightweight"
            ]);
            orchestration["stepsSkipped"] = json!([
                "call_chains:deferred_large_project",
                "project_diagnose:deferred_large_project"
            ]);
            orchestration["resultsSummary"] = json!({
                "largeProject": {"sourceFileCount": file_count, "recommendedMode": "job"}
            });
            auto_job = ask_submit_auto_job(root, language);
            next_actions = ask_job_next_actions(root, language, &auto_job, target_query.as_deref());
        } else if !root.is_empty() && !query.is_empty() {
            let root_path = Path::new(root);
            let (_, chains, _, me, _, ro, fi, _, _, _) =
                build_call_chains_result(root_path, language, &query, "both", 4, 8);
            if !chains.is_empty() {
                answer_summary = format!(
                    "Located {} call chains involving '{}' for issue triage.",
                    chains.len(),
                    query
                );
                orchestration["stepsAttempted"] =
                    json!(["intent-classification:locate_issue", "call_chains:found"]);
                call_chains = chains;
            } else {
                answer_summary = format!(
                    "Symbol '{}' found but no call chains traced. Checking project context.",
                    query
                );
                orchestration["stepsAttempted"] =
                    json!(["intent-classification:locate_issue", "call_chains:empty"]);
                missing_evidence.extend(me);
            }
            read_order_out = ro;
            files_involved = fi;
        } else {
            answer_summary =
                "Issue triage: provide a symbol or path to locate the problem.".to_string();
            orchestration["stepsAttempted"] = json!(["intent-classification:locate_issue"]);
            orchestration["stepsSkipped"] = json!(["call_chains:no_symbol"]);
        }

        if !root.is_empty() && large_issue.is_none() {
            let mut diagnose_params = json!({
                "root": root,
                "language": language,
                "mode": "diagnose",
                "symptom": question,
                "query": target_query.clone().unwrap_or_else(|| question.to_string()),
                "limit": 5,
                "compact": false
            });
            if let Some(ref tq) = target_query {
                diagnose_params["query"] = json!(tq);
            }
            match build_project_diagnose(cache, &diagnose_params) {
                Ok(diagnose) => {
                    triage_plan =
                        issue_triage_from_project_diagnose(&diagnose, target_query.as_deref());
                    let triage_likely = take_json_items(&diagnose["likelyAreas"], 5);
                    let triage_read_first = take_json_items(&diagnose["readFirst"], 5);
                    if triage_likely.is_empty() && !call_chains.is_empty() {
                        triage_plan = issue_triage_from_call_context(
                            target_query.as_deref(),
                            &call_chains,
                            &read_order_out,
                            &files_involved,
                        );
                    }
                    if read_order_out.is_empty() {
                        read_order_out = triage_read_first.clone();
                    }
                    if files_involved.is_empty() {
                        files_involved = triage_read_first
                            .iter()
                            .filter_map(|item| {
                                item.get("file")
                                    .or_else(|| item.get("path"))
                                    .and_then(|v| v.as_str())
                                    .map(|s| json!(s))
                            })
                            .collect();
                    }
                    evidence.push(json!({
                        "kind": "project_diagnose",
                        "likelyAreaCount": triage_likely.len(),
                        "readFirstCount": triage_read_first.len()
                    }));
                    orchestration["stepsAttempted"] = json!([
                        "intent-classification:locate_issue",
                        if call_chains.is_empty() {
                            "call_chains:empty"
                        } else {
                            "call_chains:found"
                        },
                        "project_diagnose:executed"
                    ]);
                    if !triage_likely.is_empty() {
                        answer_summary = format!(
                            "Static triage found {} likely area(s); start with {}.",
                            triage_likely.len(),
                            triage_likely[0]["name"]
                                .as_str()
                                .unwrap_or("the first readFirst item")
                        );
                    }
                }
                Err(err) => {
                    missing_evidence.push(json!({
                        "kind": "project_diagnose_failed",
                        "explanation": err
                    }));
                    orchestration["stepsSkipped"] = json!(["project_diagnose:failed"]);
                }
            }
        }
        next_actions.push(json!({
            "tool": "codelattice_project",
            "mode": "quick",
            "why": "Get project overview for issue context",
            "arguments": {"root": root, "language": language, "compact": true}
        }));
        if let Some(ref tq) = target_query {
            if !tq.is_empty() {
                next_actions.push(json!({
                    "tool": "codelattice_symbol",
                    "mode": "call_chains",
                    "why": format!("Trace call chains for '{}'", tq),
                    "arguments": {"query": tq, "language": language, "root": root, "direction": "both", "maxDepth": 4, "compact": true}
                }));
            }
        }
        next_actions.push(json!({
            "tool": "codelattice_workflow",
            "mode": "diagnose_issue",
            "why": "Run structured diagnosis",
            "arguments": {"root": root, "language": language, "symptom": question, "compact": true}
        }));
        ai_guidance = "Issue location is static-only. Check logs, runtime behavior, and test failures to confirm root cause.".to_string();
    } else {
        // ── 通用 intent：尝试从问题中提取目标做轻量分析 ──
        intent = "general".to_string();

        // 检测是否包含 approval/route/handler/endpoint 等关键词
        let approval_keywords = [
            "approval",
            "approve",
            "审批",
            "批准",
            "decision",
            "review",
            "route",
            "routes",
            "api",
            "handler",
            "endpoint",
            "入口",
            "路由",
            "接口",
            "处理器",
            "流程",
        ];
        let is_structural_query = approval_keywords.iter().any(|k| q.contains(k));

        if is_structural_query && !root.is_empty() {
            // 从问题中提取可能的搜索目标
            let extracted = extract_symbol_from_question(question);
            target_query = if extracted.is_empty() {
                None
            } else {
                Some(extracted.clone())
            };

            orchestration["stepsAttempted"] =
                json!(["intent-classification:general", "lightweight_symbol_search"]);

            // 构建 multi-keyword 搜索列表：优先业务关键词
            let business_terms = [
                "approval",
                "approve",
                "route",
                "handler",
                "api",
                "endpoint",
                "mission",
                "service",
                "controller",
                "middleware",
                "auth",
                "config",
                "model",
                "view",
                "component",
                "module",
                "plugin",
            ];
            let mut search_terms: Vec<String> = Vec::new();
            // 先加入提取的符号
            if !extracted.is_empty() {
                search_terms.push(extracted.clone());
            }
            // 再加入问题中匹配到的业务关键词
            for word in question.split_whitespace() {
                let w: String = word
                    .chars()
                    .filter(|c| c.is_alphanumeric() || *c == '_')
                    .collect();
                let w_lower = w.to_lowercase();
                if business_terms.contains(&w_lower.as_str())
                    && !search_terms.iter().any(|t| t.to_lowercase() == w_lower)
                {
                    search_terms.push(w);
                }
            }

            // canonicalize root 用于 cache 查询
            let canonical_root = std::path::Path::new(root)
                .canonicalize()
                .map(|p| p.to_string_lossy().to_string())
                .unwrap_or_else(|_| root.to_string());

            // 轻量 symbol search：利用已缓存 GraphView
            if let Some(entry) = cache.entries.get(&CacheKey {
                root: canonical_root,
                language: language.to_string(),
                strict: false,
            }) {
                let gv = &entry.graph_view;
                let search_refs: Vec<&str> = search_terms.iter().map(|s| s.as_str()).collect();
                // 提取匹配关键词的符号
                let search_terms_final: Vec<&str> = if search_refs.is_empty() {
                    // 如果没有明确的 symbol，从问题中提取关键词
                    question
                        .split_whitespace()
                        .filter(|w| {
                            w.len() >= 3 && w.chars().all(|c| c.is_alphanumeric() || c == '_')
                        })
                        .take(3)
                        .collect()
                } else {
                    search_refs
                };

                let mut found_symbols: Vec<Value> = Vec::new();
                for term in &search_terms_final {
                    let term_lower = term.to_lowercase();
                    if let Some(candidates) = gv.symbols_by_name.get(&term_lower) {
                        for sym in candidates.iter().take(3) {
                            found_symbols.push(sym.clone());
                        }
                    }
                    // 也搜索 id 中包含关键词的
                    for (id, node) in gv.nodes_by_id.iter() {
                        if id.to_lowercase().contains(&term_lower) && found_symbols.len() < 5 {
                            let kind = node["kind"].as_str().unwrap_or("");
                            let label = node["label"].as_str().unwrap_or("");
                            if kind == "function"
                                || kind == "method"
                                || kind == "associated-function"
                                || label == "symbol"
                                || kind == "struct"
                                || kind == "enum"
                            {
                                if !found_symbols
                                    .iter()
                                    .any(|f| f["id"].as_str() == Some(id.as_str()))
                                {
                                    found_symbols.push(node.clone());
                                }
                            }
                        }
                    }
                }

                // 构建 evidence
                for sym in found_symbols.iter().take(5) {
                    evidence.push(json!({
                        "kind": "symbol_match",
                        "file": sym["properties"]["sourcePath"].as_str()
                            .or_else(|| sym["file"].as_str())
                            .unwrap_or("unknown"),
                        "line": sym["properties"]["lineStart"].as_u64()
                            .or_else(|| sym["startLine"].as_u64()),
                        "name": sym["properties"]["name"].as_str()
                            .or_else(|| sym["name"].as_str())
                            .unwrap_or("unknown"),
                        "reason": "matched by keyword search in cached graph",
                        "source": "static_graph",
                        "staticOnly": true
                    }));
                }

                if !evidence.is_empty() {
                    answer_summary = format!(
                        "Found {} relevant symbol(s) for '{}'. See evidence for details.",
                        evidence.len(),
                        question
                    );
                    // 添加深入查询的 next calls
                    for ev in evidence.iter().take(3) {
                        if let Some(name) = ev["name"].as_str() {
                            next_actions.push(json!({
                                "tool": "codelattice_symbol",
                                "mode": "call_chains",
                                "why": format!("Trace call flow for '{}'", name),
                                "arguments": {"query": name, "root": root, "language": language, "direction": "both", "maxDepth": 4, "compact": true}
                            }));
                        }
                    }
                } else {
                    answer_summary = format!(
                        "No matching symbols found for '{}' in the cached graph. The analysis may not be complete yet.",
                        question
                    );
                    missing_evidence.push(json!({
                        "kind": "no_cached_match",
                        "explanation": "No symbols matched in current graph. Try broader terms or submit a job for full analysis."
                    }));
                    auto_job = ask_submit_auto_job(root, language);
                    next_actions = ask_job_next_actions(root, language, &auto_job, None);
                }
            } else {
                // 无缓存，提交 job
                answer_summary = format!(
                    "No cached analysis for this project. Submitting a background analysis job — retry after completion."
                );
                missing_evidence.push(json!({
                    "kind": "no_cache",
                    "explanation": "Project graph not yet loaded. A job has been submitted."
                }));
                auto_job = ask_submit_auto_job(root, language);
                next_actions = ask_job_next_actions(root, language, &auto_job, None);
            }
        } else {
            target_query = None;
            answer_summary = format!(
                "Question: '{}'. I can help with: explain_flow, find_symbol, inspect_project, before_edit, approval/route/handler lookup. Try asking about a specific symbol, API route, or the project structure.",
                question
            );
            next_actions.push(json!({
                "tool": "codelattice_workflow",
                "mode": "explore",
                "why": "Explore the project for general orientation",
                "arguments": {"root": root, "language": language, "compact": true}
            }));
            next_actions.push(json!({
                "tool": "codelattice_project",
                "mode": "quick",
                "why": "Get a quick project overview",
                "arguments": {"root": root, "language": language, "compact": true}
            }));
        }

        // confidence
        confidence = if !evidence.is_empty() {
            json!({"level": "medium", "reason": "symbol evidence from cached graph, static only"})
        } else {
            json!({"level": "low", "reason": "no matching evidence found"})
        };

        ai_guidance =
            "Results are from static analysis only. Verify with runtime behavior and logs."
                .to_string();
    }

    let _ = (compact, execute);

    (
        intent,
        answer_summary,
        target_query,
        evidence,
        call_chains,
        read_first,
        missing_evidence,
        files_involved,
        read_order_out,
        triage_plan,
        project_digest,
        orchestration,
        auto_job,
        next_actions,
        ai_guidance,
        confidence,
    )
}

fn extract_symbol_from_question(question: &str) -> String {
    if let Some(start) = question.find('`') {
        if let Some(end) = question[start + 1..].find('`') {
            return question[start + 1..start + 1 + end].to_string();
        }
    }
    let re_pattern = |c: char| !c.is_alphanumeric() && c != '_';
    for word in question.split_whitespace() {
        let w = word.trim_matches(&re_pattern as &dyn Fn(char) -> bool);
        if w.contains('(') {
            if let Some(idx) = w.find('(') {
                let name = &w[..idx];
                if name.len() >= 2 && name.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
                    return name.to_string();
                }
            }
        }
    }
    // 优先返回业务/结构关键词，而非任意最后一个英文词
    let business_priority = [
        "approval",
        "approve",
        "route",
        "handler",
        "api",
        "endpoint",
        "mission",
        "service",
        "controller",
        "middleware",
        "auth",
        "config",
        "model",
        "view",
        "component",
        "module",
        "plugin",
        "queue",
        "worker",
        "scheduler",
        "database",
        "cache",
    ];
    let mut ascii_identifiers: Vec<&str> = Vec::new();
    for word in question.split_whitespace() {
        let w = word.trim_matches(&re_pattern as &dyn Fn(char) -> bool);
        if w.len() >= 2
            && w.chars().all(|c| c.is_ascii_alphanumeric() || c == '_')
            && w.chars()
                .next()
                .map(|c| c.is_ascii_alphabetic() || c == '_')
                .unwrap_or(false)
        {
            ascii_identifiers.push(w);
        }
    }
    // 优先匹配业务关键词
    for &keyword in &business_priority {
        if let Some(found) = ascii_identifiers
            .iter()
            .find(|id| id.to_lowercase() == keyword)
        {
            return found.to_string();
        }
    }
    // fallback：返回最后一个标识符
    if let Some(&last) = ascii_identifiers.last() {
        return last.to_string();
    }
    String::new()
}

fn build_whatif_result(
    root: &str,
    language: &str,
    change: &str,
    symbol_param: &str,
    file_param: &str,
    action_param: &str,
) -> (
    serde_json::Value,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    serde_json::Value,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
    Vec<serde_json::Value>,
) {
    let change_lower = change.to_lowercase();
    let action = if !action_param.is_empty() {
        action_param.to_string()
    } else if change_lower.contains("删除") || change_lower.contains("delete") {
        "delete".to_string()
    } else if change_lower.contains("重命名") || change_lower.contains("rename") {
        "rename".to_string()
    } else {
        "modify".to_string()
    };

    let target_query = if !symbol_param.is_empty() {
        symbol_param.to_string()
    } else {
        let from_change = extract_symbol_from_question(change);
        if !from_change.is_empty() {
            from_change
        } else {
            file_param.to_string()
        }
    };

    let target_file = if !file_param.is_empty() {
        file_param.to_string()
    } else {
        String::new()
    };

    let change_intent = json!({
        "rawChange": change,
        "action": action,
        "targetQuery": target_query,
        "targetFile": target_file,
        "confidence": if target_query.is_empty() { 0.0 } else { 0.70 }
    });

    let mut target_candidates = Vec::new();
    let mut direct_impact = Vec::new();
    let mut indirect_impact = Vec::new();
    let mut read_first = Vec::new();
    let mut missing = Vec::new();
    let mut next_actions = Vec::new();

    if !target_query.is_empty() && !root.is_empty() {
        let (candidates, chains, _, me, _, ro, fi, _, _, _) =
            build_call_chains_result(Path::new(root), language, &target_query, "both", 3, 10);

        target_candidates = candidates;

        for chain in &chains {
            let dir = chain["direction"].as_str().unwrap_or("");
            if dir == "upstream" {
                if let Some(arr) = chain["chain"].as_array() {
                    if let Some(caller) = arr.first() {
                        let caller_name = caller.as_str().unwrap_or("");
                        if caller_name != target_query
                            && !direct_impact
                                .iter()
                                .any(|d: &Value| d["name"].as_str() == Some(caller_name))
                        {
                            direct_impact.push(json!({
                                "name": caller_name,
                                "kind": "caller",
                                "file": chain["entryFile"].as_str().unwrap_or(""),
                                "reason": format!("directly calls {}", target_query)
                            }));
                        }
                    }
                }
            } else if dir == "downstream" {
                if let Some(arr) = chain["chain"].as_array() {
                    if arr.len() > 1 {
                        if let Some(callee) = arr.get(1) {
                            let callee_name = callee.as_str().unwrap_or("");
                            if callee_name != target_query
                                && !direct_impact
                                    .iter()
                                    .any(|d: &Value| d["name"].as_str() == Some(callee_name))
                            {
                                direct_impact.push(json!({
                                    "name": callee_name,
                                    "kind": "callee",
                                    "file": chain["exitFile"].as_str().unwrap_or(""),
                                    "reason": format!("directly called by {}", target_query)
                                }));
                            }
                        }
                    }
                    for sym in arr.iter().skip(2) {
                        let name = sym.as_str().unwrap_or("");
                        if name != target_query
                            && !indirect_impact
                                .iter()
                                .any(|d: &Value| d["name"].as_str() == Some(name))
                        {
                            indirect_impact.push(json!({
                                "name": name,
                                "kind": "indirect",
                                "reason": format!("transitive dependency via {}", target_query)
                            }));
                        }
                    }
                }
            }
        }

        if !ro.is_empty() {
            read_first = ro;
        }
        if !fi.is_empty() {
            for f in fi {
                read_first.push(
                    json!({"kind": "file", "path": f, "reason": "file involved in change impact"}),
                );
            }
        }
        missing.extend(me);
    }

    if target_candidates.is_empty() {
        missing.push(json!({
            "kind": "symbol_not_found",
            "explanation": format!("No symbols matching '{}' found in the static graph.", target_query)
        }));
    }

    let fan_in = direct_impact
        .iter()
        .filter(|d| d["kind"].as_str() == Some("caller"))
        .count();
    let fan_out = direct_impact
        .iter()
        .filter(|d| d["kind"].as_str() == Some("callee"))
        .count();
    let total_impact = fan_in + fan_out + indirect_impact.len();

    let (risk_level, risk_reasons) = if target_candidates.is_empty() {
        (
            "low".to_string(),
            vec!["symbol not found in graph, cannot assess impact".to_string()],
        )
    } else if action == "delete" && total_impact > 5 {
        (
            "high".to_string(),
            vec![
                format!(
                    "delete action with {} direct and {} indirect impacts",
                    fan_in + fan_out,
                    indirect_impact.len()
                ),
                "high fan-in/fan-out increases risk".to_string(),
            ],
        )
    } else if action == "delete" && total_impact > 0 {
        (
            "medium".to_string(),
            vec![format!(
                "delete action affects {} direct callers/callees",
                fan_in + fan_out
            )],
        )
    } else if action == "rename" && total_impact > 3 {
        (
            "medium".to_string(),
            vec![format!("rename affects {} references", total_impact)],
        )
    } else if total_impact > 0 {
        (
            "low".to_string(),
            vec![format!(
                "modify action with {} direct impacts",
                fan_in + fan_out
            )],
        )
    } else {
        (
            "low".to_string(),
            vec!["no direct or indirect impacts detected in static graph".to_string()],
        )
    };

    let risk = json!({
        "level": risk_level,
        "reasons": risk_reasons,
        "staticOnly": true,
        "fanIn": fan_in,
        "fanOut": fan_out,
        "indirectCount": indirect_impact.len()
    });

    let mut safe_alts = Vec::new();
    if action == "delete" || action == "rename" {
        safe_alts.push(json!({"suggestion": "Add a compatibility wrapper before removing the original", "priority": "high"}));
        safe_alts.push(
            json!({"suggestion": "Keep old symbol as deprecated alias", "priority": "medium"}),
        );
        safe_alts.push(
            json!({"suggestion": "Update all call sites first, then remove", "priority": "high"}),
        );
    }
    safe_alts.push(json!({"suggestion": format!("Use codelattice_symbol(mode=call_chains, query=\"{}\") to verify chain before changing", target_query), "priority": "medium"}));

    let mut tests = Vec::new();
    if !target_candidates.is_empty() {
        tests.push(
            json!({"suggestion": "Run existing tests for affected modules", "automated": false}),
        );
        if fan_in > 0 {
            tests.push(json!({"suggestion": format!("Add integration tests for {} caller(s)", fan_in), "automated": false}));
        }
    }

    next_actions.push(json!({
        "tool": "codelattice_symbol",
        "mode": "call_chains",
        "why": format!("Trace full call chains for '{}'", target_query),
        "arguments": {"query": target_query, "language": language, "root": root, "direction": "both", "maxDepth": 4, "compact": true}
    }));
    next_actions.push(json!({
        "tool": "codelattice_change_review",
        "mode": "impact",
        "why": "Get detailed impact analysis",
        "arguments": {"symbol": target_query, "language": language, "root": root, "compact": true}
    }));

    let mut action_plan = Vec::new();
    if !read_first.is_empty() {
        action_plan.push(json!({
            "action": "readFirst",
            "target": read_first.first().and_then(|r| r.get("path")).and_then(|p| p.as_str()).unwrap_or(""),
            "reason": "Read the primary target file before making changes",
            "confidence": 0.80,
            "staticOnly": true
        }));
    }
    if !direct_impact.is_empty() {
        action_plan.push(json!({
            "action": "checkCallers",
            "target": direct_impact.iter().filter(|d| d["kind"].as_str() == Some("caller")).take(3).filter_map(|d| d["name"].as_str()).collect::<Vec<_>>().join(", "),
            "reason": format!("{} direct caller(s) will break", direct_impact.iter().filter(|d| d["kind"].as_str() == Some("caller")).count()),
            "confidence": 0.70,
            "staticOnly": true
        }));
    }
    if !safe_alts.is_empty() {
        action_plan.push(json!({
            "action": "safeAlternative",
            "target": safe_alts.first().and_then(|s| s["suggestion"].as_str()).unwrap_or(""),
            "reason": "Safest approach to minimize risk",
            "confidence": 0.60,
            "staticOnly": true
        }));
    }
    if !tests.is_empty() {
        action_plan.push(json!({
            "action": "testsToRun",
            "target": tests.first().and_then(|t| t["suggestion"].as_str()).unwrap_or(""),
            "reason": "Verify change with tests before and after",
            "confidence": 0.50,
            "staticOnly": true
        }));
    }
    if !indirect_impact.is_empty() {
        action_plan.push(json!({
            "action": "followUpImpact",
            "target": format!("{} indirect dependencies", indirect_impact.len()),
            "reason": "Transitive impact may propagate further",
            "confidence": 0.40,
            "staticOnly": true
        }));
    }
    let action_plan_compact: Vec<Value> = action_plan.into_iter().take(5).collect();

    (
        change_intent,
        target_candidates,
        direct_impact,
        indirect_impact,
        risk,
        safe_alts,
        tests,
        read_first,
        missing,
        next_actions,
        action_plan_compact,
    )
}
